export function buildP0PlatformReadinessSummary(
  goldenPath: P0PlatformReadinessSource | null | undefined
): P0PlatformReadinessSummary {
  if (!goldenPath || !Array.isArray(goldenPath.runbook)) {
    return {
      state: "unknown",
      headline: "Waiting for P0 readiness evidence",
      detail: "Golden path status is not loaded yet.",
      progressPct: 0,
      passedSteps: 0,
      totalSteps: 0,
      reviewSteps: 0,
      blockedSteps: 0,
      openStepCount: 0,
      currentGap: null,
      liveBoundary: {
        liveTradingAllowed: false,
        label: "Unknown live boundary",
        detail: "Load golden path status before evaluating execution readiness."
      }
    };
  }

  const runbook = goldenPath.runbook;
  const totalSteps = Math.max(goldenPath.summary?.totalSteps ?? runbook.length, 0);
  const passedSteps = Math.max(
    goldenPath.summary?.passedSteps ?? runbook.filter((item) => item.passed).length,
    0
  );
  const reviewSteps = Math.max(
    goldenPath.summary?.reviewSteps ?? runbook.filter((item) => !item.passed && item.status === "review").length,
    0
  );
  const blockedSteps = Math.max(
    goldenPath.summary?.blockedSteps ?? runbook.filter((item) => !item.passed && item.status === "blocked").length,
    0
  );
  const openStepCount = Math.max(totalSteps - passedSteps, reviewSteps + blockedSteps);
  const progressPct = totalSteps > 0 ? Math.round((Math.min(passedSteps, totalSteps) / totalSteps) * 100) : 0;
  const currentGapItem =
    runbook.find((item) => item.current && !item.passed) ?? runbook.find((item) => !item.passed) ?? null;
  const currentGap: P0PlatformReadinessGap | null = currentGapItem
    ? {
        stepId: currentGapItem.stepId,
        label: currentGapItem.label,
        workspaceId: currentGapItem.workspaceId,
        status: currentGapItem.status,
        detail: currentGapItem.blocker ?? currentGapItem.detail,
        actionId: currentGapItem.actionId,
        actionLabel: currentGapItem.actionLabel,
        targetWorkspaceId: currentGapItem.targetWorkspace ?? goldenPath.nextAction?.targetWorkspace ?? currentGapItem.workspaceId
      }
    : null;
  const liveTradingAllowed = Boolean(goldenPath.summary?.liveTradingAllowed);
  const state = resolveP0PlatformReadinessState({
    blockedSteps,
    goldenPathStatus: goldenPath.status,
    liveTradingAllowed,
    reviewSteps,
    totalSteps,
    passedSteps
  });
  const headline = p0PlatformReadinessHeadline(state);
  const detail = p0PlatformReadinessDetail(state, {
    currentGap,
    passedSteps,
    totalSteps
  });

  return {
    state,
    headline,
    detail,
    progressPct,
    passedSteps,
    totalSteps,
    reviewSteps,
    blockedSteps,
    openStepCount,
    currentGap,
    liveBoundary: liveTradingAllowed
      ? {
          liveTradingAllowed,
          label: "Live boundary open",
          detail: "Golden path status marks live trading gates open; require explicit operator confirmation before routing capital."
        }
      : {
          liveTradingAllowed,
          label: "Paper-only boundary",
          detail: "P0 can be usable for audited research, review, and simulation while live trading remains blocked."
        }
  };
}

export function buildP0PlatformBacklogItems(
  goldenPath: P0PlatformReadinessSource | null | undefined,
  limit = 3
): P0PlatformBacklogItem[] {
  if (!goldenPath || !Array.isArray(goldenPath.runbook) || limit <= 0) {
    return [];
  }
  return goldenPath.runbook
    .filter((item) => !item.passed)
    .map((item, index) => ({
      actionId: item.actionId,
      actionLabel: item.actionLabel,
      detail: item.blocker ?? item.detail,
      label: item.label,
      priority: p0PlatformBacklogPriority(item),
      rank: index + 1,
      status: item.status,
      stepId: item.stepId,
      targetWorkspaceId: item.targetWorkspace ?? goldenPath.nextAction?.targetWorkspace ?? item.workspaceId,
      workspaceId: item.workspaceId
    }))
    .sort((left, right) => p0PlatformBacklogPriorityRank(left.priority) - p0PlatformBacklogPriorityRank(right.priority))
    .slice(0, limit)
    .map((item, index) => ({ ...item, rank: index + 1 }));
}

export function buildP0GoldenPathJourney(input: P0GoldenPathJourneyInput | null | undefined): P0GoldenPathJourney {
  const source = input ?? {};
  const goldenPath = source.goldenPath;
  const runbook = Array.isArray(goldenPath?.runbook) ? goldenPath.runbook : [];
  const criteria = Array.isArray(source.completionChecklist?.criteria) ? source.completionChecklist.criteria : [];
  const summaryComplete = p0GoldenPathSummaryComplete(goldenPath, source.summary);
  const rawSteps = p0GoldenPathJourneyDefinitions.map((definition) => {
    const criterion = criteria.find((item) => definition.criteria.includes(item.id));
    const runbookItem = p0GoldenPathRunbookItem(runbook, definition.runbookKeys);
    const passed =
      summaryComplete ||
      criterion?.status === "passed" ||
      Boolean(runbookItem?.passed) ||
      p0GoldenPathStepHasEvidence(definition.id, source);
    const detail =
      criterion?.detail?.trim() ||
      runbookItem?.blocker?.trim() ||
      runbookItem?.detail?.trim() ||
      definition.detail;
    const evidenceId =
      criterion?.evidence?.trim() ||
      runbookItem?.stepId?.trim() ||
      p0GoldenPathStepEvidenceId(definition.id, source);
    const actionId = runbookItem?.actionId?.trim() || p0GoldenPathNextActionIdForStep(definition.id, source);
    const actionTargetWorkspaceId = p0GoldenPathActionTargetWorkspaceId(
      runbookItem?.targetWorkspace || goldenPath?.nextAction?.targetWorkspace,
      definition.workspaceId
    );

    return {
      actionId,
      actionTargetWorkspaceId,
      definition,
      detail,
      evidenceId,
      passed
    };
  });
  const firstOpenIndex = rawSteps.findIndex((step) => !step.passed);
  const currentIndex = firstOpenIndex >= 0 ? firstOpenIndex : rawSteps.length - 1;
  const currentRawStep = rawSteps[currentIndex] ?? rawSteps[0];
  const steps: P0GoldenPathJourneyStep[] = rawSteps.map((step, index) => ({
    id: step.definition.id,
    label: step.definition.label,
    state: p0GoldenPathJourneyStepState({
      hasAction: Boolean(step.actionId),
      index,
      currentIndex,
      passed: step.passed
    }),
    workspaceId: step.definition.workspaceId,
    evidenceId: step.evidenceId,
    nextActionId: index === currentIndex ? step.actionId : "",
    detail: step.detail
  }));
  const currentStep = steps[currentIndex] ?? steps[0];
  const nextActionId = currentStep?.nextActionId ?? "";

  return {
    steps,
    currentStepId: currentStep?.id ?? "data",
    nextActionId,
    nextActionTargetWorkspaceId: nextActionId ? currentRawStep.actionTargetWorkspaceId : (currentStep?.workspaceId ?? "research"),
    liveTradingAllowed: false,
    liveBoundaryLabel: "Paper-only P0 journey",
    detail: nextActionId
      ? `${currentStep?.label ?? "P0"} is current · action: ${nextActionId}`
      : `${currentStep?.label ?? "P0"} is current · live trading remains blocked`
  };
}

export function buildP0CompletionChecklist(input: P0CompletionChecklistInput): P0CompletionChecklist {
  const runbook = Array.isArray(input.goldenPath?.runbook) ? input.goldenPath.runbook : [];
  const dataQualityStep = p0CompletionRunbookStep(runbook, ["market-data", "data-quality", "watchlist-cache"]);
  const strategyStep = p0CompletionRunbookStep(runbook, ["strategy-config", "strategy-version", "strategy"]);
  const backtestStep = p0CompletionRunbookStep(runbook, ["backtest-report", "audited-backtest", "research-run"]);
  const aiStep = p0CompletionRunbookStep(runbook, ["ai-review", "agent-review"]);
  const paperStep = p0CompletionRunbookStep(runbook, ["paper-execution", "paper-order"]);
  const latestRunId = input.goldenPath?.latestRunId?.trim() || input.outcome.runId?.trim() || null;
  const hasAuditEvidence =
    input.outcome.state === "audit_run" ||
    input.outcome.state === "paper_execution" ||
    input.outcome.state === "live_ready" ||
    Boolean(latestRunId) ||
    Boolean(backtestStep?.passed);
  const paperRecorded = input.paperPreflight?.state === "recorded" || input.outcome.state === "paper_execution";
  const paperReady = paperRecorded || input.paperPreflight?.state === "ready";
  const strategyReady = Boolean(input.strategyVersionReady || strategyStep?.passed);

  const criteria: P0CompletionCriterion[] = [
    {
      id: "product-workspaces",
      label: "Clear product workspaces",
      status: input.productWorkAreaCount >= 8 ? "passed" : "blocked",
      detail:
        input.productWorkAreaCount >= 8
          ? `${input.productWorkAreaCount} product workspaces are available.`
          : "Product workspaces are not fully wired yet.",
      evidence: `${input.productWorkAreaCount} workspaces`,
      actionLabel: input.productWorkAreaCount >= 8 ? null : "Review workspace map",
      targetWorkspaceId: "research"
    },
    {
      id: "golden-path",
      label: "Golden path can run through",
      status:
        input.summary.state === "paper_ready" || input.summary.state === "live_ready"
          ? "passed"
          : input.summary.totalSteps > 0
            ? "review"
            : "blocked",
      detail:
        input.summary.totalSteps > 0
          ? input.summary.detail
          : "Golden path evidence has not been loaded.",
      evidence: `${input.summary.passedSteps}/${input.summary.totalSteps} steps`,
      actionLabel: input.summary.currentGap?.actionLabel ?? "Open golden path",
      targetWorkspaceId: p0CompletionWorkspaceId(input.summary.currentGap?.targetWorkspaceId ?? input.summary.currentGap?.workspaceId, "research")
    },
    p0CompletionCriterionFromStep({
      actionLabel: dataQualityStep?.actionLabel ?? null,
      detail: dataQualityStep?.detail ?? "Market data quality evidence is missing.",
      evidence: dataQualityStep?.detail ?? "no market-data step",
      id: "data-quality",
      label: "Market data quality is visible",
      status: p0CompletionStatusFromStep(dataQualityStep),
      targetWorkspaceId: p0CompletionWorkspaceId(dataQualityStep?.targetWorkspace ?? dataQualityStep?.workspaceId, "market")
    }),
    {
      id: "strategy-versioning",
      label: "Strategy config is structured and versioned",
      status: strategyReady ? "passed" : hasAuditEvidence ? "review" : "blocked",
      detail: strategyReady
        ? strategyStep?.detail ?? "Structured strategy version is available."
        : hasAuditEvidence
          ? "Audited evidence exists; verify the structured strategy revision is bound."
          : "Save a structured strategy version before the audited run.",
      evidence: strategyStep?.detail ?? latestRunId ?? "no strategy revision",
      actionLabel: strategyReady ? null : "Open strategy lab",
      targetWorkspaceId: "strategy"
    },
    {
      id: "audited-backtest",
      label: "Backtest run is reproducible and audited",
      status: hasAuditEvidence ? "passed" : "blocked",
      detail: hasAuditEvidence
        ? backtestStep?.detail ?? input.outcome.detail
        : "Run an audited research/backtest pipeline before AI or execution.",
      evidence: latestRunId ?? backtestStep?.detail ?? "no audited run",
      actionLabel: hasAuditEvidence ? null : "Run pipeline",
      targetWorkspaceId: hasAuditEvidence ? "audit" : "research"
    },
    {
      id: "ai-evidence",
      label: "AI review is bound to audit evidence",
      status: aiStep?.passed ? "passed" : hasAuditEvidence ? "review" : "blocked",
      detail: aiStep?.passed
        ? aiStep.detail
        : hasAuditEvidence
          ? aiStep?.blocker ?? aiStep?.detail ?? "Run AI review from audited evidence."
          : "AI review waits for audited backtest evidence.",
      evidence: aiStep?.detail ?? latestRunId ?? "no AI review",
      actionLabel: aiStep?.passed ? null : aiStep?.actionLabel ?? "Run AI review",
      targetWorkspaceId: p0CompletionWorkspaceId(aiStep?.targetWorkspace ?? aiStep?.workspaceId, "ai-review")
    },
    {
      id: "paper-execution",
      label: "Paper execution cannot bypass audit evidence",
      status: paperRecorded ? "passed" : paperReady ? "review" : "blocked",
      detail: paperRecorded
        ? input.paperPreflight?.detail ?? input.outcome.detail
        : paperReady
          ? input.paperPreflight?.detail ?? "Paper order is ready for operator confirmation."
          : paperStep?.blocker ?? paperStep?.detail ?? "Paper execution is not recorded yet.",
      evidence: input.outcome.state === "paper_execution" ? input.outcome.evidenceId ?? "paper execution" : input.paperPreflight?.headline ?? paperStep?.detail ?? "no paper execution",
      actionLabel: paperRecorded ? null : input.paperPreflight?.primaryActionLabel ?? paperStep?.actionLabel ?? "Submit paper order",
      targetWorkspaceId: "execution"
    },
    {
      id: "replay",
      label: "Replay restores chart, strategy, backtest, AI, and execution state",
      status: input.replayReady ? "passed" : input.outcome.evidenceId ? "review" : "blocked",
      detail: input.replayReady
        ? "Replay state is available for the current evidence chain."
        : input.outcome.evidenceId
          ? "Evidence exists; verify replay coverage before release."
          : "No evidence chain is available to replay.",
      evidence: input.outcome.evidenceId ?? "no replay evidence",
      actionLabel: input.replayReady ? null : "Open audit replay",
      targetWorkspaceId: "audit"
    },
    {
      id: "export-import",
      label: "Export/import can reproduce key results",
      status: input.exportImportReady ? "passed" : input.outcome.evidenceId ? "review" : "blocked",
      detail: input.exportImportReady
        ? "Export/import evidence is available for this run."
        : input.outcome.evidenceId
          ? "Run export/import verification for the current evidence chain."
          : "Create an audited run before export/import verification.",
      evidence: input.outcome.evidenceId ?? "no export evidence",
      actionLabel: input.exportImportReady ? null : "Open export evidence",
      targetWorkspaceId: "audit"
    },
    {
      id: "automated-tests",
      label: "Automated tests cover backend contracts and frontend flows",
      status: input.automatedTestsVerified ? "passed" : "review",
      detail: input.automatedTestsVerified
        ? "Automated tests were verified for the current build."
        : "Run the full test/build suite before calling P0 complete.",
      evidence: input.automatedTestsVerified ? "verified" : "not verified in runtime",
      actionLabel: input.automatedTestsVerified ? null : "Run tests",
      targetWorkspaceId: "settings"
    }
  ];
  const passed = criteria.filter((item) => item.status === "passed").length;
  const review = criteria.filter((item) => item.status === "review").length;
  const blocked = criteria.filter((item) => item.status === "blocked").length;
  const total = criteria.length;
  const progressPct = total > 0 ? Math.round((passed / total) * 100) : 0;
  const openCriteria = criteria.filter((item) => item.status !== "passed");
  const currentGap = criteria.find((item) => item.status === "blocked") ?? criteria.find((item) => item.status === "review") ?? null;
  const headline = blocked > 0 ? "P0 completion not ready" : review > 0 ? "P0 completion needs review" : "P0 completion ready";
  const detail =
    blocked > 0 || review > 0
      ? `${passed}/${total} completion criteria passed · ${review} need review · ${blocked} blocked`
      : `${passed}/${total} completion criteria passed · ready for personal/team paper workflow`;

  return {
    total,
    passed,
    review,
    blocked,
    progressPct,
    headline,
    detail,
    criteria,
    openCriteria,
    currentGap
  };
}

function p0CompletionRunbookStep(
  runbook: readonly GoldenPathRunbookSourceItem[],
  preferredStepIds: readonly string[]
): GoldenPathRunbookSourceItem | null {
  const preferred = runbook.find((item) => preferredStepIds.includes(item.stepId));
  if (preferred) {
    return preferred;
  }
  const preferredTokens = preferredStepIds.map((id) => id.replace(/-/gu, " "));
  return (
    runbook.find((item) => {
      const haystack = `${item.stepId} ${item.label}`.replace(/-/gu, " ").toLowerCase();
      return preferredTokens.some((token) => haystack.includes(token.toLowerCase()));
    }) ?? null
  );
}

function p0CompletionStatusFromStep(
  step: GoldenPathRunbookSourceItem | null | undefined
): P0CompletionCriterionStatus {
  if (!step) {
    return "blocked";
  }
  if (step.passed) {
    return "passed";
  }
  return step.status === "review" ? "review" : "blocked";
}

function p0CompletionCriterionFromStep(criterion: P0CompletionCriterion): P0CompletionCriterion {
  return criterion;
}

function p0CompletionWorkspaceId(
  value: string | null | undefined,
  fallback: ProductWorkAreaId
): ProductWorkAreaId {
  return auditReportLedgerProductWorkAreaId(value?.trim() ?? "") ?? fallback;
}

export function buildP0PlatformActionOutcome(
  source: P0PlatformActionOutcomeSource | null | undefined
): P0PlatformActionOutcome {
  const statusLabel = source?.statusLabel?.trim() ?? "";
  const paperExecution = source?.paperExecution;
  if (paperExecution?.executionId) {
    const orderCount = paperExecution.orders?.length ?? 0;
    const gateCount = paperExecution.gates?.length ?? 0;
    const passedGateCount = paperExecution.gates?.filter((gate) => gate.passed).length ?? 0;
    const preparationEvidenceDetail = formatP0PaperExecutionPreparationEvidenceDetail(
      paperExecution.preparationEvidence
    );
    const preparationEvidenceRunId = p0PaperExecutionPreparationEvidenceRunId(paperExecution.preparationEvidence);
    return {
      state: "paper_execution",
      label: "Paper execution recorded",
      detail: [
        paperExecution.executionId,
        `${orderCount} ${orderCount === 1 ? "order" : "orders"}`,
        `${passedGateCount}/${gateCount} gates passed`,
        ...(preparationEvidenceDetail ? [preparationEvidenceDetail] : [])
      ].join(" · "),
      evidenceId: paperExecution.executionId,
      runId: paperExecution.runId || null,
      ...(preparationEvidenceRunId ? { preparationEvidenceRunId } : {}),
      targetWorkspaceId: "execution",
      tone: "positive",
      nextStep: "Review the execution handoff and promotion gates; live trading remains blocked."
    };
  }

  const latestRunId = source?.goldenPath?.latestRunId?.trim() ?? "";
  if (latestRunId) {
    return {
      state: source?.goldenPath?.summary?.liveTradingAllowed ? "live_ready" : "audit_run",
      label: source?.goldenPath?.summary?.liveTradingAllowed ? "Audited run live gate open" : "Audited run available",
      detail: statusLabel ? `${latestRunId} · ${statusLabel}` : latestRunId,
      evidenceId: latestRunId,
      runId: latestRunId,
      targetWorkspaceId: "audit",
      tone: "ai",
      nextStep: source?.goldenPath?.summary?.liveTradingAllowed
        ? "Require explicit operator confirmation before any live routing."
        : "Continue with AI review or paper execution from the P0 backlog."
    };
  }

  return {
    state: "waiting",
    label: "Waiting for P0 action evidence",
    detail: statusLabel || "Run an audited pipeline to create traceable P0 evidence.",
    evidenceId: null,
    runId: null,
    targetWorkspaceId: "research",
    tone: "warning",
    nextStep: "Start with market data refresh and an audited research pipeline."
  };
}

function formatP0PaperExecutionPreparationEvidenceDetail(
  evidence: P0PlatformActionOutcomePaperExecution["preparationEvidence"]
): string | null {
  const runId = p0PaperExecutionPreparationEvidenceRunId(evidence);
  if (!runId) {
    return null;
  }
  const rows = Number.isFinite(evidence?.upsertedRows) ? `${evidence?.upsertedRows} rows` : null;
  const source = evidence?.quality?.source?.trim() || null;
  return [`prep ${runId}`, rows, source].filter(Boolean).join(" · ");
}

function p0PaperExecutionPreparationEvidenceRunId(
  evidence: P0PlatformActionOutcomePaperExecution["preparationEvidence"]
): string | null {
  return evidence?.runId?.trim() || null;
}

export function buildP0PaperExecutionPreflight(
  source: P0PaperExecutionPreflightSource | null | undefined
): P0PaperExecutionPreflight {
  const paperExecution = source?.paperExecution;
  const latestRunId = source?.goldenPath?.latestRunId?.trim() ?? "";
  const binding = source?.researchBinding ?? null;
  const riskApproval = source?.riskApproval ?? null;
  const liveTradingAllowed = Boolean(source?.goldenPath?.summary?.liveTradingAllowed);
  const targetWorkspaceId: ProductWorkAreaId = "execution";

  if (paperExecution?.executionId) {
    const orderCount = paperExecution.orders?.length ?? 0;
    const gateCount = paperExecution.gates?.length ?? 0;
    const passedGateCount = paperExecution.gates?.filter((gate) => gate.passed).length ?? 0;
    const detail = [
      paperExecution.executionId,
      `${orderCount} ${orderCount === 1 ? "order" : "orders"}`,
      `${passedGateCount}/${gateCount} gates passed`
    ].join(" · ");

    return {
      state: "recorded",
      headline: "Paper execution recorded",
      detail,
      primaryActionLabel: "Review paper execution",
      primaryActionId: null,
      primaryActionTargetWorkspaceId: targetWorkspaceId,
      canSubmitPaperOrder: false,
      canRebindLatestRun: false,
      targetWorkspaceId,
      gates: [
        {
          id: "audited-run",
          label: "Audited run",
          value: paperExecution.runId || latestRunId || "bound",
          detail: "Paper execution is linked to an audited research run.",
          status: "passed",
          tone: "positive"
        },
        {
          id: "risk-approval",
          label: "Risk approval",
          value: `${passedGateCount}/${gateCount} execution gates`,
          detail: "Paper execution captured its execution gate evidence.",
          status: gateCount > 0 && passedGateCount === gateCount ? "passed" : "review",
          tone: gateCount > 0 && passedGateCount === gateCount ? "positive" : "warning"
        },
        {
          id: "paper-execution",
          label: "Paper execution",
          value: paperExecution.executionId,
          detail: `${orderCount} ${orderCount === 1 ? "order" : "orders"} recorded in paper mode.`,
          status: "passed",
          tone: "positive"
        },
        buildP0PaperExecutionLiveBoundaryGate(liveTradingAllowed, "Paper execution remains paper-only unless live gates are explicitly opened.")
      ]
    };
  }

  const canUseBoundRun = Boolean(binding?.canUseRun);
  const canRebindLatestRun = Boolean(latestRunId) && !canUseBoundRun;
  const riskHeadline = riskApproval?.headline?.trim() || "Risk approval blocked";
  const riskSummary = riskApproval?.summary?.trim() || "Bind an audited run before paper or live execution.";
  const riskIsReady = riskApproval?.status === "paper_ready" || riskApproval?.status === "live_ready";

  if (!canUseBoundRun) {
    return {
      state: "blocked",
      headline: canRebindLatestRun ? "Bind latest audited run" : "Audited run required",
      detail: canRebindLatestRun
        ? `Golden Path has ${latestRunId} ready; load it before submitting a paper order.`
        : binding?.detail || "Run an audited pipeline before submitting a paper order.",
      primaryActionLabel: canRebindLatestRun ? "Load latest audited run" : "Run audited pipeline",
      primaryActionId: canRebindLatestRun ? "submit-paper-order" : "run-pipeline",
      primaryActionTargetWorkspaceId: canRebindLatestRun ? targetWorkspaceId : "research",
      canSubmitPaperOrder: false,
      canRebindLatestRun,
      targetWorkspaceId,
      gates: [
        {
          id: "audited-run",
          label: "Audited run",
          value: latestRunId || binding?.runId || "missing",
          detail: canRebindLatestRun
            ? "Latest Golden Path run can be rebound into the current workspace."
            : binding?.detail || "No matching audited run is bound to the current workspace.",
          status: canRebindLatestRun ? "review" : "blocked",
          tone: canRebindLatestRun ? "warning" : "risk"
        },
        buildP0PaperExecutionRiskGate(riskApproval, riskHeadline, riskSummary, false),
        buildP0PaperExecutionGate("blocked"),
        buildP0PaperExecutionLiveBoundaryGate(liveTradingAllowed, "Live routing remains blocked while paper execution is prepared.")
      ]
    };
  }

  if (!riskIsReady) {
    const firstBlockedGate = riskApproval?.gates.find((gate) => gate.status === "blocked");
    return {
      state: "blocked",
      headline: "Risk approval required",
      detail: firstBlockedGate?.detail || riskSummary,
      primaryActionLabel: "Review risk gates",
      primaryActionId: null,
      primaryActionTargetWorkspaceId: targetWorkspaceId,
      canSubmitPaperOrder: false,
      canRebindLatestRun: false,
      targetWorkspaceId,
      gates: [
        {
          id: "audited-run",
          label: "Audited run",
          value: binding?.runId || latestRunId || "bound",
          detail: binding?.detail || "Matching audited run is bound to the current workspace.",
          status: "passed",
          tone: "positive"
        },
        buildP0PaperExecutionRiskGate(riskApproval, riskHeadline, riskSummary, false),
        buildP0PaperExecutionGate("blocked"),
        buildP0PaperExecutionLiveBoundaryGate(liveTradingAllowed, "Live routing remains blocked while risk gates are reviewed.")
      ]
    };
  }

  return {
    state: "ready",
    headline: "Paper order ready",
    detail: riskSummary,
    primaryActionLabel: "Submit paper order",
    primaryActionId: "submit-paper-order",
    primaryActionTargetWorkspaceId: targetWorkspaceId,
    canSubmitPaperOrder: true,
    canRebindLatestRun: false,
    targetWorkspaceId,
    gates: [
      {
        id: "audited-run",
        label: "Audited run",
        value: binding?.runId || latestRunId || "bound",
        detail: binding?.detail || "Matching audited run is bound to the current workspace.",
        status: "passed",
        tone: "positive"
      },
      buildP0PaperExecutionRiskGate(riskApproval, riskHeadline, riskSummary, true),
      buildP0PaperExecutionGate("review"),
      buildP0PaperExecutionLiveBoundaryGate(liveTradingAllowed, "Paper route can stage; live routing still requires explicit gate approval.")
    ]
  };
}

export function buildP0PlatformActionOutcomeEvidenceLink(
  outcome: P0PlatformActionOutcome | null | undefined
): P0PlatformActionOutcomeEvidenceLink | null {
  const evidenceId = outcome?.evidenceId?.trim() ?? "";
  if (!outcome || !evidenceId) {
    return null;
  }

  const searchParams = new URLSearchParams();
  if (outcome.state === "paper_execution") {
    searchParams.set("workspace", "execution");
    searchParams.set("paperExecution", evidenceId);
    if (outcome.runId?.trim()) {
      searchParams.set("runId", outcome.runId.trim());
    }
    return {
      evidenceId,
      label: "Paper execution evidence link",
      search: searchParams.toString(),
      targetWorkspaceId: "execution"
    };
  }

  if (outcome.state === "audit_run" || outcome.state === "live_ready") {
    const runId = outcome.runId?.trim() || evidenceId;
    searchParams.set("workspace", "audit");
    searchParams.set("runId", runId);
    searchParams.set("exportPath", `manifest:${runId}`);
    return {
      evidenceId,
      label: "Audit evidence link",
      search: searchParams.toString(),
      targetWorkspaceId: "audit"
    };
  }

  return null;
}

function buildP0PaperExecutionRiskGate(
  riskApproval: RiskApprovalSummary | null,
  fallbackHeadline: string,
  fallbackSummary: string,
  ready: boolean
): P0PaperExecutionPreflightGate {
  return {
    id: "risk-approval",
    label: "Risk approval",
    value: riskApproval?.headline || fallbackHeadline,
    detail: riskApproval?.summary || fallbackSummary,
    status: ready ? "passed" : "blocked",
    tone: ready ? "positive" : "risk"
  };
}

function buildP0PaperExecutionGate(status: "blocked" | "review"): P0PaperExecutionPreflightGate {
  return {
    id: "paper-execution",
    label: "Paper execution",
    value: status === "review" ? "ready to submit" : "not recorded",
    detail:
      status === "review"
        ? "Paper order can be submitted after the operator confirms this paper-only route."
        : "Paper order has not been submitted for the latest audited run.",
    status,
    tone: status === "review" ? "warning" : "risk"
  };
}

function buildP0PaperExecutionLiveBoundaryGate(
  liveTradingAllowed: boolean,
  detail: string
): P0PaperExecutionPreflightGate {
  return {
    id: "live-boundary",
    label: "Live boundary",
    value: liveTradingAllowed ? "live gate open" : "paper only",
    detail: liveTradingAllowed
      ? "Golden Path reports live gates open; require explicit human confirmation before routing capital."
      : detail,
    status: liveTradingAllowed ? "passed" : "review",
    tone: liveTradingAllowed ? "positive" : "warning"
  };
}

export function buildP0PlatformReadinessReportMarkdown(input: P0PlatformReadinessReportInput): string {
  const generatedAt = input.generatedAt?.trim() || new Date().toISOString();
  const currentGap = input.summary.currentGap;
  const currentGapLinkLine = buildP0CurrentGapReportLinkLine(input, generatedAt);
  const backlogLines = input.backlogItems.length
    ? input.backlogItems.map((item, index) => {
        return `${index + 1}. [${item.priority}] ${item.label} (${item.status}) - ${p0ReportText(item.detail)}${p0ReadinessGapActionReportText(item)}`;
      })
    : ["No open P0 gaps in the current Golden Path status."];
  const evidenceLink = input.evidenceLink?.search?.trim()
    ? `- Evidence link: ${input.evidenceLink.search.trim()}`
    : "- Evidence link: not available yet";
  const paperPreflightLines = buildP0PaperExecutionPreflightReportLines(input.paperPreflight);

  return [
    "# P0 Platform Readiness Report",
    "",
    `- Generated at: ${generatedAt}`,
    `- State: ${input.summary.headline}`,
    `- Progress: ${input.summary.passedSteps}/${input.summary.totalSteps} steps passed (${input.summary.progressPct}%)`,
    buildP0BacklogReadinessReportLine(input.backlogItems),
    `- Open gaps: ${input.summary.openStepCount}`,
    `- Review steps: ${input.summary.reviewSteps}`,
    `- Blocked steps: ${input.summary.blockedSteps}`,
    currentGap
      ? `- Current gap: ${currentGap.label} - ${p0ReportText(currentGap.detail)}${p0ReadinessGapActionReportText(currentGap)}`
      : "- Current gap: none",
    ...(currentGapLinkLine ? [currentGapLinkLine] : []),
    `- Live boundary: ${input.summary.liveBoundary.label} - ${p0ReportText(input.summary.liveBoundary.detail)}`,
    ...buildP0CompletionChecklistReportLines(input.completionChecklist),
    "",
    "## Open P0 Gaps",
    "",
    ...backlogLines,
    "",
    "## Latest Evidence",
    "",
    `- Evidence: ${input.outcome.label} - ${p0ReportText(input.outcome.detail)}`,
    `- Next step: ${p0ReportText(input.outcome.nextStep)}`,
    evidenceLink,
    ...paperPreflightLines,
    "",
    "This report is an audit aid only. It does not authorize live trading or provide investment advice."
  ].join("\n");
}

function buildP0CompletionChecklistReportLines(
  checklist: P0CompletionChecklist | null | undefined
): string[] {
  if (!checklist) {
    return [];
  }
  const currentGapLine = checklist.currentGap
    ? `- Current completion gap: ${checklist.currentGap.label} (${checklist.currentGap.status}) - ${p0ReportText(checklist.currentGap.detail)}`
    : "- Current completion gap: none";
  return [
    "",
    "## P0 Completion Checklist",
    "",
    `- Completion: ${checklist.passed}/${checklist.total} passed, ${checklist.review} review, ${checklist.blocked} blocked.`,
    currentGapLine,
    "",
    ...checklist.criteria.map((criterion, index) => {
      const action = criterion.actionLabel
        ? ` Next: ${p0ReportText(criterion.actionLabel)} -> ${criterion.targetWorkspaceId}.`
        : "";
      return `${index + 1}. ${criterion.label} [${criterion.status}] - ${p0ReportSentence(criterion.detail)} Evidence: ${p0ReportSentence(criterion.evidence)}${action}`;
    })
  ];
}

function p0ReportSentence(value: string | null | undefined): string {
  const text = p0ReportText(value);
  return /[.!?。！？]$/u.test(text) ? text : `${text}.`;
}

function buildP0BacklogReadinessReportLine(backlogItems: readonly P0PlatformBacklogItem[]): string {
  const readiness = backlogItems.map((item) =>
    buildP0CurrentGapActionReadiness({
      actionId: item.actionId,
      targetWorkspaceId: auditReportLedgerProductWorkAreaId((item.targetWorkspaceId ?? item.workspaceId ?? "").trim()),
      workspaceId: auditReportLedgerProductWorkAreaId((item.workspaceId ?? "").trim())
    })
  );
  const total = backlogItems.length;
  const executable = readiness.filter((item) => item.canExecute).length;
  const notExecutable = Math.max(0, total - executable);
  const firstReadiness = readiness[0] ?? null;
  const firstAction =
    firstReadiness?.executableActionId ||
    backlogItems[0]?.actionId?.trim() ||
    firstReadiness?.reason ||
    "none";
  const firstReason = firstReadiness?.reason ?? "none";
  return `- Backlog readiness: ${executable}/${total} executable, ${notExecutable} not executable. First: ${firstAction} ${firstReason}.`;
}

function buildP0CurrentGapReportLinkLine(
  input: P0PlatformReadinessReportInput,
  generatedAt: string
): string | null {
  const gap = input.summary.currentGap;
  const actionId = gap?.actionId?.trim() ?? "";
  const targetWorkspaceId = auditReportLedgerProductWorkAreaId((gap?.targetWorkspaceId ?? gap?.workspaceId ?? "").trim());
  if (!gap || !actionId || !targetWorkspaceId) {
    return null;
  }
  const evidenceToken = input.outcome.runId?.trim() || input.outcome.evidenceId?.trim() || generatedAt;
  const query = ["p0_readiness_report", evidenceToken, actionId, targetWorkspaceId].filter(Boolean).join(" ");
  const params = new URLSearchParams();
  params.set("workspace", targetWorkspaceId);
  params.set("auditReportQuery", query);
  params.set("p0Action", actionId);
  const search = buildP0CurrentGapActionUrlSearch(params);
  return search ? `- Current gap link: ${search}` : null;
}

function p0ReadinessGapActionReportText(gap: P0PlatformReadinessGap): string {
  const action = gap.actionLabel?.trim() || "No direct action";
  const workspace = gap.targetWorkspaceId || gap.workspaceId;
  const targetWorkspaceId = auditReportLedgerProductWorkAreaId((gap.targetWorkspaceId ?? gap.workspaceId ?? "").trim());
  const workspaceId = auditReportLedgerProductWorkAreaId((gap.workspaceId ?? "").trim());
  const readiness = buildP0CurrentGapActionReadiness({
    actionId: gap.actionId,
    targetWorkspaceId,
    workspaceId
  });
  const executableText = readiness.canExecute
    ? `yes (${readiness.executableActionId})`
    : `no (${readiness.reason})`;
  return ` Action: ${p0ReportText(action)}. Workspace: ${workspace}. Executable: ${executableText}.`;
}

function buildP0PaperExecutionPreflightReportLines(
  preflight: P0PaperExecutionPreflight | null | undefined
): string[] {
  if (!preflight) {
    return [];
  }
  const primaryAction = preflight.primaryActionId
    ? `${preflight.primaryActionLabel} (${preflight.primaryActionId} -> ${preflight.primaryActionTargetWorkspaceId})`
    : `${preflight.primaryActionLabel} (review -> ${preflight.primaryActionTargetWorkspaceId})`;
  return [
    "",
    "## Paper Execution Preflight",
    "",
    `- State: ${preflight.state}`,
    `- Primary action: ${p0ReportText(primaryAction)}`,
    "",
    ...preflight.gates.map(
      (gate, index) =>
        `${index + 1}. ${gate.label} [${gate.status}] - ${p0ReportText(gate.value)} - ${p0ReportText(gate.detail)}`
    )
  ];
}

function p0PlatformBacklogPriority(item: GoldenPathRunbookSourceItem): P0PlatformBacklogPriority {
  if (item.current) {
    return "current";
  }
  return item.status === "review" ? "review" : "blocked";
}

const p0GoldenPathJourneyDefinitions: readonly {
  id: P0GoldenPathJourneyStepId;
  label: string;
  workspaceId: ProductWorkAreaId;
  criteria: readonly P0CompletionCriterionId[];
  runbookKeys: readonly string[];
  detail: string;
}[] = [
  {
    id: "data",
    label: "Data readiness",
    workspaceId: "market",
    criteria: ["data-quality"],
    runbookKeys: ["market-data", "data-quality", "watchlist-cache"],
    detail: "Prepare A-share data and cache evidence."
  },
  {
    id: "strategy",
    label: "Strategy draft",
    workspaceId: "strategy",
    criteria: ["strategy-versioning"],
    runbookKeys: ["strategy-config", "strategy-version", "strategy"],
    detail: "Save a structured strategy version."
  },
  {
    id: "backtest",
    label: "Audited backtest",
    workspaceId: "backtest",
    criteria: ["audited-backtest"],
    runbookKeys: ["backtest-report", "audited-backtest", "research-run"],
    detail: "Run an audited backtest and bind a run id."
  },
  {
    id: "ai-review",
    label: "AI review",
    workspaceId: "ai-review",
    criteria: ["ai-evidence"],
    runbookKeys: ["ai-review", "agent-review"],
    detail: "Run an evidence-bound AI review."
  },
  {
    id: "paper-simulation",
    label: "Paper simulation",
    workspaceId: "execution",
    criteria: ["paper-execution"],
    runbookKeys: ["paper-execution", "paper-order", "paper-simulation"],
    detail: "Submit a paper-only simulated order."
  },
  {
    id: "replay",
    label: "Replay",
    workspaceId: "execution",
    criteria: ["replay"],
    runbookKeys: ["replay", "paper-replay", "account-replay"],
    detail: "Replay cash, position, and order state."
  },
  {
    id: "export",
    label: "Export package",
    workspaceId: "audit",
    criteria: ["export-import"],
    runbookKeys: ["export-import", "export", "package"],
    detail: "Export or verify the portable P0 evidence package."
  }
];

function p0GoldenPathRunbookItem(
  runbook: readonly GoldenPathRunbookSourceItem[],
  keys: readonly string[]
): GoldenPathRunbookSourceItem | null {
  return (
    runbook.find((item) => keys.some((key) => item.stepId === key || item.stepId.includes(key))) ??
    runbook.find((item) => keys.some((key) => item.label.toLowerCase().includes(key.replaceAll("-", " ")))) ??
    null
  );
}

function p0GoldenPathStepHasEvidence(
  stepId: P0GoldenPathJourneyStepId,
  source: P0GoldenPathJourneyInput
): boolean {
  if (stepId === "paper-simulation") {
    return source.paperPreflight?.state === "recorded" || source.outcome?.state === "paper_execution";
  }
  if (stepId === "backtest") {
    return source.outcome?.state === "audit_run" || source.outcome?.state === "paper_execution" || Boolean(source.outcome?.runId);
  }
  return false;
}

function p0GoldenPathStepEvidenceId(
  stepId: P0GoldenPathJourneyStepId,
  source: P0GoldenPathJourneyInput
): string {
  if (stepId === "paper-simulation") {
    return source.outcome?.evidenceId?.trim() || "";
  }
  if (stepId === "backtest" || stepId === "ai-review") {
    return source.outcome?.runId?.trim() || source.goldenPath?.latestRunId?.trim() || "";
  }
  return "";
}

function p0GoldenPathSummaryComplete(
  goldenPath: P0PlatformReadinessSource | null | undefined,
  summary: P0PlatformReadinessSummary | null | undefined
): boolean {
  const totalSteps = Math.max(summary?.totalSteps ?? goldenPath?.summary?.totalSteps ?? 0, 0);
  const passedSteps = Math.max(summary?.passedSteps ?? goldenPath?.summary?.passedSteps ?? 0, 0);
  const blockedSteps = Math.max(summary?.blockedSteps ?? goldenPath?.summary?.blockedSteps ?? 0, 0);
  const reviewSteps = Math.max(summary?.reviewSteps ?? goldenPath?.summary?.reviewSteps ?? 0, 0);
  return totalSteps > 0 && passedSteps >= totalSteps && blockedSteps === 0 && reviewSteps === 0;
}

function p0GoldenPathNextActionIdForStep(
  stepId: P0GoldenPathJourneyStepId,
  source: P0GoldenPathJourneyInput
): string {
  const nextAction = source.goldenPath?.nextAction;
  if (!nextAction?.id) {
    return "";
  }
  const targetWorkspaceId = auditReportLedgerProductWorkAreaId(nextAction.targetWorkspace?.trim() ?? "");
  const definition = p0GoldenPathJourneyDefinitions.find((item) => item.id === stepId);
  return targetWorkspaceId && definition?.workspaceId === targetWorkspaceId ? nextAction.id.trim() : "";
}

function p0GoldenPathActionTargetWorkspaceId(
  value: string | null | undefined,
  fallback: ProductWorkAreaId
): ProductWorkAreaId {
  return auditReportLedgerProductWorkAreaId(value?.trim() ?? "") ?? fallback;
}

function p0GoldenPathJourneyStepState(input: {
  currentIndex: number;
  hasAction: boolean;
  index: number;
  passed: boolean;
}): P0GoldenPathJourneyStepState {
  if (input.index === input.currentIndex) {
    return "current";
  }
  if (input.passed) {
    return "done";
  }
  return input.hasAction ? "ready" : "blocked";
}

function p0PlatformBacklogPriorityRank(priority: P0PlatformBacklogPriority): number {
  return (
    {
      current: 0,
      blocked: 1,
      review: 2
    } satisfies Record<P0PlatformBacklogPriority, number>
  )[priority];
}

function resolveP0PlatformReadinessState(input: {
  blockedSteps: number;
  goldenPathStatus?: P0PlatformReadinessSource["status"];
  liveTradingAllowed: boolean;
  reviewSteps: number;
  totalSteps: number;
  passedSteps: number;
}): P0PlatformReadinessState {
  if (input.totalSteps <= 0) {
    return "unknown";
  }
  if (input.passedSteps >= input.totalSteps && input.blockedSteps === 0 && input.reviewSteps === 0) {
    return input.liveTradingAllowed ? "live_ready" : "paper_ready";
  }
  if (input.blockedSteps > 0 || input.goldenPathStatus === "blocked") {
    return "blocked";
  }
  if (input.reviewSteps > 0 || input.goldenPathStatus === "review") {
    return "review";
  }
  return "blocked";
}

function p0PlatformReadinessHeadline(state: P0PlatformReadinessState): string {
  return (
    {
      blocked: "P0 golden path blocked",
      live_ready: "P0 live workflow ready",
      paper_ready: "P0 paper workflow ready",
      review: "P0 golden path needs review",
      unknown: "Waiting for P0 readiness evidence"
    } satisfies Record<P0PlatformReadinessState, string>
  )[state];
}

function p0PlatformReadinessDetail(
  state: P0PlatformReadinessState,
  context: {
    currentGap: P0PlatformReadinessGap | null;
    passedSteps: number;
    totalSteps: number;
  }
): string {
  if (state === "unknown") {
    return "Golden path status is not loaded yet.";
  }
  const progress = `${context.passedSteps}/${context.totalSteps} P0 steps passed`;
  if (state === "paper_ready") {
    return `${progress} · paper workflow ready · live trading remains blocked`;
  }
  if (state === "live_ready") {
    return `${progress} · live gates reported ready`;
  }
  const gap = context.currentGap?.label ?? "Evidence";
  const action = context.currentGap?.actionLabel?.trim();
  const workspace = context.currentGap?.targetWorkspaceId || context.currentGap?.workspaceId;
  const actionDetail = action && workspace ? ` · action: ${action} -> ${workspace}` : "";
  return `${progress} · current gap: ${gap}${actionDetail}`;
}

function p0ReportText(value: string | null | undefined): string {
  return value?.trim() || "n/a";
}

export function resolveProductWorkAreaSelection(
  workspace: TerminalWorkspace,
  requestedAreaId: string,
  fallbackAreaId: ProductWorkAreaId = "research"
): ProductWorkAreaSelection {
  const areas = buildProductWorkAreas(workspace);
  const requestedArea = areas.find((area) => area.id === requestedAreaId);
  const fallbackArea = areas.find((area) => area.id === fallbackAreaId) ?? areas[0];
  const selectedArea = requestedArea ?? fallbackArea;

  return {
    areaId: selectedArea.id,
    quantLoopStepId: selectedArea.quantLoopStepId,
    workflowStageId: selectedArea.workflowStageId
  };
}

function productWorkAreaStatus(
  areaId: ProductWorkAreaId,
  hasAuditedRun: boolean,
  workspace: TerminalWorkspace
): ProductWorkAreaStatus {
  if (areaId === "execution") {
    return hasAuditedRun ? "ready" : "blocked";
  }
  if (areaId === "portfolio" || areaId === "ai-review" || areaId === "audit") {
    return hasAuditedRun ? "ready" : "needs_run";
  }
  if (areaId === "backtest") {
    return workspace.metrics.some((metric) => metric.value !== "N/A" && metric.value !== "0") ? "ready" : "needs_run";
  }
  return "ready";
}

export function resolveQuantLoopSelection(
  workspace: TerminalWorkspace,
  requestedStepId: string,
  fallbackStepId = activeQuantLoopStepId(workspace)
): QuantLoopSelection {
  const supportedStepIds = new Set<string>(primaryQuantLoopStepDefinitions.map((step) => step.id));
  const supportedSteps = workspace.quantLoop.filter((step) => supportedStepIds.has(step.id));
  const requestedStep = supportedSteps.find((step) => step.id === requestedStepId);
  const fallbackStep = supportedSteps.find((step) => step.id === fallbackStepId && step.status !== "locked");
  const selectedStep =
    requestedStep && requestedStep.status !== "locked"
      ? requestedStep
      : fallbackStep ?? supportedSteps.find((step) => step.status !== "locked");
  const stepId = selectedStep?.id ?? "research";

  return {
    stepId,
    target: buildQuantLoopNavigationTarget(stepId)
  };
}

export function visiblePanels(workspace: TerminalWorkspace): PanelId[] {
  return workspace.panels.filter((panel) => panel.visible).map((panel) => panel.id);
}

export function agentRoleLabels(workspace: TerminalWorkspace): string[] {
  return workspace.agents.map((agent) => agent.label);
}

export function buildAgentCommitteeRounds(workspace: TerminalWorkspace): AgentCommitteeRound[] {
  const returnMetric = workspace.metrics.find((metric) => metric.label === "Return")?.value ?? "N/A";
  const drawdownMetric = workspace.metrics.find((metric) => metric.label === "Max DD")?.value ?? "N/A";
  const technicalNote = findDecisionMessage(workspace, "Technical");
  const riskNote = findDecisionMessage(workspace, "Risk");
  const portfolioNote = findDecisionMessage(workspace, "Portfolio Manager");
  const auditBinding = buildResearchRunContextBinding(workspace);
  const usableRun = auditBinding.canUseRun ? workspace.researchRun : null;

  return [
    {
      id: "technical-analysis",
      phase: "analysis",
      agent: "Technical Analyst",
      thesis: technicalNote,
      evidence: `${workspace.selectedInstrument.symbol} · ${workspace.selectedTimeframe} · Return ${returnMetric} · Max DD ${drawdownMetric}`,
      verdict: returnMetric.startsWith("+") ? "support" : "challenge",
      confidence: returnMetric.startsWith("+") ? 64 : 52,
      tone: returnMetric.startsWith("+") ? "positive" : "warning"
    },
    {
      id: "bull-research",
      phase: "debate",
      agent: "Bull Researcher",
      thesis: `Bull case requires ${workspace.strategy.entry}.`,
      evidence: `Position rule: ${workspace.strategy.position}.`,
      verdict: "support",
      confidence: 58,
      tone: "positive"
    },
    {
      id: "bear-research",
      phase: "debate",
      agent: "Bear Researcher",
      thesis: `Bear case challenges the setup if ${workspace.strategy.exit}.`,
      evidence: `Risk rule: ${workspace.strategy.risk}.`,
      verdict: "challenge",
      confidence: 55,
      tone: "warning"
    },
    {
      id: "risk-manager",
      phase: "risk",
      agent: "Risk Manager",
      thesis: riskNote,
      evidence: workspace.execution.gates.map((gate) => `${gate.label}: ${gate.passed ? "passed" : "blocked"}`).join(" · "),
      verdict: "risk",
      confidence: workspace.execution.liveEnabled ? 48 : 82,
      tone: "risk"
    },
    {
      id: "portfolio-decision",
      phase: "decision",
      agent: "Portfolio Manager",
      thesis: portfolioNote,
      evidence: usableRun
        ? `Audited run ${usableRun.runId} · ${usableRun.dataRows} bars`
        : auditBinding.status === "mismatched"
          ? auditBinding.detail
          : "No audited run is bound to this research context yet.",
      verdict: "watch",
      confidence: usableRun ? 66 : 60,
      tone: "ai"
    }
  ];
}

export function buildAiEvidenceCards(workspace: TerminalWorkspace): AiEvidenceCard[] {
  const selected = workspace.selectedInstrument;
  const auditBinding = buildResearchRunContextBinding(workspace);
  const usableRun = auditBinding.canUseRun ? workspace.researchRun : null;
  const blockedGateCount = workspace.execution.gates.filter((gate) => !gate.passed).length;
  const gateDetail = workspace.execution.gates
    .map((gate) => `${gate.label}: ${gate.passed ? "passed" : "blocked"}`)
    .join(" · ");
  const researchNote = normalizedResearchNote(usableRun?.researchNote);
  const cards: AiEvidenceCard[] = [
    {
      id: "context",
      label: "Research context",
      value: `${selected.symbol} · ${workspace.selectedTimeframe}`,
      detail: `${selected.market} · price ${formatInstrumentPrice(selected.price)}`,
      tone: "neutral"
    },
    usableRun
      ? {
          id: "backtest",
          label: "Backtest evidence",
          value: `${usableRun.dataRows} ${usableRun.timeframe} bars`,
          detail: `Audited run ${usableRun.runId} · revision ${usableRun.strategyRevision}`,
          tone: "positive"
        }
      : auditBinding.status === "mismatched"
        ? {
            id: "backtest",
            label: "Backtest evidence",
            value: "Stale audited run",
            detail: auditBinding.detail,
            tone: "risk"
          }
      : {
          id: "backtest",
          label: "Backtest evidence",
          value: "Pending audited run",
          detail: "Run Pipeline before trusting AI review.",
          tone: "warning"
        },
  ];

  if (usableRun) {
    const benchmark = buildBacktestBenchmark(workspace);
    cards.push({
      id: "benchmark",
      label: "Benchmark alpha",
      value: benchmark.alpha,
      detail: aiBenchmarkDetail(benchmark),
      tone: benchmark.tone
    });
  }

  if (researchNote) {
    cards.push({
      id: "research-note",
      label: "Research note",
      value: "Locked note snapshot",
      detail: compactResearchNoteDetail(researchNote.body),
      tone: "ai"
    });
  }

  cards.push(
    {
      id: "risk",
      label: "Risk gates",
      value: workspace.execution.liveEnabled ? "Live gates open" : `${blockedGateCount} blocked gates`,
      detail: gateDetail,
      tone: workspace.execution.liveEnabled ? "positive" : "risk"
    },
    {
      id: "safety",
      label: "AI boundary",
      value: "No buy/sell advice",
      detail: "AI can explain supplied evidence only; no guaranteed outcome.",
      tone: "ai"
    }
  );

  return cards;
}

export function buildAiReviewDossier(workspace: TerminalWorkspace): AiReviewDossier {
  const auditBinding = buildResearchRunContextBinding(workspace);
  const blockedGateCount = workspace.execution.gates.filter((gate) => !gate.passed).length;
  const riskGateCitation: AiReviewCitation = {
    id: "risk-gates",
    label: "Risk gates",
    value: workspace.execution.liveEnabled ? "Live gates open" : `${blockedGateCount} blocked gates`,
    detail: workspace.execution.gates
      .map((gate) => `${gate.label}: ${gate.passed ? "passed" : "blocked"}`)
      .join(" · "),
    tone: workspace.execution.liveEnabled ? "positive" : "risk"
  };

  if (!workspace.researchRun) {
    return {
      status: "blocked",
      headline: "Audited evidence required",
      summary: "Run Pipeline before agent debate, explanation, or strategy promotion.",
      citations: [
        {
          id: "run",
          label: "Run id",
          value: "Missing audited run",
          detail: "No reproducible backtest is bound to this context.",
          tone: "risk"
        },
        {
          id: "data-quality",
          label: "Data quality",
          value: "Unavailable",
          detail: "Data quality is only trusted after an audited run is loaded.",
          tone: "warning"
        },
        riskGateCitation
      ]
    };
  }

  if (!auditBinding.canUseRun) {
    return {
      status: "blocked",
      headline: "Current audit context required",
      summary: "Run Pipeline to bind AI review to the selected research context before exporting or saving records.",
      citations: [
        {
          id: "run",
          label: "Run id",
          value: auditBinding.runId ?? "Stale audited run",
          detail: auditBinding.detail,
          tone: "risk"
        },
        {
          id: "data-quality",
          label: "Data quality",
          value: "Stale context",
          detail: "Data quality cannot be trusted until the run matches the selected market, symbol, and timeframe.",
          tone: "warning"
        },
        riskGateCitation
      ]
    };
  }

  const run = workspace.researchRun;
  const returnMetric = metricValue(workspace, "Return", "N/A");
  const drawdownMetric = metricValue(workspace, "Max DD", "N/A");
  const winRateMetric = metricValue(workspace, "Win Rate", "N/A");
  const tradeMetric = metricValue(workspace, "Trades", "0");
  const dataQuality = run.dataQuality;
  const researchNote = normalizedResearchNote(run.researchNote);
  const benchmark = buildBacktestBenchmark(workspace);
  const parameterScanSummary = buildBacktestParameterScanSummary(workspace);
  const benchmarkCitation: AiReviewCitation = {
    id: "benchmark",
    label: "Benchmark alpha",
    value: benchmark.alpha,
    detail: aiBenchmarkDetail(benchmark),
    tone: benchmark.tone
  };
  const parameterScanCitation: AiReviewCitation | null = parameterScanSummary
    ? {
        id: "parameter-scan",
        label: "Parameter scan",
        value: parameterScanSummary.headline,
        detail: parameterScanSummary.detail,
        tone: parameterScanSummary.tone
      }
    : null;
  const noteCitation: AiReviewCitation | null = researchNote
    ? {
        id: "research-note",
        label: "Research note",
        value: "Locked note snapshot",
        detail: compactResearchNoteDetail(researchNote.body),
        tone: "ai"
      }
    : null;

  return {
    status: "ready",
    headline: `AI review bound to ${run.runId}`,
    summary: `Agents may explain evidence for ${workspace.selectedInstrument.symbol}, but live execution remains gated.`,
    citations: [
      {
        id: "run",
        label: "Run id",
        value: run.runId,
        detail: `${run.dataRows} ${run.timeframe} bars · ${run.executionMode}`,
        tone: "positive"
      },
      {
        id: "metrics",
        label: "Backtest metrics",
        value: `${returnMetric} / ${drawdownMetric} / ${tradeMetric} trades`,
        detail: `Win rate ${winRateMetric}; no guaranteed outcome.`,
        tone: returnMetric.startsWith("-") ? "warning" : "positive"
      },
      benchmarkCitation,
      ...(parameterScanCitation ? [parameterScanCitation] : []),
      {
        id: "strategy",
        label: "Strategy revision",
        value: run.strategyRevision,
        detail: workspace.strategy.name,
        tone: "positive"
      },
      dataQuality
        ? {
            id: "data-quality",
            label: "Data quality",
            value: `${dataQuality.source} · ${dataQuality.isComplete ? "complete" : "review"}`,
            detail: `${dataQuality.rows} rows · ${formatWarningCount(dataQuality.warnings.length)}`,
            tone: dataQuality.isComplete && dataQuality.warnings.length === 0 ? "positive" : "warning"
          }
        : {
            id: "data-quality",
            label: "Data quality",
            value: "Not attached",
            detail: "Run metadata did not include data quality details.",
            tone: "warning"
          },
      ...(noteCitation ? [noteCitation] : []),
      riskGateCitation
    ]
  };
}

export function buildAiReviewReportMarkdown(workspace: TerminalWorkspace): string | null {
  const run = workspace.researchRun;
  if (!run) {
    return null;
  }

  const dossier = buildAiReviewDossier(workspace);
  if (dossier.status !== "ready") {
    return null;
  }

  const rounds = buildAgentCommitteeRounds(workspace);
  const benchmark = buildBacktestBenchmark(workspace);
  const parameterScanSummary = buildBacktestParameterScanSummary(workspace);
  const researchNote = normalizedResearchNote(run.researchNote);
  const citationRows = dossier.citations.map((citation) => [citation.label, citation.value, citation.detail]);
  const committeeRows = rounds.map((round) => [
    round.agent,
    round.verdict,
    `${round.confidence}%`,
    round.thesis,
    round.evidence
  ]);
  const decisionRows = workspace.decisionLog.map((entry) => [entry.agent, entry.tone, entry.message]);

  return [
    "# AIQuant Evidence-Locked AI Review",
    "",
    `Run ID: \`${run.runId}\``,
    `Market: \`${workspace.selectedInstrument.market}\``,
    `Symbol: \`${workspace.selectedInstrument.symbol}\``,
    `Timeframe: \`${run.timeframe}\``,
    `Strategy revision: \`${run.strategyRevision}\``,
    `Execution mode: \`${run.executionMode}\``,
    "",
    "## Review Scope",
    "",
    dossier.headline,
    "",
    dossier.summary,
    "",
    "## Evidence Citations",
    "",
    markdownTable(["Citation", "Value", "Evidence"], citationRows),
    "",
    "## Benchmark Context",
    "",
    benchmark.detail,
    "",
    markdownTable(
      ["Measure", "Value"],
      [
        ["Strategy return", benchmark.strategyReturn],
        ["Benchmark buy and hold", benchmark.benchmarkReturn],
        ["Benchmark alpha", benchmark.alpha]
      ]
    ),
    "",
    "## Parameter Scan Summary",
    "",
    parameterScanSummary
      ? markdownTable(
          ["Field", "Value"],
          [
            ["Rows", parameterScanSummary.totalRows],
            [
              "Current rank",
              parameterScanSummary.currentRank
                ? `${parameterScanSummary.currentRank}/${parameterScanSummary.totalRows}`
                : "N/A"
            ],
            ["Candidate for re-audit", parameterScanSummary.bestCandidateCondition ?? "N/A"],
            ["Candidate return", parameterScanSummary.bestCandidateReturnPct],
            ["Candidate max drawdown", parameterScanSummary.bestCandidateMaxDrawdownPct],
            ["Candidate delta", parameterScanSummary.bestCandidateDelta],
            ["Risk rows", parameterScanSummary.riskCount],
            ["Boundary", "Candidate must be re-audited; no investment advice."]
          ]
        )
      : "Parameter scan summary requires an audited data snapshot.",
    "",
    researchNote ? "## Locked Research Note" : "",
    researchNote ? "" : "",
    researchNote ? researchNote.body : "",
    researchNote ? "" : "",
    "## Committee Rounds",
    "",
    markdownTable(["Agent", "Verdict", "Confidence", "Thesis", "Evidence"], committeeRows),
    "",
    "## Decision Log",
    "",
    decisionRows.length ? markdownTable(["Agent", "Tone", "Message"], decisionRows) : "No decision log entries are attached.",
    "",
    "## AI Boundary",
    "",
    "AI must not output buy/sell instructions or guaranteed returns.",
    "",
    "This report can explain only the audited run, locked strategy revision, data snapshot, benchmark comparison, parameter scan summary, and risk gates above."
  ]
    .filter((line, index, lines) => line !== "" || lines[index - 1] !== "")
    .join("\n")
    .trimEnd()
    .concat("\n");
}

export function buildAiReviewRunRecord(workspace: TerminalWorkspace): AiReviewRunRecord | null {
  const run = workspace.researchRun;
  if (!run) {
    return null;
  }

  const dossier = buildAiReviewDossier(workspace);
  if (dossier.status !== "ready") {
    return null;
  }

  const rounds = buildAgentCommitteeRounds(workspace);
  const decisionLog = workspace.decisionLog.slice();
  const citations = dossier.citations.slice();
  const evidenceAnchors = buildAiReviewEvidenceAnchors(run, citations, rounds, decisionLog);

  return {
    schemaVersion: 1,
    recordType: "aiqt.aiReviewRun",
    aiReviewId: `ai-review:${run.runId}:${run.strategyRevision}`,
    runId: run.runId,
    createdAt: run.createdAt,
    market: workspace.selectedInstrument.market,
    symbol: workspace.selectedInstrument.symbol,
    timeframe: run.timeframe,
    strategyRevision: run.strategyRevision,
    executionMode: run.executionMode,
    status: dossier.status,
    summary: {
      citationCount: citations.length,
      roundCount: rounds.length,
      decisionCount: decisionLog.length,
      parameterScanBound: citations.some((citation) => citation.id === "parameter-scan"),
      liveExecutionBlocked: !workspace.execution.liveEnabled
    },
    dossier,
    citations,
    rounds,
    decisionLog,
    evidenceAnchors,
    boundary: "Evidence explanation only; no buy/sell instructions or guaranteed returns."
  };
}

function buildAiReviewEvidenceAnchors(
  run: ResearchRunSummary | ResearchRunAudit,
  citations: AiReviewCitation[],
  rounds: AgentCommitteeRound[],
  decisionLog: DecisionLogEntry[]
): AiReviewEvidenceAnchor[] {
  const anchors: AiReviewEvidenceAnchor[] = [
    {
      id: `run:${run.runId}`,
      type: "research-run",
      label: "Research run",
      reference: run.runId,
      exportPath: "researchRun.runId"
    },
    {
      id: `strategy:${run.strategyRevision}`,
      type: "strategy-revision",
      label: "Strategy revision",
      reference: run.strategyRevision,
      exportPath: "researchRun.strategyConfig.revision"
    }
  ];

  if (run.dataSnapshot?.hash) {
    anchors.push({
      id: `data:${run.dataSnapshot.hash}`,
      type: "data-snapshot",
      label: "Data snapshot",
      reference: run.dataSnapshot.hash,
      exportPath: "researchRun.dataSnapshot.hash"
    });
  }

  if (run.dataSnapshot?.marketCalendar) {
    const calendar = run.dataSnapshot.marketCalendar;
    anchors.push({
      id: `marketCalendar:${calendar.market}:${calendar.tradingDay}`,
      type: "market-calendar",
      label: "Market calendar",
      reference: `${calendar.market} ${calendar.tradingDay} ${calendar.status}/${calendar.session}`,
      exportPath: "researchRun.dataSnapshot.marketCalendar"
    });
  }

  if (run.dataSnapshot?.preparationEvidence) {
    anchors.push({
      id: `preparationEvidence:${run.dataSnapshot.preparationEvidence.runId}`,
      type: "data-preparation",
      label: "Data preparation",
      reference: run.dataSnapshot.preparationEvidence.runId,
      exportPath: "researchRun.dataSnapshot.preparationEvidence"
    });
  }

  citations.forEach((citation) => {
    anchors.push({
      id: `citation:${citation.id}`,
      type: "citation",
      label: citation.label,
      reference: citation.id,
      exportPath: `aiReviewRuns[].record.citations[${citation.id}]`
    });
  });

  anchors.push(
    {
      id: `committee:${rounds.length}-rounds`,
      type: "committee-rounds",
      label: "Committee rounds",
      reference: String(rounds.length),
      exportPath: "aiReviewRuns[].record.rounds"
    },
    {
      id: `decision-log:${decisionLog.length}`,
      type: "decision-log",
      label: "Decision log",
      reference: String(decisionLog.length),
      exportPath: "aiReviewRuns[].record.decisionLog"
    },
    {
      id: "boundary:evidence-explanation-only",
      type: "risk-boundary",
      label: "AI boundary",
      reference: "Evidence explanation only",
      exportPath: "aiReviewRuns[].record.boundary"
    }
  );

  return anchors;
}

export function buildAiReviewRecordDriftRows({
  currentCitationCount,
  currentRunId,
  currentStatus,
  currentStrategyRevision,
  liveExecutionBlocked,
  records,
  roundCount
}: {
  currentCitationCount: number;
  currentRunId: string | null;
  currentStatus: AiReviewDossier["status"];
  currentStrategyRevision: string;
  liveExecutionBlocked: boolean;
  records: AiReviewRunRecord[];
  roundCount: number;
}): AiReviewRecordDriftRow[] {
  return records.map((record) => {
    const driftReasons: AiReviewRecordDriftReason[] = [];
    if (!currentRunId || record.runId !== currentRunId) {
      driftReasons.push("run");
    }
    if (record.strategyRevision !== currentStrategyRevision) {
      driftReasons.push("strategy");
    }
    if (record.status !== currentStatus) {
      driftReasons.push("status");
    }
    if (record.summary.citationCount !== currentCitationCount) {
      driftReasons.push("citations");
    }
    if (record.summary.roundCount !== roundCount) {
      driftReasons.push("rounds");
    }
    if (record.summary.liveExecutionBlocked !== liveExecutionBlocked) {
      driftReasons.push("boundary");
    }

    return {
      aiReviewId: record.aiReviewId,
      createdAt: record.createdAt,
      strategyRevision: record.strategyRevision,
      citationCount: record.summary.citationCount,
      roundCount: record.summary.roundCount,
      liveExecutionBlocked: record.summary.liveExecutionBlocked,
      status: driftReasons.length ? "drift" : "matched",
      driftCount: driftReasons.length,
      driftReasons
    };
  });
}

export function filterAiReviewRecordDriftRows(
  rows: AiReviewRecordDriftRow[],
  query: string
): AiReviewRecordDriftRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }

  return rows.filter((row) =>
    [
      row.aiReviewId,
      row.createdAt,
      row.strategyRevision,
      row.status,
      row.driftCount.toString(),
      row.citationCount.toString(),
      row.roundCount.toString(),
      row.liveExecutionBlocked ? "paper only blocked" : "live open",
      ...row.driftReasons
    ]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

export function buildAiReviewAuditTimelineItems({
  aiBoundary = "",
  citationCount = 0,
  currentRunId,
  currentStrategyRevision,
  dataSnapshot = null,
  decisionCount = 0,
  dossier,
  marketCalendar = null,
  paperExecution = null,
  preparationEvidence = null,
  records,
  roundCount = 0,
  riskApproval
}: {
  aiBoundary?: string;
  citationCount?: number;
  currentRunId: string | null;
  currentStrategyRevision: string;
  dataSnapshot?: ResearchRunDataSnapshot | null;
  decisionCount?: number;
  dossier: AiReviewDossier;
  marketCalendar?: ResearchContextMarketCalendar | null;
  paperExecution?: PaperExecutionSnapshot | null;
  preparationEvidence?: ResearchRunDataPreparationEvidence | null;
  records: AiReviewRunRecord[];
  roundCount?: number;
  riskApproval: RiskApprovalSummary;
}): AiReviewAuditTimelineItem[] {
  const currentEvidenceReady = Boolean(currentRunId) && dossier.status === "ready";
  const currentRunReference = currentRunId ?? "pending-audit-run";
  const citationBundleItem =
    currentRunId && citationCount > 0
      ? ({
          id: `citations:${citationCount}`,
          kind: "citation-bundle-evidence" as const,
          label: "Citation bundle",
          value: `${citationCount} citations`,
          detail: `AI review citations locked for ${currentRunReference}`,
          reference: String(citationCount),
          exportAnchor: `citations:${citationCount}`,
          createdAt: null,
          targetWorkspaceId: "ai-review" as const,
          targetRecordId: null,
          actionLabel: "Open citations",
          status: "passed" as const,
          tone: "ai" as const
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const strategyItem =
    currentRunId && currentStrategyRevision.trim() && currentStrategyRevision !== "draft"
      ? ({
          id: `strategy:${currentStrategyRevision}`,
          kind: "strategy-revision-evidence" as const,
          label: "Strategy revision",
          value: currentStrategyRevision,
          detail: `Audited strategy revision · ${currentStrategyRevision}`,
          reference: currentStrategyRevision,
          exportAnchor: `strategy:${currentStrategyRevision}`,
          createdAt: null,
          targetWorkspaceId: "strategy" as const,
          targetRecordId: null,
          actionLabel: "Open strategy revision",
          status: "passed" as const,
          tone: "positive" as const
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const committeeItem =
    currentRunId && roundCount > 0
      ? ({
          id: `committee:${roundCount}-rounds`,
          kind: "committee-rounds-evidence" as const,
          label: "Committee rounds",
          value: `${roundCount} rounds`,
          detail: `TradingAgents committee rounds locked for ${currentRunReference}`,
          reference: String(roundCount),
          exportAnchor: `committee:${roundCount}-rounds`,
          createdAt: null,
          targetWorkspaceId: "ai-review" as const,
          targetRecordId: null,
          actionLabel: "Open committee rounds",
          status: "passed" as const,
          tone: "ai" as const
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const decisionLogItem =
    currentRunId && decisionCount > 0
      ? ({
          id: `decision-log:${decisionCount}`,
          kind: "decision-log-evidence" as const,
          label: "Decision log",
          value: `${decisionCount} entries`,
          detail: `AI review decision log locked for ${currentRunReference}`,
          reference: String(decisionCount),
          exportAnchor: `decision-log:${decisionCount}`,
          createdAt: null,
          targetWorkspaceId: "ai-review" as const,
          targetRecordId: null,
          actionLabel: "Open decision log",
          status: "passed" as const,
          tone: "ai" as const
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const normalizedAiBoundary = aiBoundary.trim();
  const aiBoundaryItem =
    currentRunId && normalizedAiBoundary
      ? ({
          id: "boundary:evidence-explanation-only",
          kind: "ai-boundary-evidence" as const,
          label: "AI boundary",
          value: "Evidence explanation only",
          detail: normalizedAiBoundary,
          reference: "Evidence explanation only",
          exportAnchor: "boundary:evidence-explanation-only",
          createdAt: null,
          targetWorkspaceId: "ai-review" as const,
          targetRecordId: null,
          actionLabel: "Open AI boundary",
          status: "blocked" as const,
          tone: "risk" as const
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const snapshotItem =
    dataSnapshot?.hash && Number.isFinite(dataSnapshot.rows) && dataSnapshot.rows > 0
      ? ({
          id: `snapshot:${dataSnapshot.hash}`,
          kind: "data-snapshot-evidence" as const,
          label: "Data snapshot",
          value: `${dataSnapshot.rows} rows · ${dataSnapshot.source}`,
          detail: `${dataSnapshot.source} · ${dataSnapshot.hash} · ${formatWarningCount(dataSnapshot.warnings.length)}`,
          reference: dataSnapshot.hash,
          exportAnchor: `data:${dataSnapshot.hash}`,
          createdAt: dataSnapshot.end,
          targetWorkspaceId: "backtest" as const,
          targetRecordId: null,
          actionLabel: "Open data snapshot",
          status:
            dataSnapshot.isComplete && dataSnapshot.warnings.length === 0 ? ("passed" as const) : ("review" as const),
          tone: dataSnapshot.isComplete && dataSnapshot.warnings.length === 0 ? ("positive" as const) : ("warning" as const)
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const preparationItem = preparationEvidence
    ? ({
        id: `preparation:${preparationEvidence.runId}`,
        kind: "data-preparation-evidence" as const,
        label: "Data preparation",
        value: `${preparationEvidence.upsertedRows} rows · ${preparationEvidence.quality.source}`,
        detail: formatPreparationEvidenceDetail(preparationEvidence),
        reference: preparationEvidence.runId,
        exportAnchor: `preparationEvidence:${preparationEvidence.runId}`,
        createdAt: preparationEvidence.createdAt,
        targetWorkspaceId: "backtest" as const,
        targetRecordId: null,
        actionLabel: "Open preparation evidence",
        status: preparationEvidence.quality.isComplete ? ("passed" as const) : ("review" as const),
        tone: preparationEvidence.quality.isComplete ? ("positive" as const) : ("warning" as const)
      } satisfies AiReviewAuditTimelineItem)
    : null;
  const paperExecutionPreparationEvidence =
    paperExecution?.runId === currentRunId ? (paperExecution.preparationEvidence ?? null) : null;
  const paperExecutionPreparationItem =
    paperExecution && paperExecutionPreparationEvidence
      ? ({
          id: `paper-preparation:${paperExecutionPreparationEvidence.runId}`,
          kind: "paper-execution-preparation-evidence" as const,
          label: "Paper execution preparation",
          value: `${paperExecutionPreparationEvidence.upsertedRows} rows · ${paperExecutionPreparationEvidence.quality.source}`,
          detail: `Paper ${paperExecution.executionId} · ${formatPreparationEvidenceDetail(paperExecutionPreparationEvidence)}`,
          reference: paperExecutionPreparationEvidence.runId,
          exportAnchor: `paperExecution:${paperExecution.executionId}:preparationEvidence:${paperExecutionPreparationEvidence.runId}`,
          createdAt: paperExecutionPreparationEvidence.createdAt,
          targetWorkspaceId: "execution" as const,
          targetRecordId: paperExecution.executionId,
          actionLabel: "Open paper evidence",
          status: paperExecutionPreparationEvidence.quality.isComplete ? ("passed" as const) : ("review" as const),
          tone: paperExecutionPreparationEvidence.quality.isComplete ? ("positive" as const) : ("warning" as const)
        } satisfies AiReviewAuditTimelineItem)
      : null;
  const calendarItem = marketCalendar
    ? ({
        id: `calendar:${marketCalendar.market}:${marketCalendar.tradingDay}`,
        kind: "market-calendar-evidence" as const,
        label: "Market calendar",
        value: `${marketCalendar.status} · ${marketCalendar.session}`,
        detail: formatMarketCalendarEvidenceDetail(marketCalendar),
        reference: `${marketCalendar.market} ${marketCalendar.tradingDay} ${marketCalendar.status}/${marketCalendar.session}`,
        exportAnchor: `marketCalendar:${marketCalendar.market}:${marketCalendar.tradingDay}`,
        createdAt: marketCalendar.asOf,
        targetWorkspaceId: "backtest" as const,
        targetRecordId: null,
        actionLabel: "Open calendar evidence",
        status: marketCalendarEvidenceTone(marketCalendar) === "positive" ? ("passed" as const) : ("review" as const),
        tone: marketCalendarEvidenceTone(marketCalendar)
      } satisfies AiReviewAuditTimelineItem)
    : null;
  const savedRecordItems = [...records]
    .sort((left, right) => timestampSortValue(right.createdAt) - timestampSortValue(left.createdAt))
    .map((record) => ({
      id: `saved:${record.aiReviewId}`,
      kind: "saved-review" as const,
      label: "Saved AI review",
      value: `${record.strategyRevision} · ${record.summary.citationCount} citations · ${record.summary.roundCount} rounds`,
      detail: record.dossier.headline,
      reference: record.aiReviewId,
      exportAnchor: `aiReviewRun:${record.aiReviewId}`,
      createdAt: record.createdAt,
      targetWorkspaceId: null,
      targetRecordId: record.aiReviewId,
      actionLabel: "Compare saved review",
      status: record.status === "ready" ? ("passed" as const) : ("blocked" as const),
      tone: record.status === "ready" ? ("ai" as const) : ("risk" as const)
    }));

  return [
    {
      id: `current:${currentRunReference}`,
      kind: "current-evidence",
      label: "Current audit evidence",
      value: currentRunId
        ? `${currentStrategyRevision} · ${dossier.citations.length} citations`
        : `${currentStrategyRevision} · no audited run`,
      detail: dossier.headline,
      reference: currentRunReference,
      exportAnchor: `run:${currentRunReference}`,
      createdAt: null,
      targetWorkspaceId: "backtest",
      targetRecordId: null,
      actionLabel: "Open backtest evidence",
      status: currentEvidenceReady ? "passed" : "blocked",
      tone: currentEvidenceReady ? "ai" : "risk"
    },
    ...(citationBundleItem ? [citationBundleItem] : []),
    ...(strategyItem ? [strategyItem] : []),
    ...(committeeItem ? [committeeItem] : []),
    ...(decisionLogItem ? [decisionLogItem] : []),
    ...(aiBoundaryItem ? [aiBoundaryItem] : []),
    ...(snapshotItem ? [snapshotItem] : []),
    ...(preparationItem ? [preparationItem] : []),
    ...(paperExecutionPreparationItem ? [paperExecutionPreparationItem] : []),
    ...(calendarItem ? [calendarItem] : []),
    ...savedRecordItems,
    {
      id: `risk:${riskApproval.status}`,
      kind: "risk-approval",
      label: "Risk approval",
      value: riskApproval.headline,
      detail: riskApproval.summary,
      reference: `risk:${riskApproval.status}`,
      exportAnchor: `riskApproval:${riskApproval.status}`,
      createdAt: null,
      targetWorkspaceId: "execution",
      targetRecordId: null,
      actionLabel: "Open execution approval",
      status:
        riskApproval.status === "live_ready" ? "passed" : riskApproval.status === "paper_ready" ? "review" : "blocked",
      tone:
        riskApproval.status === "live_ready" ? "positive" : riskApproval.status === "paper_ready" ? "warning" : "risk"
    }
  ];
}

export function buildAiReviewExportEvidenceIndexRows({
  currentRecord,
  records,
  timelineItems
}: {
  currentRecord: AiReviewRunRecord | null;
  records: AiReviewRunRecord[];
  timelineItems: AiReviewAuditTimelineItem[];
}): AiReviewExportEvidenceIndexRow[] {
  const rows: AiReviewExportEvidenceIndexRow[] = [];

  currentRecord?.evidenceAnchors?.forEach((anchor) => {
    rows.push({
      id: `current:${anchor.id}`,
      group: "current-record",
      label: anchor.label,
      anchor: anchor.id,
      reference: anchor.reference,
      exportPath: anchor.exportPath,
      detail: `Current AI review record · ${currentRecord.aiReviewId}`,
      tone: anchor.type === "risk-boundary" ? "risk" : "ai"
    });
  });

  records.forEach((record) => {
    record.evidenceAnchors?.forEach((anchor) => {
      rows.push({
        id: `saved:${record.aiReviewId}:${anchor.id}`,
        group: "saved-record",
        label: `${record.strategyRevision} · ${anchor.label}`,
        anchor: anchor.id,
        reference: anchor.reference,
        exportPath: anchor.exportPath,
        detail: `Saved AI review record · ${record.aiReviewId}`,
        tone: anchor.type === "risk-boundary" ? "risk" : "neutral"
      });
    });
  });

  timelineItems.forEach((item) => {
    rows.push({
      id: `timeline:${item.reference}`,
      group: "timeline",
      label: item.label,
      anchor: item.exportAnchor,
      reference: item.reference,
      exportPath: auditTimelineExportPath(item),
      detail: item.detail,
      tone: item.tone
    });
  });

  return rows;
}

export function filterAiReviewExportEvidenceIndexRows(
  rows: AiReviewExportEvidenceIndexRow[],
  query: string
): AiReviewExportEvidenceIndexRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }

  return rows.filter((row) =>
    [row.group, row.label, row.anchor, row.reference, row.exportPath, row.detail, row.tone]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

export function buildResearchRunExportPreviewRows({
  aiReviewRecords = [],
  currentAiReviewRecord = null,
  paperExecution = null,
  promotionCandidate = null,
  riskApproval = null,
  workspace
}: {
  workspace: TerminalWorkspace;
  currentAiReviewRecord?: AiReviewRunRecord | null;
  aiReviewRecords?: ResearchRunExportPreviewAiReviewEnvelope[];
  paperExecution?: PaperExecutionSnapshot | null;
  promotionCandidate?: ResearchRunExportPreviewPromotionCandidate | null;
  riskApproval?: RiskApprovalSummary | null;
}): ResearchRunExportPreviewRow[] {
  const run = workspace.researchRun ?? null;
  const runId = run?.runId ?? "pending-run";
  const dataSnapshot = run?.dataSnapshot ?? null;
  const preparationEvidence = dataSnapshot?.preparationEvidence ?? null;
  const marketCalendar = dataSnapshot?.marketCalendar ?? null;
  const researchNote = normalizedResearchNote(run?.researchNote);
  const activePaperExecution = run && paperExecution?.runId === run.runId ? paperExecution : null;
  const activePaperPreparationEvidence = activePaperExecution?.preparationEvidence ?? null;
  const activePromotionCandidate =
    run && promotionCandidate?.runId && promotionCandidate.runId === run.runId ? promotionCandidate : null;
  const activeAiReviewRecords = run
    ? aiReviewRecords.filter((record) => record.runId === run.runId)
    : [];
  const latestAiReviewRecord = activeAiReviewRecords[0] ?? null;
  const currentRecordReady = Boolean(currentAiReviewRecord && run && currentAiReviewRecord.runId === run.runId);
  const backtestTradeCount = workspace.backtestTrades?.length ?? 0;
  const equityPointCount = workspace.backtestEquityCurve?.length ?? 0;

  return [
    {
      id: "research-run",
      label: "Research run",
      status: run ? "ready" : "blocked",
      count: run ? "1" : "0",
      anchor: `run:${runId}`,
      exportPath: "researchRun",
      detail: run
        ? `${workspace.selectedInstrument.symbol} · ${run.timeframe} · ${run.strategyRevision} · ${run.dataRows} bars`
        : "Run Pipeline before an export package can be reproduced.",
      tone: run ? "positive" : "risk"
    },
    {
      id: "data-snapshot",
      label: "Data snapshot",
      status:
        run && dataSnapshot?.hash && Number.isFinite(dataSnapshot.rows) && dataSnapshot.rows > 0
          ? "ready"
          : run
            ? "missing"
            : "blocked",
      count: dataSnapshot ? String(dataSnapshot.rows) : "0",
      anchor: dataSnapshot?.hash ? `dataSnapshot:${dataSnapshot.hash}` : `dataSnapshot:${runId}:missing`,
      exportPath: "researchRun.dataSnapshot",
      detail: dataSnapshot
        ? `${dataSnapshot.source} · ${dataSnapshot.hash} · ${formatWarningCount(dataSnapshot.warnings.length)}`
        : run
          ? "The audited run did not include a local data snapshot hash."
          : "A research run is required before data can be exported.",
      tone:
        run && dataSnapshot?.hash && Number.isFinite(dataSnapshot.rows) && dataSnapshot.rows > 0
          ? dataSnapshot.warnings.length
            ? "warning"
            : "positive"
          : run
            ? "warning"
            : "risk"
    },
    {
      id: "market-calendar",
      label: "Market calendar",
      status: marketCalendar ? "ready" : run ? "missing" : "blocked",
      count: marketCalendar ? `${marketCalendar.status} · ${marketCalendar.session}` : "missing",
      anchor: marketCalendar ? `marketCalendar:${marketCalendar.market}:${marketCalendar.tradingDay}` : `marketCalendar:${runId}:missing`,
      exportPath: "researchRun.dataSnapshot.marketCalendar",
      detail: marketCalendar
        ? formatMarketCalendarEvidenceDetail(marketCalendar)
        : run
          ? "The audited run did not include market calendar evidence."
          : "Run Pipeline before market calendar evidence can be exported.",
      tone: marketCalendar ? marketCalendarEvidenceTone(marketCalendar) : run ? "warning" : "risk"
    },
    {
      id: "preparation-evidence",
      label: "Preparation evidence",
      status: preparationEvidence ? "ready" : run ? "missing" : "blocked",
      count: preparationEvidence ? `${preparationEvidence.upsertedRows} rows` : "0 rows",
      anchor: preparationEvidence
        ? `preparationEvidence:${preparationEvidence.runId}`
        : `preparationEvidence:${runId}:missing`,
      exportPath: "researchRun.dataSnapshot.preparationEvidence",
      detail: preparationEvidence
        ? formatPreparationEvidenceDetail(preparationEvidence)
        : run
          ? "The audited run did not lock a matching watchlist cache refresh run."
          : "Run Pipeline from a matched watchlist cache refresh before preparation evidence can be exported.",
      tone: preparationEvidence ? (preparationEvidence.quality.isComplete ? "positive" : "warning") : run ? "warning" : "risk"
    },
    {
      id: "strategy-config",
      label: "Strategy config",
      status: run?.strategyConfig ? "ready" : run ? "missing" : "blocked",
      count: run?.strategyConfig ? `${run.strategyConfig.entryConditions.length}/${run.strategyConfig.exitConditions.length}` : "0/0",
      anchor: run?.strategyConfig ? `strategy:${run.strategyConfig.revision}` : `strategy:${runId}:missing`,
      exportPath: "researchRun.strategyConfig",
      detail: run?.strategyConfig
        ? `${run.strategyConfig.name} · v${run.strategyConfig.version} · ${run.strategyConfig.symbols.join(", ")}`
        : run
          ? "The export can replay the run, but structured strategy rules are missing."
          : "Run Pipeline after saving a strategy to bind structured rules.",
      tone: run?.strategyConfig ? "positive" : run ? "warning" : "risk"
    },
    {
      id: "research-note",
      label: "Research note",
      status: researchNote ? "ready" : run ? "missing" : "blocked",
      count: researchNote ? "1" : "0",
      anchor: researchNote ? `researchNote:${researchNote.symbol}:${researchNote.timeframe}` : `researchNote:${runId}:missing`,
      exportPath: "researchRun.researchNote",
      detail: researchNote
        ? compactResearchNoteDetail(researchNote.body)
        : run
          ? "No research note is attached to this run; add one for stronger replay context."
          : "Research notes are bound after a run is created.",
      tone: researchNote ? "ai" : run ? "neutral" : "risk"
    },
    {
      id: "backtest-trades",
      label: "Backtest trades",
      status: backtestTradeCount > 0 || equityPointCount > 0 ? "ready" : run ? "missing" : "blocked",
      count:
        backtestTradeCount > 0 || equityPointCount > 0
          ? `${backtestTradeCount} trades / ${equityPointCount} equity`
          : "0 trades / 0 equity",
      anchor: `backtest:${runId}`,
      exportPath: "researchRun.backtestTrades",
      detail:
        backtestTradeCount > 0 || equityPointCount > 0
          ? "Trade blotter and equity curve are available for replay."
          : run
            ? "The run summary is bound, but the trade blotter or equity curve is missing."
            : "Run Pipeline before backtest replay artifacts are exported.",
      tone: backtestTradeCount > 0 || equityPointCount > 0 ? "positive" : run ? "warning" : "risk"
    },
    {
      id: "ai-review-runs",
      label: "AI review runs",
      status: activeAiReviewRecords.length > 0 ? "ready" : currentRecordReady ? "missing" : run ? "missing" : "blocked",
      count: `${activeAiReviewRecords.length} saved / ${currentRecordReady ? "current ready" : "current missing"}`,
      anchor: latestAiReviewRecord
        ? `aiReviewRun:${latestAiReviewRecord.aiReviewId}`
        : currentRecordReady
          ? `aiReviewRun:${currentAiReviewRecord?.aiReviewId}`
          : `aiReviewRun:${runId}:missing`,
      exportPath: "aiReviewRuns[]",
      detail:
        activeAiReviewRecords.length > 0
          ? "Saved AI review records are attached to this export package."
          : currentRecordReady
            ? "Current AI evidence is ready, but it has not been saved into the export package yet."
            : run
              ? "Run and save an AI review record before relying on exported AI evidence."
              : "A research run is required before AI review records can be exported.",
      tone: activeAiReviewRecords.length > 0 ? "ai" : currentRecordReady || run ? "warning" : "risk"
    },
    {
      id: "paper-executions",
      label: "Paper executions",
      status: activePaperExecution ? "ready" : run ? "missing" : "blocked",
      count: activePaperExecution ? `${activePaperExecution.orders.length} order${activePaperExecution.orders.length === 1 ? "" : "s"}` : "0 orders",
      anchor: activePaperExecution ? `paperExecution:${activePaperExecution.executionId}` : `paperExecution:${runId}:missing`,
      exportPath: "paperExecutions[]",
      detail: activePaperExecution
        ? [
            activePaperExecution.mode,
            `${activePaperExecution.gates.filter((gate) => gate.passed).length}/${activePaperExecution.gates.length} gates passed`,
            ...(activePaperPreparationEvidence ? [`prep ${activePaperPreparationEvidence.runId}`] : [])
          ].join(" · ")
        : run
          ? "Submit a paper order to attach execution evidence to the run package."
          : "Paper execution waits for an audited run.",
      tone: activePaperExecution ? "positive" : run ? "warning" : "risk"
    },
    {
      id: "promotion-candidate",
      label: "Promotion candidate",
      status: activePromotionCandidate
        ? activePromotionCandidate.status === "live_ready" || activePromotionCandidate.liveTradingAllowed
          ? "ready"
          : "blocked"
        : run
          ? "missing"
          : "blocked",
      count: activePromotionCandidate?.evidence
        ? `${activePromotionCandidate.evidence.filledOrders} fills / ${activePromotionCandidate.evidence.passedPaperRiskChecks} risk`
        : "0 fills / 0 risk",
      anchor: activePromotionCandidate?.candidateId
        ? `promotion:${activePromotionCandidate.candidateId}`
        : `promotion:${runId}:missing`,
      exportPath: "promotionCandidate",
      detail: activePromotionCandidate
        ? activePromotionCandidate.summary ?? "Promotion evidence is attached, but live execution remains blocked."
        : run
          ? "Create a paper execution before promotion evidence can be attached."
          : "Promotion evidence waits for a research run.",
      tone:
        activePromotionCandidate?.status === "live_ready" || activePromotionCandidate?.liveTradingAllowed
          ? "positive"
          : activePromotionCandidate
            ? "warning"
            : run
              ? "neutral"
              : "risk"
    },
    {
      id: "execution-handoff",
      label: "Execution handoff",
      status: run && riskApproval && riskApproval.status !== "blocked" ? "ready" : run ? "blocked" : "blocked",
      count: riskApproval ? `${riskApproval.gates.filter((gate) => gate.status === "passed").length}/${riskApproval.gates.length}` : "0/0",
      anchor: riskApproval ? `riskApproval:${riskApproval.status}` : `riskApproval:${runId}:missing`,
      exportPath: "executionHandoff.requiredGates",
      detail: riskApproval
        ? riskApproval.summary
        : "Execution handoff gates are created after an audited run is available.",
      tone: riskApproval?.status === "live_ready" ? "positive" : riskApproval?.status === "paper_ready" ? "warning" : "risk"
    }
  ];
}

export function filterResearchRunExportPreviewRows(
  rows: ResearchRunExportPreviewRow[],
  query: string
): ResearchRunExportPreviewRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }
  return rows.filter((row) =>
    [row.id, row.label, row.status, row.count, row.anchor, row.exportPath, row.detail, row.tone]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

function collectPaperExecutionPreparationEvidenceRunIds(
  executions: readonly PaperExecutionSnapshot[] | null | undefined
): string[] {
  return Array.from(
    new Set(
      (executions ?? [])
        .map((execution) => execution.preparationEvidence?.runId)
        .filter((runId): runId is string => Boolean(runId))
    )
  );
}

function formatAdapterPaperExecutionEvidenceDetail(
  executions: readonly ExecutionAdapterPaperExecutionSnapshot[] | null | undefined
): string {
  const firstExecution = executions?.[0];
  if (!firstExecution) {
    return "No adapter paper execution evidence is attached.";
  }
  return [
    firstExecution.adapterPaperExecutionId,
    firstExecution.adapterId,
    firstExecution.route,
    firstExecution.simulatedFill.status
  ].join(" · ");
}

function formatPortfolioPaperOrderSimulationAdapterEvidenceDetail(
  simulations: readonly PortfolioPaperOrderSimulationSnapshot[] | null | undefined
): string {
  const withAdapterEvidence = (simulations ?? []).filter((simulation) => simulation.adapterPaperExecutionId);
  if (!withAdapterEvidence.length) {
    return "";
  }
  const firstSimulation = withAdapterEvidence[0];
  const evidence = firstSimulation?.adapterPaperExecutionEvidence ?? {};
  const fillSummary = typeof evidence.fillSummary === "string" ? evidence.fillSummary : "adapter fill evidence";
  return `${withAdapterEvidence.length} simulated fill${
    withAdapterEvidence.length === 1 ? "" : "s"
  } carries adapter paper execution evidence: ${firstSimulation.adapterPaperExecutionId} · ${fillSummary}`;
}

export function buildResearchRunExportBrowserRows(
  exportPackage: ResearchRunExportBrowserPackage | null | undefined
): ResearchRunExportBrowserRow[] {
  if (!exportPackage) {
    return [
      {
        id: "package",
        label: "Export package",
        status: "blocked",
        value: "No package selected",
        detail: "Inspect a run from history to load its manifest and artifact counts.",
        exportPath: "manifest.runId",
        tone: "risk"
      }
    ];
  }

  const { artifactCounts } = exportPackage.manifest;
  const paperPackageCount = exportPackage.paperExecutions?.length ?? 0;
  const paperPreparationEvidenceRunIds = collectPaperExecutionPreparationEvidenceRunIds(exportPackage.paperExecutions);
  const adapterPaperExecutionPackageCount = exportPackage.adapterPaperExecutions?.length ?? 0;
  const adapterPaperExecutionDetail = formatAdapterPaperExecutionEvidenceDetail(exportPackage.adapterPaperExecutions);
  const portfolioPaperOrderPackageCount = exportPackage.portfolioPaperOrderBatches?.length ?? 0;
  const portfolioPaperOrderApprovalPackageCount = exportPackage.portfolioPaperOrderApprovals?.length ?? 0;
  const portfolioPaperOrderSimulationPackageCount = exportPackage.portfolioPaperOrderSimulations?.length ?? 0;
  const portfolioPaperOrderSimulationAdapterEvidenceDetail =
    formatPortfolioPaperOrderSimulationAdapterEvidenceDetail(exportPackage.portfolioPaperOrderSimulations);
  const aiReviewPackageCount = exportPackage.aiReviewRuns?.length ?? 0;
  const auditEventPackageCount = exportPackage.auditEvents?.length ?? 0;
  const handoffNotePackageCount = exportPackage.handoffNotes?.length ?? 0;
  const p0PaperSimulationAuditEvents = (exportPackage.auditEvents ?? []).filter(
    (event) => event.eventType === "p0_paper_simulation"
  );
  const promotionPackageCount = exportPackage.promotionCandidate ? 1 : 0;
  const preparationEvidence = exportPackage.researchRun?.dataSnapshot?.preparationEvidence ?? null;
  const marketCalendar = exportPackage.researchRun?.dataSnapshot?.marketCalendar ?? null;
  const passedGateCount = exportPackage.executionHandoff.requiredGates.filter((gate) => gate.passed).length;
  const totalGateCount = exportPackage.executionHandoff.requiredGates.length;
  const integrityHash = exportPackage.integrity?.hash ?? "";
  const auditSummary = exportPackage.auditEvidenceSummary;
  const auditReport = exportPackage.auditReport;
  const backtestReport = exportPackage.backtestReport;
  const auditSummaryIsReady =
    auditSummary?.kind === "aiqt.auditEvidenceSummary" &&
    auditSummary.schemaVersion === 1 &&
    auditSummary.runId === exportPackage.manifest.runId &&
    auditSummary.copyText.trim() !== "";
  const auditReportHash = auditReport?.contentSha256.hash ?? "";
  const auditReportIsReady =
    auditReport?.kind === "aiqt.auditReport" &&
    auditReport.schemaVersion === 1 &&
    auditReport.runId === exportPackage.manifest.runId &&
    auditReport.format === "text/markdown" &&
    auditReport.contentSha256.algorithm === "sha256" &&
    /^[a-f0-9]{64}$/iu.test(auditReportHash) &&
    auditReport.contentMarkdown.trim() !== "";
  const backtestReportHash = backtestReport?.contentSha256.hash ?? "";
  const backtestReportIsReady =
    backtestReport?.kind === "aiqt.backtestReport" &&
    backtestReport.schemaVersion === 1 &&
    backtestReport.runId === exportPackage.manifest.runId &&
    backtestReport.format === "text/markdown" &&
    backtestReport.contentSha256.algorithm === "sha256" &&
    /^[a-f0-9]{64}$/iu.test(backtestReportHash) &&
    backtestReport.contentMarkdown.trim() !== "";
  const auditReportSignatureDetail = researchRunExportReportSignatureDetail(auditReport?.signature);
  const backtestReportSignatureDetail = researchRunExportReportSignatureDetail(backtestReport?.signature);
  const integrityIsReady = exportPackage.integrity?.algorithm === "sha256" && /^[a-f0-9]{64}$/iu.test(integrityHash);
  const dataIsReady =
    artifactCounts.bars === exportPackage.manifest.dataRows &&
    artifactCounts.bars > 0 &&
    exportPackage.manifest.dataHash.trim() !== "";
  const backtestIsReady = artifactCounts.trades > 0 && artifactCounts.equityPoints > 0;
  const paperCountMatches = (artifactCounts.paperExecutions ?? 0) === paperPackageCount;
  const adapterPaperExecutionCountMatches =
    (artifactCounts.adapterPaperExecutions ?? 0) === adapterPaperExecutionPackageCount;
  const portfolioPaperOrderCountMatches =
    (artifactCounts.portfolioPaperOrderBatches ?? 0) === portfolioPaperOrderPackageCount &&
    (artifactCounts.portfolioPaperOrderApprovals ?? 0) === portfolioPaperOrderApprovalPackageCount &&
    (artifactCounts.portfolioPaperOrderSimulations ?? 0) === portfolioPaperOrderSimulationPackageCount;
  const portfolioPaperOrderPackageHasLedger =
    portfolioPaperOrderPackageCount + portfolioPaperOrderApprovalPackageCount + portfolioPaperOrderSimulationPackageCount >
    0;
  const portfolioPaperOrderMismatchDetail = [
    (artifactCounts.portfolioPaperOrderBatches ?? 0) === portfolioPaperOrderPackageCount
      ? ""
      : `portfolioPaperOrderBatches ${artifactCounts.portfolioPaperOrderBatches ?? 0}/${portfolioPaperOrderPackageCount}`,
    (artifactCounts.portfolioPaperOrderApprovals ?? 0) === portfolioPaperOrderApprovalPackageCount
      ? ""
      : `portfolioPaperOrderApprovals ${artifactCounts.portfolioPaperOrderApprovals ?? 0}/${portfolioPaperOrderApprovalPackageCount}`,
    (artifactCounts.portfolioPaperOrderSimulations ?? 0) === portfolioPaperOrderSimulationPackageCount
      ? ""
      : `portfolioPaperOrderSimulations ${artifactCounts.portfolioPaperOrderSimulations ?? 0}/${portfolioPaperOrderSimulationPackageCount}`
  ].filter(Boolean);
  const promotionCountMatches = (artifactCounts.promotionCandidates ?? 0) === promotionPackageCount;
  const aiReviewCountMatches = (artifactCounts.aiReviewRuns ?? 0) === aiReviewPackageCount;
  const auditEventCountMatches = (artifactCounts.auditEvents ?? 0) === auditEventPackageCount;
  const handoffNoteCountMatches = (artifactCounts.handoffNotes ?? 0) === handoffNotePackageCount;
  const p0PackageCompleteness = exportPackage.p0PackageCompleteness;
  const p0CompletenessIsReady =
    p0PackageCompleteness?.kind === "aiqt.p0PackageCompleteness" &&
    p0PackageCompleteness.schemaVersion === 1 &&
    p0PackageCompleteness.runId === exportPackage.manifest.runId &&
    p0PackageCompleteness.ready &&
    p0PackageCompleteness.status === "complete" &&
    !p0PackageCompleteness.liveTradingAllowed &&
    p0PackageCompleteness.liveBlockedBoundary;

  return [
    {
      id: "package",
      label: "Export package",
      status: "ready",
      value: `${exportPackage.manifest.runId} · ${exportPackage.manifest.strategyRevision}`,
      detail: `${exportPackage.manifest.symbol} · ${exportPackage.manifest.timeframe} · exported ${exportPackage.exportedAt}`,
      exportPath: "manifest.runId",
      tone: "positive"
    },
    {
      id: "integrity",
      label: "Integrity",
      status: integrityIsReady ? "ready" : "missing",
      value: exportPackage.integrity ? `${exportPackage.integrity.algorithm} · ${integrityHash.slice(0, 8)}` : "No hash",
      detail: integrityIsReady
        ? "Canonical SHA-256 integrity metadata is present."
        : "Integrity metadata is missing or malformed.",
      exportPath: "integrity.hash",
      tone: integrityIsReady ? "positive" : "warning"
    },
    {
      id: "data",
      label: "Data snapshot",
      status: dataIsReady ? "ready" : "blocked",
      value: `${artifactCounts.bars}/${exportPackage.manifest.dataRows} bars`,
      detail: `${exportPackage.manifest.dataHash || "missing hash"} · ${exportPackage.manifest.market}`,
      exportPath: "manifest.artifactCounts.bars",
      tone: dataIsReady ? "positive" : "risk"
    },
    {
      id: "market-calendar",
      label: "Market calendar",
      status: marketCalendar ? "ready" : "missing",
      value: marketCalendar ? `${marketCalendar.status} · ${marketCalendar.session}` : "No market calendar evidence",
      detail: marketCalendar
        ? formatMarketCalendarEvidenceDetail(marketCalendar)
        : "Package research run does not include market calendar evidence.",
      exportPath: "researchRun.dataSnapshot.marketCalendar",
      tone: marketCalendar ? marketCalendarEvidenceTone(marketCalendar) : "neutral"
    },
    {
      id: "preparation-evidence",
      label: "Preparation evidence",
      status: preparationEvidence ? "ready" : "missing",
      value: preparationEvidence?.runId ?? "No preparation evidence",
      detail: preparationEvidence
        ? formatPreparationEvidenceDetail(preparationEvidence)
        : "Package research run does not include locked watchlist cache refresh evidence.",
      exportPath: "researchRun.dataSnapshot.preparationEvidence",
      tone: preparationEvidence ? (preparationEvidence.quality.isComplete ? "positive" : "warning") : "neutral"
    },
    {
      id: "backtest",
      label: "Backtest replay",
      status: backtestIsReady ? "ready" : "missing",
      value: `${artifactCounts.trades} trades / ${artifactCounts.equityPoints} equity`,
      detail: `${artifactCounts.decisions} decisions · ${artifactCounts.aiRisks} AI risks`,
      exportPath: "researchRun.backtestTrades",
      tone: backtestIsReady ? "positive" : "warning"
    },
    ...(backtestReport
      ? ([
          {
            id: "backtest-report",
            label: "Backtest report",
            status: backtestReportIsReady ? "ready" : "blocked",
            value: backtestReport.contentSha256
              ? `${backtestReport.contentSha256.algorithm} · ${backtestReportHash.slice(0, 8)}`
              : "No content hash",
            detail: backtestReportIsReady
              ? [
                  `${backtestReport.fileName} · ${backtestReport.runComparisonRows} comparable runs`,
                  backtestReportSignatureDetail
                ]
                  .filter(Boolean)
                  .join(" · ")
              : "Backtest report artifact is missing valid Markdown content or SHA-256 metadata.",
            exportPath: "backtestReport.contentSha256.hash",
            tone: backtestReportIsReady ? "ai" : "risk"
          }
        ] satisfies ResearchRunExportBrowserRow[])
      : []),
    {
      id: "research-note",
      label: "Research note",
      status: (artifactCounts.researchNotes ?? 0) > 0 ? "ready" : "missing",
      value: `${artifactCounts.researchNotes ?? 0} note`,
      detail:
        (artifactCounts.researchNotes ?? 0) > 0
          ? "Locked research context is declared in the manifest."
          : "No locked research note is declared in this package.",
      exportPath: "researchRun.researchNote",
      tone: (artifactCounts.researchNotes ?? 0) > 0 ? "ai" : "neutral"
    },
    {
      id: "handoff-notes",
      label: "Handoff notes",
      status:
        handoffNoteCountMatches && handoffNotePackageCount > 0
          ? "ready"
          : handoffNoteCountMatches
            ? "missing"
            : "blocked",
      value: `${artifactCounts.handoffNotes ?? 0} manifest / ${handoffNotePackageCount} package`,
      detail: handoffNoteCountMatches
        ? "Local team handoff note count matches the export package payload."
        : "Handoff note manifest count does not match the package payload.",
      exportPath: "handoffNotes[]",
      tone: handoffNoteCountMatches && handoffNotePackageCount > 0 ? "ai" : handoffNoteCountMatches ? "neutral" : "risk"
    },
    {
      id: "paper-executions",
      label: "Paper executions",
      status: paperCountMatches && paperPackageCount > 0 ? "ready" : paperCountMatches ? "missing" : "blocked",
      value: `${artifactCounts.paperExecutions ?? 0} manifest / ${paperPackageCount} package`,
      detail: paperCountMatches
        ? [
            "Manifest and package paper execution counts match",
            ...(paperPreparationEvidenceRunIds.length ? [`prep ${paperPreparationEvidenceRunIds.join(", ")}`] : [])
          ].join(" · ")
        : "Manifest paper execution count does not match the package payload.",
      exportPath: "paperExecutions[]",
      tone: paperCountMatches && paperPackageCount > 0 ? "positive" : paperCountMatches ? "neutral" : "risk"
    },
    {
      id: "adapter-paper-executions",
      label: "Adapter paper executions",
      status:
        adapterPaperExecutionCountMatches && adapterPaperExecutionPackageCount > 0
          ? "ready"
          : adapterPaperExecutionCountMatches
            ? "missing"
            : "blocked",
      value: `${artifactCounts.adapterPaperExecutions ?? 0} manifest / ${adapterPaperExecutionPackageCount} package`,
      detail: adapterPaperExecutionCountMatches
        ? adapterPaperExecutionDetail
        : "Manifest adapter paper execution count does not match the package payload.",
      exportPath: "adapterPaperExecutions[]",
      tone:
        adapterPaperExecutionCountMatches && adapterPaperExecutionPackageCount > 0
          ? "positive"
          : adapterPaperExecutionCountMatches
            ? "neutral"
            : "risk"
    },
    {
      id: "portfolio-paper-orders",
      label: "Portfolio paper orders",
      status:
        portfolioPaperOrderCountMatches && portfolioPaperOrderPackageHasLedger
          ? "ready"
          : portfolioPaperOrderCountMatches
            ? "missing"
            : "blocked",
      value: `${artifactCounts.portfolioPaperOrderBatches ?? 0} batches / ${artifactCounts.portfolioPaperOrderApprovals ?? 0} approvals / ${artifactCounts.portfolioPaperOrderSimulations ?? 0} fills`,
      detail: portfolioPaperOrderCountMatches
        ? [
            "Portfolio paper order batch, approval, and simulated-fill counts match the package payload. portfolioPaperOrderBatches / portfolioPaperOrderApprovals / portfolioPaperOrderSimulations",
            portfolioPaperOrderSimulationAdapterEvidenceDetail
          ]
            .filter(Boolean)
            .join(" · ")
        : `Portfolio paper order manifest count does not match the package payload: ${portfolioPaperOrderMismatchDetail.join(", ")}.`,
      exportPath: "portfolioPaperOrderBatches[] portfolioPaperOrderApprovals[] portfolioPaperOrderSimulations[]",
      tone:
        portfolioPaperOrderCountMatches && portfolioPaperOrderPackageHasLedger
          ? "warning"
          : portfolioPaperOrderCountMatches
            ? "neutral"
            : "risk"
    },
    {
      id: "promotion-candidate",
      label: "Promotion candidate",
      status: promotionCountMatches && promotionPackageCount > 0 ? "ready" : promotionCountMatches ? "missing" : "blocked",
      value: `${artifactCounts.promotionCandidates ?? 0} manifest / ${promotionPackageCount} package`,
      detail: exportPackage.promotionCandidate?.summary ?? "No promotion candidate payload is attached.",
      exportPath: "promotionCandidate",
      tone: promotionCountMatches && promotionPackageCount > 0 ? "warning" : promotionCountMatches ? "neutral" : "risk"
    },
    {
      id: "ai-reviews",
      label: "AI review records",
      status: aiReviewCountMatches && aiReviewPackageCount > 0 ? "ready" : aiReviewCountMatches ? "missing" : "blocked",
      value: `${artifactCounts.aiReviewRuns ?? 0} manifest / ${aiReviewPackageCount} package`,
      detail: aiReviewCountMatches
        ? "AI review record count matches the export package payload."
        : "AI review manifest count does not match the package payload.",
      exportPath: "aiReviewRuns[]",
      tone: aiReviewCountMatches && aiReviewPackageCount > 0 ? "ai" : aiReviewCountMatches ? "neutral" : "risk"
    },
    {
      id: "audit-events",
      label: "Audit events",
      status:
        auditEventCountMatches && auditEventPackageCount > 0
          ? "ready"
          : auditEventCountMatches
            ? "missing"
            : "blocked",
      value: `${artifactCounts.auditEvents ?? 0} manifest / ${auditEventPackageCount} package`,
      detail: auditEventCountMatches
        ? `${p0PaperSimulationAuditEvents.length} P0 paper simulation event${
            p0PaperSimulationAuditEvents.length === 1 ? "" : "s"
          }${
            p0PaperSimulationAuditEvents[0]?.eventType ? ` · ${p0PaperSimulationAuditEvents[0].eventType}` : ""
          }${
            p0PaperSimulationAuditEvents[0]?.eventId ? ` · ${p0PaperSimulationAuditEvents[0].eventId}` : ""
          }`
        : "Manifest audit event count does not match the package payload.",
      exportPath: "auditEvents[]",
      tone: auditEventCountMatches && auditEventPackageCount > 0 ? "ai" : auditEventCountMatches ? "neutral" : "risk"
    },
    ...(p0PackageCompleteness
      ? ([
          {
            id: "p0-completeness",
            label: "P0 package completeness",
            status: p0CompletenessIsReady ? "ready" : p0PackageCompleteness.blocked > 0 ? "blocked" : "missing",
            value: `${p0PackageCompleteness.passed}/${p0PackageCompleteness.total} · ${p0PackageCompleteness.status}`,
            detail: p0PackageCompleteness.summary,
            exportPath: "p0PackageCompleteness",
            tone: p0CompletenessIsReady ? "positive" : p0PackageCompleteness.blocked > 0 ? "risk" : "warning"
          }
        ] satisfies ResearchRunExportBrowserRow[])
      : []),
    ...(auditSummary
      ? ([
          {
            id: "audit-summary",
            label: "Audit evidence summary",
            status: auditSummaryIsReady ? "ready" : "blocked",
            value: `${auditSummary.package.matched}/${auditSummary.package.total} package · ${auditSummary.importDiff.blocked} diff blocked`,
            detail: auditSummaryIsReady
              ? `Copyable audit focus embedded at ${auditSummary.generatedAt}.`
              : "Audit evidence summary metadata does not match this export package.",
            exportPath: "auditEvidenceSummary",
            tone: auditSummaryIsReady ? "ai" : "risk"
          }
        ] satisfies ResearchRunExportBrowserRow[])
      : []),
    ...(auditReport
      ? ([
          {
            id: "audit-report",
            label: "Audit report",
            status: auditReportIsReady ? "ready" : "blocked",
            value: auditReport.contentSha256
              ? `${auditReport.contentSha256.algorithm} · ${auditReportHash.slice(0, 8)}`
              : "No content hash",
            detail: auditReportIsReady
              ? [`${auditReport.fileName} · generated ${auditReport.generatedAt}`, auditReportSignatureDetail]
                  .filter(Boolean)
                  .join(" · ")
              : "Audit report artifact is missing valid Markdown content or SHA-256 metadata.",
            exportPath: "auditReport.contentSha256.hash",
            tone: auditReportIsReady ? "ai" : "risk"
          }
        ] satisfies ResearchRunExportBrowserRow[])
      : []),
    {
      id: "execution-handoff",
      label: "Execution handoff",
      status: exportPackage.executionHandoff.liveTradingAllowed ? "ready" : "blocked",
      value: `${passedGateCount}/${totalGateCount} gates`,
      detail: exportPackage.executionHandoff.liveTradingAllowed
        ? "Live execution handoff is allowed by the package gates."
        : "Package remains paper-only; live execution is blocked.",
      exportPath: "executionHandoff.requiredGates",
      tone: exportPackage.executionHandoff.liveTradingAllowed ? "positive" : "risk"
    }
  ];
}

export function filterResearchRunExportBrowserRows(
  rows: ResearchRunExportBrowserRow[],
  query: string
): ResearchRunExportBrowserRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }
  return rows.filter((row) =>
    [row.id, row.label, row.status, row.value, row.detail, row.exportPath, row.tone]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

function researchRunExportReportSignatureMetadata(signature: Record<string, unknown> | undefined): Record<string, unknown> {
  return signature && typeof signature === "object" && !Array.isArray(signature) ? signature : {};
}

function researchRunExportReportSignatureStatus(signature: Record<string, unknown> | undefined): AuditEvidenceReportSignatureStatus {
  return auditReportLedgerSignatureStatus(researchRunExportReportSignatureMetadata(signature));
}

function researchRunExportReportSignatureImportBlockReason(
  signature: Record<string, unknown> | undefined,
  reportLabel: string
): string {
  const status = researchRunExportReportSignatureStatus(signature);
  if (status === "invalid" || status === "revoked") {
    return `${reportLabel} signature is revoked or invalid and cannot be trusted for import.`;
  }
  if (
    (status === "signed" || status === "verified") &&
    !researchRunExportReportSignatureHasRequiredFields(signature, status)
  ) {
    return `${reportLabel} signature metadata is incomplete and cannot be trusted for import.`;
  }
  return "";
}

function researchRunExportAuditReportImportPolicyBlockReason(
  auditReport: ResearchRunExportBrowserPackage["auditReport"] | undefined
): string {
  const invalidImportVerificationCount = auditReport?.evidenceSummary?.importVerification?.invalid ?? 0;
  if (Number.isFinite(invalidImportVerificationCount) && invalidImportVerificationCount > 0) {
    return "Audit report carries invalid imported evidence and cannot be trusted for import.";
  }
  return "";
}

function researchRunExportReportSignatureHasRequiredFields(
  signature: Record<string, unknown> | undefined,
  status: "signed" | "verified"
): boolean {
  const metadata = researchRunExportReportSignatureMetadata(signature);
  const requiredFields = ["algorithm", "chainId", "eventId", "keyId", "signedAt", "signer", "value"];
  if (status === "verified") {
    requiredFields.push("verifiedAt");
  }
  return requiredFields.every((field) => auditReportLedgerMetadataText(metadata, field).trim() !== "");
}

function researchRunExportReportSignatureDetail(signature: Record<string, unknown> | undefined): string {
  const metadata = researchRunExportReportSignatureMetadata(signature);
  const status = auditReportLedgerSignatureStatus(metadata);
  if (status === "unsigned") {
    return "";
  }
  const detail = auditReportLedgerSignatureDetail(metadata);
  return [auditReportLedgerSignatureLabel(status), detail].filter(Boolean).join(" · ");
}

function researchRunExportReportSignatureImportVerificationDetail(signature: Record<string, unknown> | undefined): string {
  const metadata = researchRunExportReportSignatureMetadata(signature);
  const source = auditReportLedgerMetadataText(metadata, "importVerificationSource");
  const status = auditReportLedgerMetadataText(metadata, "importVerificationStatus");
  if (source !== "local-core" || (status !== "verified" && status !== "invalid")) {
    return "";
  }
  return [`Local core import verification: ${status}`, auditReportLedgerMetadataText(metadata, "importVerificationReason")]
    .filter(Boolean)
    .join(" · ");
}

function researchRunExportReportSignatureArtifactSuffix(signature: Record<string, unknown> | undefined): string {
  const status = researchRunExportReportSignatureStatus(signature);
  return status === "unsigned" ? "" : status;
}

export function buildResearchRunExportIndexRows(
  exportPackages: ResearchRunExportBrowserPackage[]
): ResearchRunExportIndexRow[] {
  return [...exportPackages]
    .sort((left, right) => timestampSortValue(right.exportedAt) - timestampSortValue(left.exportedAt))
    .map((exportPackage) => {
      const { artifactCounts } = exportPackage.manifest;
      const paperPackageCount = exportPackage.paperExecutions?.length ?? 0;
      const adapterPaperExecutionPackageCount = exportPackage.adapterPaperExecutions?.length ?? 0;
      const portfolioPaperOrderPackageCount = exportPackage.portfolioPaperOrderBatches?.length ?? 0;
      const portfolioPaperOrderApprovalPackageCount = exportPackage.portfolioPaperOrderApprovals?.length ?? 0;
      const portfolioPaperOrderSimulationPackageCount = exportPackage.portfolioPaperOrderSimulations?.length ?? 0;
      const aiReviewPackageCount = exportPackage.aiReviewRuns?.length ?? 0;
      const auditEventPackageCount = exportPackage.auditEvents?.length ?? 0;
      const handoffNotePackageCount = exportPackage.handoffNotes?.length ?? 0;
      const promotionPackageCount = exportPackage.promotionCandidate ? 1 : 0;
      const passedGateCount = exportPackage.executionHandoff.requiredGates.filter((gate) => gate.passed).length;
      const totalGateCount = exportPackage.executionHandoff.requiredGates.length;
      const integrityHash = exportPackage.integrity?.hash ?? "";
      const preparationEvidence = exportPackage.researchRun?.dataSnapshot?.preparationEvidence ?? null;
      const preparationEvidenceArtifact = preparationEvidence ? `prep ${preparationEvidence.runId}` : null;
      const paperPreparationEvidenceRunIds = collectPaperExecutionPreparationEvidenceRunIds(exportPackage.paperExecutions);
      const paperPreparationEvidenceArtifact = paperPreparationEvidenceRunIds.length
        ? `paper prep ${paperPreparationEvidenceRunIds.join(", ")}`
        : null;
      const marketCalendar = exportPackage.researchRun?.dataSnapshot?.marketCalendar ?? null;
      const marketCalendarArtifact = marketCalendar ? `calendar ${marketCalendar.status}/${marketCalendar.session}` : null;
      const auditReport = exportPackage.auditReport;
      const auditReportHash = auditReport?.contentSha256.hash ?? "";
      const auditReportIsReady =
        auditReport?.kind === "aiqt.auditReport" &&
        auditReport.schemaVersion === 1 &&
        auditReport.runId === exportPackage.manifest.runId &&
        auditReport.evidenceSummary?.runId === exportPackage.manifest.runId &&
        auditReport.format === "text/markdown" &&
        auditReport.contentSha256.algorithm === "sha256" &&
        /^[a-f0-9]{64}$/iu.test(auditReportHash) &&
        auditReport.contentMarkdown.trim() !== "";
      const backtestReport = exportPackage.backtestReport;
      const backtestReportHash = backtestReport?.contentSha256.hash ?? "";
      const backtestReportIsReady =
        backtestReport?.kind === "aiqt.backtestReport" &&
        backtestReport.schemaVersion === 1 &&
        backtestReport.runId === exportPackage.manifest.runId &&
        backtestReport.market === exportPackage.manifest.market &&
        backtestReport.symbol === exportPackage.manifest.symbol &&
        backtestReport.timeframe === exportPackage.manifest.timeframe &&
        backtestReport.strategyRevision === exportPackage.manifest.strategyRevision &&
        backtestReport.format === "text/markdown" &&
        backtestReport.contentSha256.algorithm === "sha256" &&
        /^[a-f0-9]{64}$/iu.test(backtestReportHash) &&
        backtestReport.contentMarkdown.trim() !== "";
      const reportArtifactLabels = [
        auditReport
          ? `auditReport ${
              auditReportIsReady
                ? [auditReportHash.slice(0, 8), researchRunExportReportSignatureArtifactSuffix(auditReport.signature)]
                    .filter(Boolean)
                    .join(" ")
                : "blocked"
            }`
          : null,
        backtestReport
          ? `backtestReport ${
              backtestReportIsReady
                ? [
                    backtestReportHash.slice(0, 8),
                    researchRunExportReportSignatureArtifactSuffix(backtestReport.signature)
                  ]
                    .filter(Boolean)
                    .join(" ")
                : "blocked"
            }`
          : null
      ].filter((label): label is string => Boolean(label));
      const reportSignatureDetails = [
        auditReportIsReady ? researchRunExportReportSignatureDetail(auditReport?.signature) : "",
        backtestReportIsReady ? researchRunExportReportSignatureDetail(backtestReport?.signature) : ""
      ].filter(Boolean);
      const integrityIsReady =
        exportPackage.integrity?.algorithm === "sha256" && /^[a-f0-9]{64}$/iu.test(integrityHash);
      const dataIsReady =
        artifactCounts.bars === exportPackage.manifest.dataRows &&
        artifactCounts.bars > 0 &&
        exportPackage.manifest.dataHash.trim() !== "";
      const paperCountMatches = (artifactCounts.paperExecutions ?? 0) === paperPackageCount;
      const adapterPaperExecutionCountMatches =
        (artifactCounts.adapterPaperExecutions ?? 0) === adapterPaperExecutionPackageCount;
      const portfolioPaperOrderCountMatches =
        (artifactCounts.portfolioPaperOrderBatches ?? 0) === portfolioPaperOrderPackageCount &&
        (artifactCounts.portfolioPaperOrderApprovals ?? 0) === portfolioPaperOrderApprovalPackageCount &&
        (artifactCounts.portfolioPaperOrderSimulations ?? 0) === portfolioPaperOrderSimulationPackageCount;
      const promotionCountMatches = (artifactCounts.promotionCandidates ?? 0) === promotionPackageCount;
      const aiReviewCountMatches = (artifactCounts.aiReviewRuns ?? 0) === aiReviewPackageCount;
      const auditEventCountMatches = (artifactCounts.auditEvents ?? 0) === auditEventPackageCount;
      const handoffNoteCountMatches = (artifactCounts.handoffNotes ?? 0) === handoffNotePackageCount;
      const mismatchReasons = [
        integrityIsReady ? null : "Integrity missing",
        dataIsReady ? null : "Data snapshot mismatch",
        paperCountMatches ? null : "Paper execution count mismatch",
        adapterPaperExecutionCountMatches ? null : "Adapter paper execution count mismatch",
        portfolioPaperOrderCountMatches ? null : "Portfolio paper order count mismatch",
        promotionCountMatches ? null : "Promotion candidate count mismatch",
        aiReviewCountMatches ? null : "AI review count mismatch",
        auditEventCountMatches ? null : "Audit event count mismatch",
        handoffNoteCountMatches ? null : "Handoff note count mismatch",
        auditReport && !auditReportIsReady ? "Audit report mismatch" : null,
        backtestReport && !backtestReportIsReady ? "Backtest report mismatch" : null
      ].filter((reason): reason is string => Boolean(reason));
      const status: ResearchRunExportIndexStatus = mismatchReasons.length
        ? "blocked"
        : exportPackage.executionHandoff.liveTradingAllowed
          ? "ready"
          : "review";

      return {
        id: exportPackage.manifest.runId,
        runId: exportPackage.manifest.runId,
        context: `${exportPackage.manifest.symbol} · ${exportPackage.manifest.timeframe}`,
        strategyRevision: exportPackage.manifest.strategyRevision,
        exportedAt: exportPackage.exportedAt,
        status,
        integrity: exportPackage.integrity
          ? `${exportPackage.integrity.algorithm} · ${integrityHash.slice(0, 8)}`
          : "No hash",
        dataHash: exportPackage.manifest.dataHash || "missing hash",
        artifacts: [
          `${artifactCounts.bars} bars`,
          `${artifactCounts.trades} trades`,
          marketCalendarArtifact,
          preparationEvidenceArtifact,
          paperPreparationEvidenceArtifact,
          (artifactCounts.adapterPaperExecutions ?? 0) > 0
            ? `${artifactCounts.adapterPaperExecutions ?? 0} adapter paper executions`
            : null,
          `${artifactCounts.portfolioPaperOrderBatches ?? 0} portfolio batches`,
          `${artifactCounts.portfolioPaperOrderApprovals ?? 0} approvals`,
          `${artifactCounts.portfolioPaperOrderSimulations ?? 0} fills`,
          `${artifactCounts.aiReviewRuns ?? 0} AI`,
          (artifactCounts.auditEvents ?? 0) > 0 ? `${artifactCounts.auditEvents ?? 0} audit events` : null,
          (artifactCounts.handoffNotes ?? 0) > 0 ? `${artifactCounts.handoffNotes ?? 0} handoff notes` : null,
          reportArtifactLabels.length ? `${reportArtifactLabels.length} reports` : null,
          ...reportArtifactLabels
        ]
          .filter((artifact): artifact is string => Boolean(artifact))
          .join(" / "),
        execution: `${passedGateCount}/${totalGateCount} gates · ${exportPackage.executionHandoff.mode}`,
        detail: mismatchReasons.length
          ? mismatchReasons.join("; ")
          : exportPackage.executionHandoff.liveTradingAllowed
            ? ["Package is consistent and live handoff is open.", ...reportSignatureDetails].join(" · ")
            : ["Package is consistent; paper-only handoff requires review.", ...reportSignatureDetails].join(" · "),
        exportPath: `manifest:${exportPackage.manifest.runId}`,
        tone: status === "ready" ? "positive" : status === "review" ? "warning" : "risk"
      };
    });
}

export function filterResearchRunExportIndexRows(
  rows: ResearchRunExportIndexRow[],
  query: string
): ResearchRunExportIndexRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }
  return rows.filter((row) =>
    [
      row.id,
      row.runId,
      row.context,
      row.strategyRevision,
      row.exportedAt,
      row.status,
      row.integrity,
      row.dataHash,
      row.artifacts,
      row.execution,
      row.detail,
      row.exportPath,
      row.tone
    ]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

function researchRunImportArtifactCountMismatches(
  exportPackage: ResearchRunExportBrowserPackage,
  actualCounts: {
    aiReviewRuns: number;
    adapterPaperExecutions: number;
    paperExecutions: number;
    portfolioPaperOrderApprovals: number;
    portfolioPaperOrderBatches: number;
    portfolioPaperOrderSimulations: number;
    promotionCandidates: number;
    researchNotes: number;
    auditEvents: number;
    handoffNotes: number;
  }
): string[] {
  const { artifactCounts } = exportPackage.manifest;
  const pairs: Array<[string, number, number]> = [
    ["bars", artifactCounts.bars, exportPackage.manifest.dataRows],
    ["researchNotes", artifactCounts.researchNotes ?? 0, actualCounts.researchNotes],
    ["paperExecutions", artifactCounts.paperExecutions ?? 0, actualCounts.paperExecutions],
    ["adapterPaperExecutions", artifactCounts.adapterPaperExecutions ?? 0, actualCounts.adapterPaperExecutions],
    [
      "portfolioPaperOrderBatches",
      artifactCounts.portfolioPaperOrderBatches ?? 0,
      actualCounts.portfolioPaperOrderBatches
    ],
    [
      "portfolioPaperOrderApprovals",
      artifactCounts.portfolioPaperOrderApprovals ?? 0,
      actualCounts.portfolioPaperOrderApprovals
    ],
    [
      "portfolioPaperOrderSimulations",
      artifactCounts.portfolioPaperOrderSimulations ?? 0,
      actualCounts.portfolioPaperOrderSimulations
    ],
    ["promotionCandidates", artifactCounts.promotionCandidates ?? 0, actualCounts.promotionCandidates],
    ["aiReviewRuns", artifactCounts.aiReviewRuns ?? 0, actualCounts.aiReviewRuns],
    ["auditEvents", artifactCounts.auditEvents ?? 0, actualCounts.auditEvents],
    ["handoffNotes", artifactCounts.handoffNotes ?? 0, actualCounts.handoffNotes]
  ];

  return pairs
    .filter(([, manifestCount, packageCount]) => manifestCount !== packageCount)
    .map(([label, manifestCount, packageCount]) => `${label} ${manifestCount}/${packageCount}`);
}

export function buildResearchRunImportDiffRows({
  aiReviewRecords = [],
  exportPackage,
  paperExecution = null,
  workspace
}: {
  workspace: TerminalWorkspace;
  exportPackage: ResearchRunExportBrowserPackage | null | undefined;
  aiReviewRecords?: ResearchRunExportPreviewAiReviewEnvelope[];
  paperExecution?: PaperExecutionSnapshot | null;
}): ResearchRunImportDiffRow[] {
  if (!exportPackage) {
    return [
      {
        id: "run-id",
        label: "Research run",
        status: "blocked",
        current: workspace.researchRun?.runId ?? "No audited run",
        incoming: "No package selected",
        detail: "Inspect or choose a research run export package before importing.",
        exportPath: "researchRun",
        tone: "risk"
      }
    ];
  }

  const currentRun = workspace.researchRun ?? null;
  const incomingRun = exportPackage.researchRun ?? null;
  const currentNote = normalizedResearchNote(currentRun?.researchNote);
  const incomingNote = normalizedResearchNote(incomingRun?.researchNote);
  const currentPreparationEvidence = currentRun?.dataSnapshot?.preparationEvidence ?? null;
  const incomingPreparationEvidence = incomingRun?.dataSnapshot?.preparationEvidence ?? null;
  const currentMarketCalendar = currentRun?.dataSnapshot?.marketCalendar ?? null;
  const incomingMarketCalendar = incomingRun?.dataSnapshot?.marketCalendar ?? null;
  const currentMarketCalendarDetail = currentMarketCalendar
    ? formatMarketCalendarEvidenceDetail(currentMarketCalendar)
    : "No market calendar evidence";
  const incomingMarketCalendarDetail = incomingMarketCalendar
    ? formatMarketCalendarEvidenceDetail(incomingMarketCalendar)
    : "No package market calendar evidence";
  const marketCalendarStatus: ResearchRunImportDiffStatus =
    currentMarketCalendar && incomingMarketCalendar
      ? currentMarketCalendarDetail === incomingMarketCalendarDetail
        ? "same"
        : "change"
      : incomingMarketCalendar
        ? "add"
        : currentMarketCalendar
          ? "change"
          : "same";
  const currentPreparationEvidenceDetail = currentPreparationEvidence
    ? formatPreparationEvidenceDetail(currentPreparationEvidence)
    : "No locked preparation evidence";
  const incomingPreparationEvidenceDetail = incomingPreparationEvidence
    ? formatPreparationEvidenceDetail(incomingPreparationEvidence)
    : "No package preparation evidence";
  const preparationEvidenceStatus: ResearchRunImportDiffStatus =
    currentPreparationEvidence && incomingPreparationEvidence
      ? currentPreparationEvidenceDetail === incomingPreparationEvidenceDetail
        ? "same"
        : "change"
      : incomingPreparationEvidence
        ? "add"
        : currentPreparationEvidence
          ? "change"
          : "same";
  const integrityHash = exportPackage.integrity?.hash ?? "";
  const integrityIsReady =
    exportPackage.integrity?.algorithm === "sha256" && /^[a-f0-9]{64}$/iu.test(integrityHash);
  const packageAiReviewCount = exportPackage.aiReviewRuns?.length ?? 0;
  const manifestAiReviewCount = exportPackage.manifest.artifactCounts.aiReviewRuns ?? 0;
  const packageAuditEventCount = exportPackage.auditEvents?.length ?? 0;
  const packageHandoffNoteCount = exportPackage.handoffNotes?.length ?? 0;
  const currentAiReviewCount = currentRun
    ? aiReviewRecords.filter((record) => record.runId === currentRun.runId).length
    : 0;
  const packagePaperCount = exportPackage.paperExecutions?.length ?? 0;
  const packagePaperPreparationEvidenceRunIds = collectPaperExecutionPreparationEvidenceRunIds(exportPackage.paperExecutions);
  const packageAdapterPaperExecutionCount = exportPackage.adapterPaperExecutions?.length ?? 0;
  const packageAdapterPaperExecutionDetail = formatAdapterPaperExecutionEvidenceDetail(
    exportPackage.adapterPaperExecutions
  );
  const packagePortfolioPaperOrderCount = exportPackage.portfolioPaperOrderBatches?.length ?? 0;
  const packagePortfolioPaperOrderApprovalCount = exportPackage.portfolioPaperOrderApprovals?.length ?? 0;
  const packagePortfolioPaperOrderSimulationCount = exportPackage.portfolioPaperOrderSimulations?.length ?? 0;
  const packagePortfolioPaperOrderHasLedger =
    packagePortfolioPaperOrderCount + packagePortfolioPaperOrderApprovalCount + packagePortfolioPaperOrderSimulationCount >
    0;
  const packagePortfolioPaperOrderSimulationAdapterEvidenceDetail =
    formatPortfolioPaperOrderSimulationAdapterEvidenceDetail(exportPackage.portfolioPaperOrderSimulations);
  const currentPaperCount = currentRun && paperExecution?.runId === currentRun.runId ? 1 : 0;
  const auditSummary = exportPackage.auditEvidenceSummary;
  const auditSummaryMatchesPackage = auditSummary?.runId === exportPackage.manifest.runId;
  const auditReport = exportPackage.auditReport;
  const auditReportHash = auditReport?.contentSha256.hash ?? "";
  const auditReportMatchesPackage =
    auditReport?.runId === exportPackage.manifest.runId &&
    auditReport.evidenceSummary?.runId === exportPackage.manifest.runId &&
    auditReport.contentSha256.algorithm === "sha256" &&
    /^[a-f0-9]{64}$/iu.test(auditReportHash) &&
    auditReport.contentMarkdown.trim() !== "";
  const auditReportSignatureDetail = researchRunExportReportSignatureDetail(auditReport?.signature);
  const auditReportSignatureImportVerificationDetail = researchRunExportReportSignatureImportVerificationDetail(
    auditReport?.signature
  );
  const auditReportSignatureStatus = researchRunExportReportSignatureStatus(auditReport?.signature);
  const auditReportSignatureImportBlockReason = researchRunExportReportSignatureImportBlockReason(
    auditReport?.signature,
    "Audit report"
  );
  const auditReportImportPolicyBlockReason = researchRunExportAuditReportImportPolicyBlockReason(auditReport);
  const auditReportImportBlockReason = auditReportSignatureImportBlockReason || auditReportImportPolicyBlockReason;
  const auditReportSignatureIsImportable = auditReportImportBlockReason === "";
  const auditReportSignatureLabel = auditReportSignatureDetail
    ? auditReportLedgerSignatureLabel(auditReportSignatureStatus)
    : "";
  const backtestReport = exportPackage.backtestReport;
  const backtestReportHash = backtestReport?.contentSha256.hash ?? "";
  const backtestReportMatchesPackage =
    backtestReport?.runId === exportPackage.manifest.runId &&
    backtestReport.market === exportPackage.manifest.market &&
    backtestReport.symbol === exportPackage.manifest.symbol &&
    backtestReport.timeframe === exportPackage.manifest.timeframe &&
    backtestReport.strategyRevision === exportPackage.manifest.strategyRevision &&
    backtestReport.contentSha256.algorithm === "sha256" &&
    /^[a-f0-9]{64}$/iu.test(backtestReportHash) &&
    backtestReport.contentMarkdown.trim() !== "";
  const backtestReportSignatureDetail = researchRunExportReportSignatureDetail(backtestReport?.signature);
  const backtestReportSignatureImportVerificationDetail = researchRunExportReportSignatureImportVerificationDetail(
    backtestReport?.signature
  );
  const backtestReportSignatureStatus = researchRunExportReportSignatureStatus(backtestReport?.signature);
  const backtestReportSignatureImportBlockReason = researchRunExportReportSignatureImportBlockReason(
    backtestReport?.signature,
    "Backtest report"
  );
  const backtestReportSignatureIsImportable = backtestReportSignatureImportBlockReason === "";
  const backtestReportSignatureLabel = backtestReportSignatureDetail
    ? auditReportLedgerSignatureLabel(backtestReportSignatureStatus)
    : "";
  const artifactCountMismatches = researchRunImportArtifactCountMismatches(exportPackage, {
    aiReviewRuns: packageAiReviewCount,
    adapterPaperExecutions: packageAdapterPaperExecutionCount,
    paperExecutions: packagePaperCount,
    portfolioPaperOrderApprovals: packagePortfolioPaperOrderApprovalCount,
    portfolioPaperOrderBatches: packagePortfolioPaperOrderCount,
    portfolioPaperOrderSimulations: packagePortfolioPaperOrderSimulationCount,
    promotionCandidates: exportPackage.promotionCandidate ? 1 : 0,
    researchNotes: incomingNote ? 1 : 0,
    auditEvents: packageAuditEventCount,
    handoffNotes: packageHandoffNoteCount
  });

  return [
    {
      id: "package-integrity",
      label: "Package integrity",
      status: integrityIsReady ? "same" : "blocked",
      current: "Local verification required",
      incoming: exportPackage.integrity
        ? `${exportPackage.integrity.algorithm} · ${integrityIsReady ? integrityHash.slice(0, 8) : "invalid"}`
        : "No integrity hash",
      detail: integrityIsReady
        ? "Canonical SHA-256 metadata is present before import."
        : "Import must stop until the package has valid canonical SHA-256 metadata.",
      exportPath: "integrity.hash",
      tone: integrityIsReady ? "positive" : "risk"
    },
    {
      id: "artifact-counts",
      label: "Artifact counts",
      status: artifactCountMismatches.length ? "blocked" : "same",
      current: "Manifest versus package payload",
      incoming: artifactCountMismatches.length ? `${artifactCountMismatches.length} mismatch` : "Counts match",
      detail: artifactCountMismatches.length
        ? artifactCountMismatches.join(" · ")
        : "Manifest artifact counts match the package payloads that will be restored.",
      exportPath: "manifest.artifactCounts",
      tone: artifactCountMismatches.length ? "risk" : "positive"
    },
    {
      id: "run-id",
      label: "Research run",
      status: currentRun ? (currentRun.runId === exportPackage.manifest.runId ? "same" : "replace") : "add",
      current: currentRun?.runId ?? "No audited run",
      incoming: exportPackage.manifest.runId,
      detail: currentRun
        ? currentRun.runId === exportPackage.manifest.runId
          ? "Import will refresh the existing audited run payload."
          : "Import will replace the current replay context with the package run."
        : "Import will add an audited run to the local workspace.",
      exportPath: "researchRun.runId",
      tone: currentRun?.runId === exportPackage.manifest.runId ? "positive" : "warning"
    },
    {
      id: "context",
      label: "Market / symbol",
      status:
        workspace.selectedInstrument.market === exportPackage.manifest.market &&
        workspace.selectedInstrument.symbol === exportPackage.manifest.symbol
          ? "same"
          : "change",
      current: `${workspace.selectedInstrument.market} · ${workspace.selectedInstrument.symbol}`,
      incoming: `${exportPackage.manifest.market} · ${exportPackage.manifest.symbol}`,
      detail: "Import will bind the terminal to the package market and symbol.",
      exportPath: "manifest.market",
      tone:
        workspace.selectedInstrument.market === exportPackage.manifest.market &&
        workspace.selectedInstrument.symbol === exportPackage.manifest.symbol
          ? "positive"
          : "warning"
    },
    {
      id: "timeframe",
      label: "Timeframe",
      status: workspace.selectedTimeframe === exportPackage.manifest.timeframe ? "same" : "change",
      current: workspace.selectedTimeframe,
      incoming: exportPackage.manifest.timeframe,
      detail:
        workspace.selectedTimeframe === exportPackage.manifest.timeframe
          ? "Current research context already matches the package timeframe."
          : "Current research context will switch to the package timeframe.",
      exportPath: "manifest.timeframe",
      tone: workspace.selectedTimeframe === exportPackage.manifest.timeframe ? "positive" : "warning"
    },
    {
      id: "data-snapshot",
      label: "Data snapshot",
      status:
        currentRun?.dataSnapshot?.hash && currentRun.dataSnapshot.hash === exportPackage.manifest.dataHash
          ? "same"
          : currentRun?.dataSnapshot
            ? "change"
            : "add",
      current: currentRun?.dataSnapshot
        ? `${currentRun.dataSnapshot.rows} rows · ${currentRun.dataSnapshot.hash || "missing hash"}`
        : "No data snapshot",
      incoming: `${exportPackage.manifest.dataRows} rows · ${exportPackage.manifest.dataHash || "missing hash"}`,
      detail: "Import will replay the package data hash and row count as the audited snapshot.",
      exportPath: "researchRun.dataSnapshot",
      tone:
        currentRun?.dataSnapshot?.hash && currentRun.dataSnapshot.hash === exportPackage.manifest.dataHash
          ? "positive"
          : "warning"
    },
    {
      id: "market-calendar",
      label: "Market calendar",
      status: marketCalendarStatus,
      current: currentMarketCalendarDetail,
      incoming: incomingMarketCalendarDetail,
      detail: incomingMarketCalendar
        ? marketCalendarStatus === "same"
          ? "Market calendar evidence already matches the package snapshot."
          : currentMarketCalendar
            ? "Import will replace market calendar evidence used to review the audited snapshot."
            : "Import will add market calendar evidence for the audited snapshot."
        : currentMarketCalendar
          ? "Package does not include market calendar evidence; import will replace the current replay context without it."
          : "Neither current workspace nor package includes market calendar evidence.",
      exportPath: "researchRun.dataSnapshot.marketCalendar",
      tone: marketCalendarStatus === "same" ? (incomingMarketCalendar ? "positive" : "neutral") : "warning"
    },
    {
      id: "preparation-evidence",
      label: "Preparation evidence",
      status: preparationEvidenceStatus,
      current: currentPreparationEvidenceDetail,
      incoming: incomingPreparationEvidenceDetail,
      detail: incomingPreparationEvidence
        ? preparationEvidenceStatus === "same"
          ? "Locked data preparation evidence already matches the package snapshot."
          : currentPreparationEvidence
            ? "Import will replace locked data preparation evidence used to build the audited snapshot."
            : "Import will add locked data preparation evidence for the audited snapshot."
        : currentPreparationEvidence
          ? "Package does not include locked preparation evidence; import will replace the current replay context without it."
          : "Neither current workspace nor package includes locked preparation evidence.",
      exportPath: "researchRun.dataSnapshot.preparationEvidence",
      tone: preparationEvidenceStatus === "same" ? (incomingPreparationEvidence ? "positive" : "neutral") : "warning"
    },
    {
      id: "strategy-revision",
      label: "Strategy revision",
      status:
        currentRun?.strategyRevision && currentRun.strategyRevision === exportPackage.manifest.strategyRevision
          ? "same"
          : currentRun?.strategyRevision
            ? "change"
            : "add",
      current: currentRun?.strategyRevision ?? "No audited strategy",
      incoming: exportPackage.manifest.strategyRevision,
      detail: "Import will restore the package strategy revision as an audited Strategy Lab version.",
      exportPath: "researchRun.strategyConfig.revision",
      tone:
        currentRun?.strategyRevision && currentRun.strategyRevision === exportPackage.manifest.strategyRevision
          ? "positive"
          : "warning"
    },
    {
      id: "research-note",
      label: "Research note",
      status: incomingNote
        ? currentNote?.body === incomingNote.body
          ? "same"
          : currentNote
            ? "change"
            : "add"
        : "same",
      current: currentNote ? compactResearchNoteDetail(currentNote.body) : "No local note",
      incoming: incomingNote ? compactResearchNoteDetail(incomingNote.body) : "No package note",
      detail: incomingNote
        ? "Import will write the package research note back to the local note store."
        : "Package does not include a locked research note.",
      exportPath: "researchRun.researchNote",
      tone: incomingNote && currentNote?.body !== incomingNote.body ? "warning" : "neutral"
    },
    {
      id: "handoff-notes",
      label: "Handoff notes",
      status: packageHandoffNoteCount > 0 ? "add" : "same",
      current: "Local handoff store",
      incoming: `${packageHandoffNoteCount} saved / ${exportPackage.manifest.artifactCounts.handoffNotes ?? 0} manifest`,
      detail:
        packageHandoffNoteCount > 0
          ? "Import will restore local team handoff notes attached to the package run."
          : "Package does not include local team handoff notes.",
      exportPath: "handoffNotes[]",
      tone: packageHandoffNoteCount > 0 ? "warning" : "neutral"
    },
    {
      id: "paper-executions",
      label: "Paper executions",
      status: packagePaperCount > currentPaperCount ? "add" : packagePaperCount === currentPaperCount ? "same" : "change",
      current: `${currentPaperCount} saved`,
      incoming: `${packagePaperCount} saved / ${exportPackage.manifest.artifactCounts.paperExecutions ?? 0} manifest`,
      detail: [
        "Import will restore paper execution records attached to the package run",
        ...(packagePaperPreparationEvidenceRunIds.length
          ? [`prep ${packagePaperPreparationEvidenceRunIds.join(", ")}`]
          : [])
      ].join(" · "),
      exportPath: "paperExecutions[]",
      tone: packagePaperCount > 0 ? "warning" : "neutral"
    },
    {
      id: "adapter-paper-executions",
      label: "Adapter paper executions",
      status: packageAdapterPaperExecutionCount > 0 ? "add" : "same",
      current: "0 saved",
      incoming: `${packageAdapterPaperExecutionCount} saved / ${
        exportPackage.manifest.artifactCounts.adapterPaperExecutions ?? 0
      } manifest`,
      detail:
        packageAdapterPaperExecutionCount > 0
          ? `Import will preserve adapter paper execution evidence: ${packageAdapterPaperExecutionDetail}`
          : "Package does not include adapter paper execution evidence.",
      exportPath: "adapterPaperExecutions[]",
      tone: packageAdapterPaperExecutionCount > 0 ? "warning" : "neutral"
    },
    {
      id: "portfolio-paper-orders",
      label: "Portfolio paper orders",
      status: packagePortfolioPaperOrderHasLedger ? "add" : "same",
      current: "Not loaded in current preview",
      incoming: `${packagePortfolioPaperOrderCount} batches / ${packagePortfolioPaperOrderApprovalCount} approvals / ${packagePortfolioPaperOrderSimulationCount} fills`,
      detail: [
        "Import will restore Portfolio paper order ledger bound to the package run.",
        packagePortfolioPaperOrderSimulationAdapterEvidenceDetail
      ]
        .filter(Boolean)
        .join(" "),
      exportPath: "portfolioPaperOrderBatches[] portfolioPaperOrderApprovals[] portfolioPaperOrderSimulations[]",
      tone: packagePortfolioPaperOrderHasLedger ? "warning" : "neutral"
    },
    {
      id: "ai-review-runs",
      label: "AI review runs",
      status: packageAiReviewCount > currentAiReviewCount ? "add" : packageAiReviewCount === currentAiReviewCount ? "same" : "change",
      current: `${currentAiReviewCount} saved`,
      incoming: `${packageAiReviewCount} saved / ${manifestAiReviewCount} manifest`,
      detail: "Import will restore saved AI review records and their evidence anchors.",
      exportPath: "aiReviewRuns[]",
      tone: packageAiReviewCount > 0 ? "ai" : "neutral"
    },
    ...(auditSummary
      ? ([
          {
            id: "audit-summary",
            label: "Audit evidence summary",
            status: auditSummaryMatchesPackage ? "add" : "blocked",
            current: "No local package summary",
            incoming: `${auditSummary.runId} · ${auditSummary.focusQuery || auditSummary.packageQuery || "no focus"}`,
            detail: auditSummaryMatchesPackage
              ? `Audit focus carries ${auditSummary.package.matched}/${auditSummary.package.total} package matches and ${auditSummary.importDiff.blocked} import diff blockers.`
              : "Audit evidence summary run id does not match the import package manifest.",
            exportPath: "auditEvidenceSummary",
            tone: auditSummaryMatchesPackage ? "ai" : "risk"
          }
        ] satisfies ResearchRunImportDiffRow[])
      : []),
    ...(auditReport
      ? ([
          {
            id: "audit-report",
            label: "Audit report",
            status: auditReportMatchesPackage && auditReportSignatureIsImportable ? "add" : "blocked",
            current: "No local audit report",
            incoming: [
              `${auditReport.runId} · ${auditReport.contentSha256.algorithm} ${auditReportHash.slice(0, 8)} · ${
                auditReport.fileName
              }`,
              auditReportSignatureLabel
            ]
              .filter(Boolean)
              .join(" · "),
            detail: auditReportMatchesPackage
              ? [
                   auditReportSignatureIsImportable
                     ? "Package includes a portable Audit Markdown report bound to this manifest."
                     : auditReportImportBlockReason,
                   auditReportSignatureDetail,
                   auditReportSignatureImportVerificationDetail
                 ]
                  .filter(Boolean)
                  .join(" · ")
              : "Audit report artifact does not match the import package manifest or content hash.",
            exportPath: "auditReport.contentSha256.hash",
            tone: auditReportMatchesPackage && auditReportSignatureIsImportable ? "ai" : "risk"
          }
        ] satisfies ResearchRunImportDiffRow[])
      : []),
    ...(backtestReport
      ? ([
          {
            id: "backtest-report",
            label: "Backtest report",
            status: backtestReportMatchesPackage && backtestReportSignatureIsImportable ? "add" : "blocked",
            current: "No local backtest report",
            incoming: [
              `${backtestReport.runId} · ${backtestReport.contentSha256.algorithm} ${backtestReportHash.slice(
                0,
                8
              )} · ${backtestReport.runComparisonRows} comparisons`,
              backtestReportSignatureLabel
            ]
              .filter(Boolean)
              .join(" · "),
            detail: backtestReportMatchesPackage
              ? [
                   backtestReportSignatureIsImportable
                     ? "Package includes a portable Backtest Markdown report bound to this manifest."
                     : backtestReportSignatureImportBlockReason,
                   backtestReportSignatureDetail,
                   backtestReportSignatureImportVerificationDetail
                 ]
                  .filter(Boolean)
                  .join(" · ")
              : "Backtest report artifact does not match the import package manifest or content hash.",
            exportPath: "backtestReport.contentSha256.hash",
            tone: backtestReportMatchesPackage && backtestReportSignatureIsImportable ? "ai" : "risk"
          }
        ] satisfies ResearchRunImportDiffRow[])
      : []),
    {
      id: "live-boundary",
      label: "Live boundary",
      status: exportPackage.manifest.liveTradingAllowed || exportPackage.executionHandoff.liveTradingAllowed ? "blocked" : "same",
      current: workspace.execution.liveEnabled ? "Local live enabled" : "Local paper boundary",
      incoming:
        exportPackage.manifest.liveTradingAllowed || exportPackage.executionHandoff.liveTradingAllowed
          ? "Package claims live handoff"
          : "Package remains paper-only",
      detail:
        exportPackage.manifest.liveTradingAllowed || exportPackage.executionHandoff.liveTradingAllowed
          ? "Local import must reject packages that claim live trading permission."
          : "Import keeps the package inside the paper-only execution boundary.",
      exportPath: "executionHandoff.liveTradingAllowed",
      tone: exportPackage.manifest.liveTradingAllowed || exportPackage.executionHandoff.liveTradingAllowed ? "risk" : "positive"
    }
  ];
}

export function filterResearchRunImportDiffRows(
  rows: ResearchRunImportDiffRow[],
  query: string
): ResearchRunImportDiffRow[] {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) {
    return rows;
  }
  return rows.filter((row) =>
    [row.id, row.label, row.status, row.current, row.incoming, row.detail, row.exportPath, row.tone]
      .join(" ")
      .toLowerCase()
      .includes(normalizedQuery)
  );
}

export function buildAuditEvidenceSummary({
  auditQuery,
  deepLinkError,
  deepLinkRunId,
  deepLinkStatus = "none",
  importDiffQuery,
  importDiffRows,
  importAuditEvents = [],
  packageQuery,
  packageRows
}: {
  auditQuery: string;
  deepLinkError?: string | null;
  deepLinkRunId?: string | null;
  deepLinkStatus?: AuditEvidenceDeepLinkStatus;
  importDiffQuery: string;
  importDiffRows: ResearchRunImportDiffRow[];
  importAuditEvents?: ResearchRunImportAuditEvent[];
  packageQuery: string;
  packageRows: ResearchRunExportBrowserRow[];
}): AuditEvidenceSummary {
  const normalizedAuditQuery = auditQuery.trim();
  const normalizedPackageQuery = packageQuery.trim();
  const normalizedImportDiffQuery = importDiffQuery.trim();
  const packageMatchedRows = filterResearchRunExportBrowserRows(packageRows, normalizedPackageQuery);
  const importDiffMatchedRows = filterResearchRunImportDiffRows(importDiffRows, normalizedImportDiffQuery);
  const packageMatchedCount = packageMatchedRows.length;
  const importDiffMatchedCount = importDiffMatchedRows.length;
  const packageReadyCount = packageRows.filter((row) => row.status === "ready").length;
  const packageMissingCount = packageRows.filter((row) => row.status === "missing").length;
  const packageBlockedCount = packageRows.filter((row) => row.status === "blocked").length;
  const importDiffAddCount = importDiffRows.filter((row) => row.status === "add").length;
  const importDiffChangeCount = importDiffRows.filter((row) => row.status === "change" || row.status === "replace").length;
  const importDiffBlockedCount = importDiffRows.filter((row) => row.status === "blocked").length;
  const importAuditAggregation = buildResearchRunImportAuditAggregation(importAuditEvents);
  const importPolicyBlockerBuckets = importAuditAggregation.blockedEvidenceBuckets.map((bucket) => ({
    category: bucket.category,
    count: bucket.count,
    label: bucket.label,
    latestDetail: bucket.latestDetail,
    latestExportPath: bucket.latestExportPath,
    latestFileName: bucket.latestFileName,
    latestRunId: bucket.latestRunId,
    tone: bucket.tone
  }));
  const importPolicyBlockedCount = importPolicyBlockerBuckets.reduce((total, bucket) => total + bucket.count, 0);
  const importVerificationBuckets = importAuditAggregation.verifiedReportSignatureBuckets.map((bucket) => ({
    count: bucket.count,
    latestExportPath: bucket.latestExportPath,
    latestReason: bucket.latestReason,
    source: bucket.source,
    status: bucket.status
  }));
  const importVerificationVerifiedCount =
    importVerificationBuckets.find((bucket) => bucket.status === "verified")?.count ?? 0;
  const importVerificationInvalidCount =
    importVerificationBuckets.find((bucket) => bucket.status === "invalid")?.count ?? 0;
  const latestImportVerification = importVerificationBuckets[0]
    ? `latest ${importVerificationBuckets[0].status} ${importVerificationBuckets[0].latestExportPath} · ${importVerificationBuckets[0].latestReason}`
    : "none";
  const latestImportPolicyBlocker = importPolicyBlockerBuckets[0]
    ? `latest ${importPolicyBlockerBuckets[0].label} ${importPolicyBlockerBuckets[0].latestExportPath} · ${importPolicyBlockerBuckets[0].latestDetail}`
    : "none";
  const runId =
    deepLinkRunId?.trim() ||
    packageRows.find((row) => row.exportPath.startsWith("manifest:"))?.value ||
    normalizedPackageQuery ||
    "unknown";
  const focusQuery = normalizedPackageQuery || normalizedImportDiffQuery || normalizedAuditQuery || runId;
  const matchedEvidenceFocus: AuditEvidenceMatchedEvidenceFocus[] = [
    ...packageMatchedRows.map((row) => ({
      area: "Export package" as const,
      detail: row.detail,
      exportPath: row.exportPath,
      label: row.label
    })),
    ...importDiffMatchedRows.map((row) => ({
      area: "Import diff" as const,
      detail: row.detail,
      exportPath: row.exportPath,
      label: row.label
    }))
  ];
  const matchedPackageEvidenceLine = packageMatchedRows.length
    ? `Matched package evidence: ${packageMatchedRows
        .map((row) => `${row.label} -> ${row.detail}`)
        .join(" | ")}`
    : null;
  const matchedImportEvidenceLine = importDiffMatchedRows.length
    ? `Matched import evidence: ${importDiffMatchedRows
        .map((row) => `${row.label} -> ${row.detail}`)
        .join(" | ")}`
    : null;
  const copyLines = [
    "AIQT Audit Evidence Summary",
    `Run: ${runId}`,
    `Audit query: ${normalizedAuditQuery || "none"}`,
    `Package focus: ${normalizedPackageQuery || "none"}`,
    `Import diff focus: ${normalizedImportDiffQuery || "none"}`,
    `Deep link: ${deepLinkStatus}${deepLinkError ? ` (${deepLinkError})` : ""}`,
    `Package checks: ${packageReadyCount} ready / ${packageMissingCount} missing / ${packageBlockedCount} blocked / ${packageMatchedCount} of ${packageRows.length} matched`,
    `Import diff: ${importDiffChangeCount} changes / ${importDiffAddCount} adds / ${importDiffBlockedCount} blocked / ${importDiffMatchedCount} of ${importDiffRows.length} matched`,
    matchedPackageEvidenceLine,
    matchedImportEvidenceLine,
    `Import policy blockers: ${importPolicyBlockedCount} blocked / ${latestImportPolicyBlocker}`,
    `Import report verification: ${importVerificationVerifiedCount} verified / ${importVerificationInvalidCount} invalid / ${latestImportVerification}`
  ].filter((line): line is string => Boolean(line));
  return {
    auditQuery: normalizedAuditQuery,
    copyText: copyLines.join("\n"),
    deepLinkError: deepLinkError ?? null,
    deepLinkStatus,
    focusQuery,
    importDiffAddCount,
    importDiffBlockedCount,
    importDiffChangeCount,
    importDiffMatchedCount,
    importDiffQuery: normalizedImportDiffQuery,
    importDiffTotalCount: importDiffRows.length,
    importPolicyBlockedCount,
    importPolicyBlockerBuckets,
    importVerificationBuckets,
    importVerificationInvalidCount,
    importVerificationVerifiedCount,
    matchedEvidenceFocus,
    packageBlockedCount,
    packageMatchedCount,
    packageMissingCount,
    packageQuery: normalizedPackageQuery,
    packageReadyCount,
    packageTotalCount: packageRows.length,
    runId
  };
}

export function buildAuditEvidenceReportMarkdown(
  summary: AuditEvidenceSummary,
  { generatedAt = new Date().toISOString() }: { generatedAt?: string } = {}
): string {
  const importVerificationBuckets = summary.importVerificationBuckets ?? [];
  const importPolicyBlockerBuckets = summary.importPolicyBlockerBuckets ?? [];
  const matchedEvidenceFocus = summary.matchedEvidenceFocus ?? [];
  const deepLinkDetail = summary.deepLinkError
    ? `${summary.deepLinkStatus} (${summary.deepLinkError})`
    : summary.deepLinkStatus;
  const evidenceRows = [
    [
      "Package checks",
      `${summary.packageReadyCount} ready`,
      `${summary.packageMissingCount} missing`,
      `${summary.packageBlockedCount} blocked`,
      `${summary.packageMatchedCount} / ${summary.packageTotalCount}`
    ],
    [
      "Import diff",
      `${summary.importDiffChangeCount} changes`,
      `${summary.importDiffAddCount} adds`,
      `${summary.importDiffBlockedCount} blocked`,
      `${summary.importDiffMatchedCount} / ${summary.importDiffTotalCount}`
    ]
  ];
  const importVerificationSection = importVerificationBuckets.length
    ? [
        "",
        "## Import Report Verification",
        "",
        markdownTable(
          ["Status", "Count", "Source", "Latest exportPath", "Latest reason"],
          importVerificationBuckets.map((bucket) => [
            bucket.status,
            String(bucket.count),
            bucket.source,
            bucket.latestExportPath,
            bucket.latestReason
          ])
        )
      ]
    : [];
  const importPolicyBlockerSection = importPolicyBlockerBuckets.length
    ? [
        "",
        "## Import Policy Blockers",
        "",
        markdownTable(
          ["Category", "Count", "Latest run", "Latest exportPath", "Latest detail"],
          importPolicyBlockerBuckets.map((bucket) => [
            bucket.label,
            String(bucket.count),
            bucket.latestRunId,
            bucket.latestExportPath,
            bucket.latestDetail
          ])
        )
      ]
    : [];
  const matchedEvidenceFocusSection = matchedEvidenceFocus.length
    ? [
        "",
        "### Matched Evidence",
        "",
        markdownTable(
          ["Area", "Label", "Detail"],
          matchedEvidenceFocus.map((item) => [item.area, item.label, item.detail])
        )
      ]
    : [];

  return [
    "# AIQuant Audit Evidence Report",
    "",
    `Generated at: \`${generatedAt}\``,
    `Run ID: \`${summary.runId}\``,
    `Deep link status: \`${deepLinkDetail}\``,
    "",
    "## Evidence Focus",
    "",
    markdownTable(
      ["Area", "Query"],
      [
        ["Audit ledger", summary.auditQuery || "none"],
        ["Export package", summary.packageQuery || "none"],
        ["Import diff", summary.importDiffQuery || "none"],
        ["Current focus", summary.focusQuery || "none"]
      ]
    ),
    ...matchedEvidenceFocusSection,
    "",
    "## Evidence Counts",
    "",
    markdownTable(["Area", "Ready / changes", "Missing / adds", "Blocked", "Matched"], evidenceRows),
    ...importPolicyBlockerSection,
    ...importVerificationSection,
    "",
    "## Portable Summary",
    "",
    "```text",
    summary.copyText,
    "```",
    "",
    "## Boundary",
    "",
    "This audit report fragment records reproducibility evidence and import impact context only. It does not provide buy/sell instructions, guaranteed returns, or live execution approval."
  ]
    .filter((line, index, lines) => line !== "" || lines[index - 1] !== "")
    .join("\n")
    .trimEnd()
    .concat("\n");
}

export function buildResearchRunImportAuditEvent({
  createdAt = new Date().toISOString(),
  error,
  exportPackage,
  fileName,
  previousRunId = null,
  rows,
  stage,
  undoToken = null
}: {
  exportPackage: Pick<ResearchRunExportBrowserPackage, "manifest"> | null | undefined;
  fileName: string;
  previousRunId?: string | null;
  rows: ResearchRunImportDiffRow[];
  stage: "preview" | "confirmed" | "failed" | "cancelled";
  createdAt?: string;
  error?: string | null;
  undoToken?: string | null;
}): ResearchRunImportAuditEvent {
  const runId = exportPackage?.manifest.runId ?? "unknown";
  const blockedCount = rows.filter((row) => row.status === "blocked").length;
  const blockedRows = researchRunImportAuditBlockedRows(rows);
  const artifactRows = researchRunImportAuditArtifactRows(rows);
  const verifiedReportSignatures = researchRunImportVerifiedReportSignatures(rows);
  const changeCount = rows.filter(
    (row) => row.status === "add" || row.status === "change" || row.status === "replace"
  ).length;
  const resolvedStage: ResearchRunImportAuditEventStage =
    stage === "preview" && blockedCount > 0 ? "blocked" : stage;
  const summary = researchRunImportAuditSummary(resolvedStage);
  const failure = researchRunImportFailure(error);
  const detail = researchRunImportAuditDetail({
    blockedCount,
    changeCount,
    error: failure.detail ?? error,
    fileName,
    stage: resolvedStage
  });
  const normalizedPreviousRunId = previousRunId?.trim() || null;
  const rollbackTargetRunId = resolvedStage === "confirmed" ? normalizedPreviousRunId : null;
  const normalizedUndoToken = resolvedStage === "confirmed" ? undoToken?.trim() || null : null;

  return {
    id: `import:${runId}:${resolvedStage}:${createdAt}:${fileName || "unknown"}`,
    stage: resolvedStage,
    runId,
    previousRunId: normalizedPreviousRunId,
    rollbackTargetRunId,
    undoToken: normalizedUndoToken,
    fileName: fileName || "unknown",
    createdAt,
    summary,
    detail,
    failureCategory: resolvedStage === "failed" ? failure.category : null,
    recoveryHint: researchRunImportRecoveryHint(resolvedStage, rollbackTargetRunId, failure, normalizedUndoToken),
    blockedCount,
    blockedRows,
    artifactRows,
    changeCount,
    exportPath: exportPackage ? `manifest:${runId}` : `import:file:${fileName || "unknown"}`,
    tone: researchRunImportAuditTone(resolvedStage),
    verifiedReportSignatures
  };
}

function researchRunImportAuditBlockedRows(rows: ResearchRunImportDiffRow[]): ResearchRunImportAuditBlockedRow[] {
  return rows
    .filter((row) => row.status === "blocked")
    .map((row) => ({
      id: row.id,
      label: row.label,
      detail: row.detail,
      exportPath: row.exportPath,
      incoming: row.incoming
    }));
}

function researchRunImportVerifiedReportSignatures(
  rows: ResearchRunImportDiffRow[]
): ResearchRunImportVerifiedReportSignature[] {
  return rows
    .map((row) => {
      if (row.id !== "audit-report" && row.id !== "backtest-report") {
        return null;
      }
      const match = row.detail.match(/Local core import verification: (verified|invalid)(?: · ([^·]+))?/u);
      if (!match) {
        return null;
      }
      const status = match[1] as ResearchRunImportVerifiedReportSignature["status"];
      const reason = match[2]?.trim() || status;
      return {
        id: row.id,
        label: row.label,
        detail: `Local core import verification: ${status} · ${reason}`,
        exportPath: row.exportPath,
        incoming: row.incoming,
        reason,
        source: "local-core" as const,
        status
      };
    })
    .filter((row): row is ResearchRunImportVerifiedReportSignature => Boolean(row));
}

export function buildResearchRunImportUndoAuditEvent({
  createdAt = new Date().toISOString(),
  event
}: {
  createdAt?: string;
  event: ResearchRunImportAuditEvent;
}): ResearchRunImportAuditEvent {
  const consumedUndoToken = event.undoToken?.trim() || "unknown";
  return {
    ...event,
    createdAt,
    stage: "undone",
    summary: researchRunImportAuditSummary("undone"),
    detail: researchRunImportAuditDetail({
      blockedCount: event.blockedCount,
      changeCount: event.changeCount,
      fileName: event.fileName,
      stage: "undone"
    }),
    undoToken: null,
    recoveryHint: researchRunImportRecoveryHint("undone", event.rollbackTargetRunId, {
      category: "unknown",
      detail: null
    }, consumedUndoToken),
    tone: researchRunImportAuditTone("undone"),
    artifactRows: [],
    verifiedReportSignatures: []
  };
}

export function buildResearchRunImportUndoFailureAuditEvent({
  createdAt = new Date().toISOString(),
  error,
  event
}: {
  createdAt?: string;
  error?: string | null;
  event: ResearchRunImportAuditEvent;
}): ResearchRunImportAuditEvent {
  const failure = researchRunImportFailure(error);
  return {
    ...event,
    id: `${event.id}:undo-failed:${createdAt}`,
    createdAt,
    stage: "undo-failed",
    summary: researchRunImportAuditSummary("undo-failed"),
    detail: researchRunImportAuditDetail({
      blockedCount: event.blockedCount,
      changeCount: event.changeCount,
      error: failure.detail ?? error,
      fileName: event.fileName,
      stage: "undo-failed"
    }),
    failureCategory: failure.category,
    recoveryHint: researchRunImportRecoveryHint("undo-failed", event.rollbackTargetRunId, failure, event.undoToken),
    tone: researchRunImportAuditTone("undo-failed"),
    artifactRows: [],
    verifiedReportSignatures: []
  };
}

export function buildResearchRunImportUndoConfirmation(
  event: ResearchRunImportAuditEvent
): ResearchRunImportUndoConfirmation | null {
  const undoToken = event.undoToken?.trim();
  if (event.stage !== "confirmed" || !undoToken) {
    return null;
  }
  const artifactSummary = researchRunImportUndoArtifactSummary(event.artifactRows);
  return {
    undoToken,
    runId: event.runId,
    fileName: event.fileName,
    message: "Confirm import undo",
    detail: artifactSummary
      ? `Undo import ${undoToken} will restore previous audited stores, ${artifactSummary}, and cannot be repeated.`
      : `Undo import ${undoToken} will restore previous audited stores and cannot be repeated.`
  };
}

function researchRunImportUndoArtifactSummary(rows: ResearchRunImportAuditArtifactRow[]): string {
  if (!rows.length) {
    return "";
  }
  const artifactLabels = rows.map((row) => {
    if (row.id === "adapter-paper-executions" || row.id === "portfolio-paper-orders") {
      return `${row.label}: ${row.detail}`;
    }
    return row.label;
  });
  return `remove ${rows.length} imported artifact row${rows.length === 1 ? "" : "s"} (${artifactLabels.join("; ")})`;
}

export function mergeResearchRunImportAuditEvents(
  events: ResearchRunImportAuditEvent[],
  event: ResearchRunImportAuditEvent,
  limit = 12
): ResearchRunImportAuditEvent[] {
  return [event, ...events.filter((item) => item.id !== event.id)].slice(0, limit);
}

export function buildResearchRunImportAuditAggregation(
  events: ResearchRunImportAuditEvent[]
): ResearchRunImportAuditAggregation {
  const stageCounts: Record<ResearchRunImportAuditEventStage, number> = {
    blocked: 0,
    cancelled: 0,
    confirmed: 0,
    failed: 0,
    preview: 0,
    undone: 0,
    "undo-failed": 0
  };
  const failureBuckets = new Map<ResearchRunImportAuditFailureBucketCategory, ResearchRunImportAuditFailureBucket>();
  const blockedEvidenceBuckets = new Map<
    ResearchRunImportBlockedEvidenceBucketCategory,
    ResearchRunImportBlockedEvidenceBucket
  >();
  const verifiedReportSignatureBuckets = new Map<
    ResearchRunImportVerifiedReportSignatureBucket["status"],
    ResearchRunImportVerifiedReportSignatureBucket
  >();
  let needsReview = 0;
  let recoverable = 0;
  let undoable = 0;

  events.forEach((event) => {
    stageCounts[event.stage] += 1;
    if (isResearchRunImportAuditEventUndoable(event)) {
      undoable += 1;
    }
    if (isResearchRunImportAuditEventRecoverable(event)) {
      recoverable += 1;
    }
    event.verifiedReportSignatures.forEach((row) => {
      const existingSignatureBucket = verifiedReportSignatureBuckets.get(row.status);
      if (existingSignatureBucket) {
        existingSignatureBucket.count += 1;
        if (!existingSignatureBucket.rowIds.includes(row.id)) {
          existingSignatureBucket.rowIds.push(row.id);
        }
        if (event.createdAt >= existingSignatureBucket.latestCreatedAt) {
          existingSignatureBucket.latestCreatedAt = event.createdAt;
          existingSignatureBucket.latestDetail = row.detail;
          existingSignatureBucket.latestExportPath = row.exportPath;
          existingSignatureBucket.latestFileName = event.fileName;
          existingSignatureBucket.latestReason = row.reason;
          existingSignatureBucket.latestRunId = event.runId;
        }
        return;
      }
      verifiedReportSignatureBuckets.set(row.status, {
        status: row.status,
        count: 1,
        label: researchRunImportVerifiedReportSignatureBucketLabel(row.status),
        latestCreatedAt: event.createdAt,
        latestDetail: row.detail,
        latestExportPath: row.exportPath,
        latestFileName: event.fileName,
        latestReason: row.reason,
        latestRunId: event.runId,
        rowIds: [row.id],
        source: row.source,
        tone: researchRunImportVerifiedReportSignatureBucketTone(row.status)
      });
    });
    if (!isResearchRunImportAuditEventNeedsReview(event)) {
      return;
    }
    needsReview += 1;
    const category: ResearchRunImportAuditFailureBucketCategory =
      event.stage === "blocked" ? "blocked" : event.failureCategory ?? "unknown";
    const existing = failureBuckets.get(category);
    if (existing) {
      existing.count += 1;
      existing.stageCounts[event.stage] = (existing.stageCounts[event.stage] ?? 0) + 1;
      if (event.createdAt > existing.latestCreatedAt) {
        existing.latestCreatedAt = event.createdAt;
        existing.latestFileName = event.fileName;
        existing.latestRunId = event.runId;
        existing.recoveryHint = event.recoveryHint;
      }
      return;
    }
    failureBuckets.set(category, {
      category,
      count: 1,
      label: researchRunImportFailureBucketLabel(category),
      latestCreatedAt: event.createdAt,
      latestFileName: event.fileName,
      latestRunId: event.runId,
      recoveryHint: event.recoveryHint,
      stageCounts: {
        [event.stage]: 1
      },
      tone: "risk"
    });
    event.blockedRows.forEach((row) => {
      const blockedCategory = researchRunImportBlockedEvidenceBucketCategory(row);
      const existingBlockedBucket = blockedEvidenceBuckets.get(blockedCategory);
      if (existingBlockedBucket) {
        existingBlockedBucket.count += 1;
        if (!existingBlockedBucket.rowIds.includes(row.id)) {
          existingBlockedBucket.rowIds.push(row.id);
        }
        if (event.createdAt >= existingBlockedBucket.latestCreatedAt) {
          existingBlockedBucket.latestCreatedAt = event.createdAt;
          existingBlockedBucket.latestDetail = row.detail;
          existingBlockedBucket.latestExportPath = row.exportPath;
          existingBlockedBucket.latestFileName = event.fileName;
          existingBlockedBucket.latestRunId = event.runId;
        }
        return;
      }
      blockedEvidenceBuckets.set(blockedCategory, {
        category: blockedCategory,
        count: 1,
        label: researchRunImportBlockedEvidenceBucketLabel(blockedCategory),
        latestCreatedAt: event.createdAt,
        latestDetail: row.detail,
        latestExportPath: row.exportPath,
        latestFileName: event.fileName,
        latestRunId: event.runId,
        rowIds: [row.id],
        tone: researchRunImportBlockedEvidenceBucketTone(blockedCategory)
      });
    });
  });

  return {
    total: events.length,
    preview: stageCounts.preview,
    blocked: stageCounts.blocked,
    confirmed: stageCounts.confirmed,
    failed: stageCounts.failed,
    cancelled: stageCounts.cancelled,
    undone: stageCounts.undone,
    undoFailed: stageCounts["undo-failed"],
    needsReview,
    undoable,
    recoverable,
    failureBuckets: researchRunImportFailureBucketOrder
      .map((category) => failureBuckets.get(category))
      .filter((bucket): bucket is ResearchRunImportAuditFailureBucket => Boolean(bucket)),
    blockedEvidenceBuckets: researchRunImportBlockedEvidenceBucketOrder
      .map((category) => blockedEvidenceBuckets.get(category))
      .filter((bucket): bucket is ResearchRunImportBlockedEvidenceBucket => Boolean(bucket)),
    verifiedReportSignatureBuckets: researchRunImportVerifiedReportSignatureBucketOrder
      .map((status) => verifiedReportSignatureBuckets.get(status))
      .filter((bucket): bucket is ResearchRunImportVerifiedReportSignatureBucket => Boolean(bucket))
  };
}

export function filterResearchRunImportAuditEvents(
  events: ResearchRunImportAuditEvent[],
  query: string,
  filter: ResearchRunImportAuditFilter = "all"
): ResearchRunImportAuditEvent[] {
  const normalizedQuery = query.trim().toLowerCase();
  return events.filter((event) => {
    if (!researchRunImportAuditEventMatchesFilter(event, filter)) {
      return false;
    }
    if (!normalizedQuery) {
      return true;
    }
    const searchableText = [
      event.id,
      event.stage,
      event.runId,
      event.fileName,
      event.createdAt,
      event.summary,
      event.detail,
      event.previousRunId ?? "",
      event.rollbackTargetRunId ?? "",
      event.rollbackTargetRunId && event.stage !== "undone" ? "rollback" : "",
      event.undoToken ?? "",
      event.undoToken ? "undo" : "",
      isResearchRunImportAuditEventUndoable(event) ? "undoable" : "",
      isResearchRunImportAuditEventNeedsReview(event) ? "needs review" : "",
      isResearchRunImportAuditEventRecoverable(event) ? "recoverable recovery" : "",
      event.stage === "undone" ? "undo consumed" : "",
      event.stage === "undo-failed" ? "undo failed retry recovery" : "",
      event.failureCategory ?? "",
      event.recoveryHint,
      String(event.blockedCount),
      event.blockedRows
        .map((row) => [row.id, row.label, row.incoming, row.detail, row.exportPath].join(" "))
        .join(" "),
      event.artifactRows
        .map((row) => [row.id, row.label, row.status, row.incoming, row.detail, row.exportPath].join(" "))
        .join(" "),
      event.verifiedReportSignatures
        .map((row) => [row.id, row.label, row.incoming, row.detail, row.exportPath, row.source, row.status, row.reason].join(" "))
        .join(" "),
      String(event.changeCount),
      event.exportPath,
      event.tone
    ]
      .join(" ")
      .toLowerCase();
    if (searchableText.includes(normalizedQuery)) {
      return true;
    }
    const normalizedSearchableText = normalizeResearchRunImportAuditSearchText(searchableText);
    const normalizedSearchQuery = normalizeResearchRunImportAuditSearchText(normalizedQuery);
    return Boolean(
      normalizedSearchQuery &&
        normalizedSearchQuery
          .split(" ")
          .filter(Boolean)
          .every((token) => normalizedSearchableText.includes(token))
    );
  });
}

const researchRunImportAuditArtifactRowIds = new Set<ResearchRunImportDiffRow["id"]>([
  "market-calendar",
  "preparation-evidence",
  "paper-executions",
  "adapter-paper-executions",
  "portfolio-paper-orders",
  "ai-review-runs",
  "audit-summary",
  "audit-report",
  "backtest-report"
]);

function researchRunImportAuditArtifactRows(rows: ResearchRunImportDiffRow[]): ResearchRunImportAuditArtifactRow[] {
  return rows.flatMap((row) => {
    if (!researchRunImportAuditArtifactRowIds.has(row.id) || row.status === "blocked" || row.status === "same") {
      return [];
    }
    return [{
      id: row.id,
      label: row.label,
      status: row.status,
      detail: row.detail,
      exportPath: row.exportPath,
      incoming: row.incoming
    }];
  });
}

function normalizeResearchRunImportAuditSearchText(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9_\-\u4e00-\u9fff]+/giu, " ")
    .replace(/\s+/gu, " ")
    .trim();
}

const auditReportLedgerProductWorkAreaIds: readonly ProductWorkAreaId[] = [
  "market",
  "research",
  "strategy",
  "backtest",
  "ai-review",
  "portfolio",
  "execution",
  "audit",
  "settings"
];

function auditReportLedgerProductWorkAreaId(value: string): ProductWorkAreaId | null {
  return auditReportLedgerProductWorkAreaIds.includes(value as ProductWorkAreaId) ? (value as ProductWorkAreaId) : null;
}

function auditReportLedgerEvidenceTargetWorkspaceId(search: string): ProductWorkAreaId | null {
  if (!search.trim()) {
    return null;
  }
  const workspaceMatch = search.match(/(?:^|[?&])workspace=([^&]+)/u);
  const workspaceId = workspaceMatch ? decodeURIComponent(workspaceMatch[1].replace(/\+/gu, " ")) : "";
  return auditReportLedgerProductWorkAreaId(workspaceId);
}

function auditReportLedgerDecodedSearchText(value: string): string {
  try {
    return decodeURIComponent(value.replace(/\+/gu, " "));
  } catch {
    return value;
  }
}

function auditReportLedgerUrlSearch(value: string): string {
  const trimmedValue = value.trim();
  if (!trimmedValue) {
    return "";
  }
  try {
    const url = new URL(trimmedValue);
    return url.searchParams.toString();
  } catch {
    const queryText = trimmedValue.includes("?") ? trimmedValue.slice(trimmedValue.indexOf("?") + 1) : trimmedValue;
    const cleanQueryText = queryText.split("#", 1)[0].replace(/^\?/u, "");
    return new URLSearchParams(cleanQueryText).toString();
  }
}

function auditReportLedgerResearchContextLabel({
  fallbackMarket,
  fallbackSymbol,
  fallbackTimeframe,
  search
}: {
  fallbackMarket: string;
  fallbackSymbol: string;
  fallbackTimeframe: string;
  search: string;
}): string {
  const urlState = resolveResearchContextUrlState(search);
  const market = urlState?.market ?? fallbackMarket;
  const symbol = urlState?.symbol ?? fallbackSymbol;
  const timeframe = urlState?.timeframe ?? fallbackTimeframe;
  return market && symbol && timeframe ? `Research context · ${market} ${symbol} ${timeframe}` : "";
}

function auditReportLedgerEvidenceLinkLabel(
  workspaceId: ProductWorkAreaId | null,
  status: string
): string {
  if (!workspaceId) {
    return "";
  }
  const workspaceLabel =
    workspaceId === "audit"
      ? "Audit evidence"
      : workspaceId === "execution"
        ? "Execution evidence"
        : `${workspaceId} evidence`;
  return status ? `${workspaceLabel} · ${status}` : workspaceLabel;
}

