function auditReportLedgerRowSearchTokenSet(row: AuditEvidenceReportLedgerRow): Set<string> {
  return auditReportSearchTokenSet([row.id, row.runId, row.fileName, row.focusQuery, row.searchText, row.detail]);
}

export type P2ManifestChainPreflightAuditEventReferenceSource = "none" | "response" | "ledger";

export interface P2ManifestChainPreflightAuditEventReference {
  eventId: string;
  ledgerRow: AuditEvidenceReportLedgerRow | null;
  source: P2ManifestChainPreflightAuditEventReferenceSource;
}

type P2ManifestChainPreflightAuditContext = {
  blockerIds?: unknown[] | null;
  nextAction?: unknown;
  sourcePath?: unknown;
  status?: unknown;
  totalStageCount?: unknown;
  validStageCount?: unknown;
};

type P2ManifestChainPreflightAuditEventLike = {
  detail?: unknown;
  eventId?: unknown;
  metadata?: Record<string, unknown> | null;
  runId?: unknown;
  summary?: unknown;
};

export function resolveP2ManifestChainPreflightAuditEventReference({
  context = {},
  event,
  ledgerRow
}: {
  context?: P2ManifestChainPreflightAuditContext;
  event?: P2ManifestChainPreflightAuditEventLike | null;
  ledgerRow?: AuditEvidenceReportLedgerRow | null;
}): P2ManifestChainPreflightAuditEventReference {
  const responseEventId = auditReportSearchValueText(event?.eventId).trim();
  if (responseEventId && event && p2ManifestChainPreflightAuditEventMatchesContext(event, context)) {
    return {
      eventId: responseEventId,
      ledgerRow: null,
      source: "response"
    };
  }
  if (ledgerRow?.id) {
    return {
      eventId: ledgerRow.id,
      ledgerRow,
      source: "ledger"
    };
  }
  return {
    eventId: "",
    ledgerRow: null,
    source: "none"
  };
}

function p2ManifestChainPreflightAuditEventMatchesContext(
  event: P2ManifestChainPreflightAuditEventLike,
  context: P2ManifestChainPreflightAuditContext
): boolean {
  const contextTokenGroups = p2ManifestChainPreflightAuditContextTokenGroups(context);
  if (!contextTokenGroups.length) {
    return true;
  }
  return auditReportSearchTokenGroupsMatch(auditReportEventSearchTokenSet(event), contextTokenGroups);
}

function p2ManifestChainPreflightAuditContextTokenGroups(
  context: P2ManifestChainPreflightAuditContext
): string[][] {
  const stageCount =
    auditReportSearchValueText(context.validStageCount).trim() && auditReportSearchValueText(context.totalStageCount).trim()
      ? `${auditReportSearchValueText(context.validStageCount).trim()}/${auditReportSearchValueText(context.totalStageCount).trim()}`
      : "";
  return auditReportSearchTokenGroups([
    context.status,
    stageCount,
    context.nextAction,
    context.sourcePath,
    ...(Array.isArray(context.blockerIds) ? context.blockerIds : [])
  ]);
}

export type P2ReadinessEvidenceCoverageReviewAuditEventReferenceSource = "none" | "response" | "ledger";

export interface P2ReadinessEvidenceCoverageReviewAuditEventReference {
  eventId: string;
  ledgerRow: AuditEvidenceReportLedgerRow | null;
  source: P2ReadinessEvidenceCoverageReviewAuditEventReferenceSource;
}

type P2ReadinessEvidenceCoverageReviewAuditEventLike = {
  detail?: unknown;
  eventId?: unknown;
  metadata?: Record<string, unknown> | null;
  runId?: unknown;
  summary?: unknown;
};

export function resolveP2ReadinessEvidenceCoverageReviewAuditEventReference({
  coverage,
  event,
  ledgerRow
}: {
  coverage?: P2ReadinessEvidenceCoverage | null;
  event?: P2ReadinessEvidenceCoverageReviewAuditEventLike | null;
  ledgerRow?: AuditEvidenceReportLedgerRow | null;
}): P2ReadinessEvidenceCoverageReviewAuditEventReference {
  const responseEventId = auditReportSearchValueText(event?.eventId).trim();
  if (responseEventId && event && p2ReadinessEvidenceCoverageReviewAuditEventMatchesContext(event, coverage)) {
    return {
      eventId: responseEventId,
      ledgerRow: null,
      source: "response"
    };
  }
  if (ledgerRow?.id) {
    return {
      eventId: ledgerRow.id,
      ledgerRow,
      source: "ledger"
    };
  }
  return {
    eventId: "",
    ledgerRow: null,
    source: "none"
  };
}

function p2ReadinessEvidenceCoverageReviewAuditEventMatchesContext(
  event: P2ReadinessEvidenceCoverageReviewAuditEventLike,
  coverage: P2ReadinessEvidenceCoverage | null | undefined
): boolean {
  const contextTokenGroups = p2ReadinessEvidenceCoverageReviewContextTokenGroups(coverage);
  if (!contextTokenGroups.length) {
    return true;
  }
  return auditReportSearchTokenGroupsMatch(auditReportEventSearchTokenSet(event), contextTokenGroups);
}

function p2ReadinessEvidenceCoverageReviewContextTokenGroups(
  coverage: P2ReadinessEvidenceCoverage | null | undefined
): string[][] {
  if (!coverage) {
    return [];
  }
  return auditReportSearchTokenGroups([
    coverage.status,
    `${coverage.coveredCount}/${coverage.totalCount}`,
    ...coverage.rows.map((row) => row.id),
    ...coverage.rows.map((row) => row.status),
    ...coverage.rows.map((row) => row.sourceType),
    ...coverage.rows.map((row) => row.sourceId ?? "")
  ]);
}

export type P2ReadinessAcceptanceAuditEventReferenceSource = "none" | "response" | "ledger";

export interface P2ReadinessAcceptanceAuditEventReference {
  eventId: string;
  ledgerRow: AuditEvidenceReportLedgerRow | null;
  source: P2ReadinessAcceptanceAuditEventReferenceSource;
}

type P2ReadinessAcceptanceAuditContext = {
  evidenceCoverageReviewAuditEventId?: string | null;
  market?: string | null;
  runId?: string | null;
  symbol?: string | null;
  timeframe?: string | null;
};

type P2ReadinessAcceptanceAuditEventLike = {
  detail?: unknown;
  eventId?: unknown;
  metadata?: Record<string, unknown> | null;
  runId?: unknown;
  summary?: unknown;
};

export function resolveP2ReadinessAcceptanceAuditEventReference({
  context = {},
  event,
  ledgerRow
}: {
  context?: P2ReadinessAcceptanceAuditContext;
  event?: P2ReadinessAcceptanceAuditEventLike | null;
  ledgerRow?: AuditEvidenceReportLedgerRow | null;
}): P2ReadinessAcceptanceAuditEventReference {
  const responseEventId = auditReportSearchValueText(event?.eventId).trim();
  if (responseEventId && event && p2ReadinessAcceptanceAuditEventMatchesContext(event, context)) {
    return {
      eventId: responseEventId,
      ledgerRow: null,
      source: "response"
    };
  }
  if (ledgerRow?.id) {
    return {
      eventId: ledgerRow.id,
      ledgerRow,
      source: "ledger"
    };
  }
  return {
    eventId: "",
    ledgerRow: null,
    source: "none"
  };
}

function p2ReadinessAcceptanceAuditEventMatchesContext(
  event: P2ReadinessAcceptanceAuditEventLike,
  context: P2ReadinessAcceptanceAuditContext
): boolean {
  const terms = [context.market, context.symbol, context.timeframe]
    .map((term) => term?.trim().toLowerCase() ?? "")
    .filter(Boolean);
  const runId = context.runId?.trim().toLowerCase() ?? "";
  const evidenceCoverageReviewAuditEventId = context.evidenceCoverageReviewAuditEventId?.trim().toLowerCase() ?? "";
  if (!runId && terms.length === 0 && !evidenceCoverageReviewAuditEventId) {
    return true;
  }
  const tokens = auditReportEventSearchTokenSet(event);
  const eventRunId = auditReportSearchValueText(event.runId).trim().toLowerCase();
  const metadataRunId =
    event.metadata && Object.prototype.hasOwnProperty.call(event.metadata, "runId")
      ? auditReportSearchValueText(event.metadata.runId).trim().toLowerCase()
      : "";
  if (runId && eventRunId !== runId && metadataRunId !== runId && !tokens.has(runId)) {
    return false;
  }
  if (evidenceCoverageReviewAuditEventId && !tokens.has(evidenceCoverageReviewAuditEventId)) {
    return false;
  }
  return terms.every((term) => tokens.has(term));
}

function auditReportEventSearchTokenSet(event: P2ReadinessAcceptanceAuditEventLike): Set<string> {
  return auditReportSearchTokenSet([
    event.eventId ?? "",
    event.runId ?? "",
    event.summary ?? "",
    event.detail ?? "",
    ...auditReportEventMetadataSearchValues(event.metadata)
  ]);
}

function auditReportSearchTokenSet(values: unknown[]): Set<string> {
  return new Set(
    values.flatMap((value) =>
      value === null || value === undefined ? [] : auditReportSearchTokens(auditReportSearchValueText(value))
    )
  );
}

function auditReportSearchTokenGroups(values: unknown[]): string[][] {
  return values
    .map((value) => (value === null || value === undefined ? [] : auditReportSearchTokens(auditReportSearchValueText(value))))
    .filter((tokens) => tokens.length > 0);
}

function auditReportSearchTokenGroupsMatch(tokens: Set<string>, groups: string[][]): boolean {
  return groups.every((group) => group.every((token) => tokens.has(token)));
}

function auditReportSearchValueText(value: unknown): string {
  return value === null || value === undefined ? "" : String(value);
}

function auditReportSearchTokens(value: string): string[] {
  return value
    .toLowerCase()
    .split(/[^a-z0-9._-]+/iu)
    .filter(Boolean);
}

function auditReportEventMetadataSearchValues(value: unknown): string[] {
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return [String(value)];
  }
  if (Array.isArray(value)) {
    return value.flatMap((item) => auditReportEventMetadataSearchValues(item));
  }
  if (value && typeof value === "object") {
    return Object.values(value as Record<string, unknown>).flatMap((item) => auditReportEventMetadataSearchValues(item));
  }
  return [];
}

function auditReportLedgerLatestResearchContextReportQuery(row: AuditEvidenceReportLedgerRow | undefined): string {
  return buildAuditEvidenceReportLedgerRowResearchContextReportQuery(row);
}

export type ResearchContextReportCoverageStatus = "matched" | "context-mismatch" | "missing";

export interface ResearchContextReportCoverage {
  latestMatchingReport: AuditEvidenceReportLedgerRow | null;
  latestOtherReport: AuditEvidenceReportLedgerRow | null;
  readyReportCount: number;
  status: ResearchContextReportCoverageStatus;
}

function auditReportLedgerLatestAuditAidBacklogReadinessQuery(row: AuditEvidenceReportLedgerRow | undefined): string {
  const baseQuery = auditReportLedgerLatestAuditAidBaseQuery(row);
  if (!row || !baseQuery) {
    return "";
  }
  return [
    baseQuery,
    "backlog",
    row.p0BacklogReadinessRecorded ? "backlog-recorded" : "backlog-not-recorded",
    `backlog total ${row.p0BacklogTotalCount}`,
    `executable ${row.p0BacklogExecutableCount}`,
    `not-executable ${row.p0BacklogNotExecutableCount}`,
    row.p0FirstBacklogCanExecute ? "first-backlog-executable" : "first-backlog-not-executable",
    row.p0FirstBacklogExecutableActionId,
    row.p0FirstBacklogReadinessReason,
    row.p0BacklogReadinessSummary.trim() ? "backlog-summary-recorded" : "backlog-summary-missing",
    row.p0BacklogReadinessSummary
  ]
    .filter(Boolean)
    .join(" ");
}

function auditReportLedgerLatestAuditAidCompletionQuery(row: AuditEvidenceReportLedgerRow | undefined): string {
  const baseQuery = auditReportLedgerLatestAuditAidBaseQuery(row);
  if (!row || !baseQuery) {
    return "";
  }
  return [
    baseQuery,
    "p0-completion-focus",
    "completion",
    row.p0CompletionReadinessRecorded ? "completion-recorded" : "completion-not-recorded",
    `completion ${row.p0CompletionPassedCount}/${row.p0CompletionTotalCount}`,
    `completion-progress ${row.p0CompletionProgressPct}`,
    `completion-review ${row.p0CompletionReviewCount}`,
    `completion-blocked ${row.p0CompletionBlockedCount}`,
    row.p0CompletionCurrentCriterionId,
    row.p0CompletionCurrentCriterionLabel,
    row.p0CompletionCurrentCriterionStatus,
    row.p0CompletionCurrentCriterionActionLabel,
    row.p0CompletionCurrentCriterionTargetWorkspaceId ?? "",
    row.p0CompletionOpenCriterionIds,
    row.p0CompletionSummary.trim() ? "completion-summary-recorded" : "completion-summary-missing",
    row.p0CompletionSummary
  ]
    .filter(Boolean)
    .join(" ");
}

function auditReportLedgerLatestAuditAidCurrentGapReadinessQuery(
  row: AuditEvidenceReportLedgerRow | undefined
): string {
  const baseQuery = auditReportLedgerLatestAuditAidBaseQuery(row);
  if (!row || !baseQuery) {
    return "";
  }
  const readiness = buildAuditEvidenceReportLedgerRowCurrentGapActionReadiness(row);
  return [
    baseQuery,
    "current-gap",
    readiness.canExecute ? "current-gap-executable" : "current-gap-not-executable",
    readiness.executableActionId,
    readiness.reason,
    readiness.targetWorkspaceId ?? readiness.workspaceId ?? ""
  ]
    .filter(Boolean)
    .join(" ");
}

function auditReportLedgerPreparationEvidenceLabel(runId: string): string {
  return runId ? `prep ${runId}` : "";
}

export function buildAuditEvidenceReportLedgerRowP0ProgressLabel(
  row: AuditEvidenceReportLedgerRow | null | undefined
): string {
  if (!row || row.reportKind !== "p0_readiness_report") {
    return "";
  }
  const progress = row.packageTotal > 0 ? `${row.packageMatched}/${row.packageTotal}` : "";
  const focusSuffix = row.runId ? ` ${row.runId}` : "";
  const focusText = row.focusQuery.endsWith(focusSuffix)
    ? row.focusQuery.slice(0, -focusSuffix.length).trim()
    : row.focusQuery.trim();
  const focus = focusText.replace(/^(\S+)\s+(\d+%)\s+(.+)$/u, "$1 $2 · $3");
  return [progress ? `P0 progress ${progress}` : "P0 progress", focus].filter(Boolean).join(" · ");
}

export function buildMarketDataRefreshOverrideAuditLedgerRows(
  events: AuditEvidenceReportLedgerEventRecord[]
): MarketDataRefreshOverrideAuditLedgerRow[] {
  return events
    .filter((event) => event.eventType === "market_data_refresh_override")
    .map((event) => {
      const market = auditReportLedgerMetadataText(event.metadata, "market") as Market;
      const timeframe = auditReportLedgerMetadataText(event.metadata, "timeframe") as Timeframe;
      const affectedContexts = auditReportLedgerMetadataStringList(event.metadata, "affectedContexts");
      const affectedSymbols = auditReportLedgerMetadataStringList(event.metadata, "affectedSymbols");
      const liveTradingAllowed = auditReportLedgerMetadataBoolean(event.metadata, "liveTradingAllowed");
      const overrideApplied = auditReportLedgerMetadataBoolean(event.metadata, "overrideApplied");
      const providerHealthStatus = auditReportLedgerMetadataText(event.metadata, "providerHealthStatus");
      const providerHealthReason = auditReportLedgerMetadataText(event.metadata, "providerHealthReason");
      const boundary = auditReportLedgerMetadataText(event.metadata, "boundary");
      const statusLabel = overrideApplied ? "Override recorded" : "Override blocked";
      const liveBoundaryLabel = liveTradingAllowed ? "live allowed" : "live blocked";
      const tone: MarketDataRefreshOverrideAuditLedgerRow["tone"] =
        liveTradingAllowed || !overrideApplied
          ? "risk"
          : providerHealthStatus === "ok"
            ? "positive"
            : "warning";

      return {
        id: event.eventId,
        actionScope: auditReportLedgerMetadataText(event.metadata, "actionScope"),
        affectedContexts,
        affectedContextsLabel: affectedContexts.join(", "),
        affectedSymbols,
        affectedSymbolsLabel: affectedSymbols.join(", "),
        boundary,
        createdAt: event.createdAt,
        detail: event.detail,
        liveTradingAllowed,
        market,
        name: auditReportLedgerMetadataText(event.metadata, "name"),
        operator: auditReportLedgerMetadataText(event.metadata, "operator"),
        overrideApplied,
        overrideReason: auditReportLedgerMetadataText(event.metadata, "overrideReason"),
        providerHealthReason,
        providerHealthStatus,
        recentErrorCount: auditReportLedgerMetadataNumber(event.metadata, "recentErrorCount"),
        retryAfterSeconds: auditReportLedgerMetadataNumber(event.metadata, "retryAfterSeconds"),
        searchText: [
          event.eventType,
          event.stage,
          event.source,
          event.summary,
          event.detail,
          market,
          auditReportLedgerMetadataText(event.metadata, "symbol"),
          timeframe,
          auditReportLedgerMetadataText(event.metadata, "name"),
          auditReportLedgerMetadataText(event.metadata, "operator"),
          auditReportLedgerMetadataText(event.metadata, "overrideReason"),
          providerHealthStatus,
          providerHealthReason,
          boundary,
          liveBoundaryLabel,
          affectedContexts.join(" "),
          affectedSymbols.join(" "),
          String(auditReportLedgerMetadataNumber(event.metadata, "retryAfterSeconds")),
          String(auditReportLedgerMetadataNumber(event.metadata, "recentErrorCount"))
        ]
          .filter(Boolean)
          .join(" "),
        source: event.source,
        stage: event.stage,
        statusLabel,
        summary: event.summary,
        symbol: auditReportLedgerMetadataText(event.metadata, "symbol"),
        timeframe,
        tone
      };
    });
}

export function buildMarketDataRefreshOverrideAuditLedgerSummary(
  rows: MarketDataRefreshOverrideAuditLedgerRow[]
): MarketDataRefreshOverrideAuditLedgerSummary {
  const latestRow = rows.reduce<MarketDataRefreshOverrideAuditLedgerRow | undefined>((latest, row) => {
    if (!latest) {
      return row;
    }
    return Date.parse(row.createdAt) > Date.parse(latest.createdAt) ? row : latest;
  }, undefined);

  return {
    blocked: rows.filter((row) => !row.overrideApplied).length,
    latestEventId: latestRow?.id ?? "",
    latestMarket: latestRow?.market ?? "",
    latestReason: latestRow?.overrideReason ?? "",
    latestRetryAfterSeconds: latestRow?.retryAfterSeconds ?? 0,
    latestSymbol: latestRow?.symbol ?? "",
    latestTimeframe: latestRow?.timeframe ?? "",
    liveBlocked: rows.filter((row) => !row.liveTradingAllowed).length,
    recorded: rows.filter((row) => row.overrideApplied).length,
    total: rows.length
  };
}

export function filterMarketDataRefreshOverrideAuditLedgerRows(
  rows: MarketDataRefreshOverrideAuditLedgerRow[],
  query: string
): MarketDataRefreshOverrideAuditLedgerRow[] {
  const queryTokens = query.trim().toLowerCase().split(/\s+/u).filter(Boolean);
  if (!queryTokens.length) {
    return rows;
  }
  return rows.filter((row) =>
    queryTokens.every((token) =>
      [
        row.id,
        row.actionScope,
        row.affectedContextsLabel,
        row.affectedSymbolsLabel,
        row.boundary,
        row.createdAt,
        row.detail,
        row.liveTradingAllowed ? "live allowed" : "live blocked",
        row.market,
        row.name,
        row.operator,
        row.overrideReason,
        row.providerHealthReason,
        row.providerHealthStatus,
        row.searchText,
        row.source,
        row.stage,
        row.statusLabel,
        row.summary,
        row.symbol,
        row.timeframe,
        row.tone,
        String(row.recentErrorCount),
        String(row.retryAfterSeconds)
      ]
        .join(" ")
        .toLowerCase()
        .includes(token)
    )
  );
}

export function buildExecutionAdapterPaperExecutionAuditLedgerRows(
  events: AuditEvidenceReportLedgerEventRecord[]
): ExecutionAdapterPaperExecutionAuditLedgerRow[] {
  return events
    .filter((event) => event.eventType === "execution_adapter_paper_execution")
    .map((event) => {
      const metadata = event.metadata ?? {};
      const fill = executionAdapterPaperExecutionAuditRecord(metadata, "simulatedFill");
      const adapterId = auditReportLedgerMetadataText(metadata, "adapterId");
      const adapterOpsStateId = auditReportLedgerMetadataText(metadata, "adapterOpsStateId");
      const manifestValidationId = auditReportLedgerMetadataText(metadata, "manifestValidationId");
      const market = auditReportLedgerMetadataText(metadata, "market");
      const route = auditReportLedgerMetadataText(metadata, "route");
      const status = auditReportLedgerMetadataText(metadata, "status");
      const paperOnly = auditReportLedgerMetadataBoolean(metadata, "paperOnly");
      const liveTradingAllowed = auditReportLedgerMetadataBoolean(metadata, "liveTradingAllowed");
      const routeExecuted = auditReportLedgerMetadataBoolean(metadata, "routeExecuted");
      const paperFillRecorded = auditReportLedgerMetadataBoolean(metadata, "paperFillRecorded");
      const statusLabel = executionAdapterPaperExecutionAuditStatusLabel(status, paperFillRecorded);
      const fillLabel = executionAdapterPaperExecutionAuditFillLabel(fill);
      const confirmationLabel = executionAdapterPaperExecutionAuditConfirmationLabel(metadata);
      const blockedReasonsLabel = executionAdapterPaperExecutionAuditBlockedReasonsLabel(metadata);
      const boundaryLabel = executionAdapterPaperExecutionAuditBoundaryLabel(paperOnly, liveTradingAllowed, routeExecuted);
      const symbol = executionAdapterPaperExecutionAuditText(fill, "symbol");
      const tone = executionAdapterPaperExecutionAuditTone(status, paperFillRecorded, liveTradingAllowed, routeExecuted);
      const searchText = [
        event.eventId,
        event.eventType,
        event.runId ?? "",
        event.stage,
        event.source,
        event.summary,
        event.detail,
        adapterId,
        adapterOpsStateId,
        manifestValidationId,
        market,
        route,
        status,
        statusLabel,
        fillLabel,
        confirmationLabel,
        blockedReasonsLabel,
        boundaryLabel,
        symbol,
        ...portfolioPaperOrderAuditMetadataSearchParts(metadata)
      ]
        .filter(Boolean)
        .join(" ");

      return {
        id: event.eventId,
        adapterId,
        adapterOpsStateId,
        blockedReasonsLabel,
        boundaryLabel,
        confirmationLabel,
        createdAt: event.createdAt,
        detail: event.detail,
        eventType: event.eventType,
        fillLabel,
        manifestValidationId,
        market,
        paperFillRecorded,
        route,
        runId: event.runId ?? "",
        searchText,
        source: event.source,
        stage: event.stage,
        statusLabel,
        summary: event.summary,
        symbol,
        tone
      };
    });
}

export function buildExecutionAdapterPaperExecutionAuditLedgerSummary(
  rows: ExecutionAdapterPaperExecutionAuditLedgerRow[]
): ExecutionAdapterPaperExecutionAuditLedgerSummary {
  const latestRow = rows.reduce<ExecutionAdapterPaperExecutionAuditLedgerRow | undefined>((latest, row) => {
    if (!latest) {
      return row;
    }
    return Date.parse(row.createdAt) > Date.parse(latest.createdAt) ? row : latest;
  }, undefined);

  return {
    blocked: rows.filter((row) => row.tone === "risk").length,
    filled: rows.filter((row) => row.paperFillRecorded).length,
    latestEventId: latestRow?.id ?? "",
    liveBlocked: rows.filter((row) => row.boundaryLabel.includes("live blocked")).length,
    total: rows.length
  };
}

export function filterExecutionAdapterPaperExecutionAuditLedgerRows(
  rows: ExecutionAdapterPaperExecutionAuditLedgerRow[],
  query: string
): ExecutionAdapterPaperExecutionAuditLedgerRow[] {
  const queryTokens = query.trim().toLowerCase().split(/\s+/u).filter(Boolean);
  if (!queryTokens.length) {
    return rows;
  }
  return rows.filter((row) =>
    queryTokens.every((token) =>
      [
        row.id,
        row.adapterId,
        row.adapterOpsStateId,
        row.blockedReasonsLabel,
        row.boundaryLabel,
        row.confirmationLabel,
        row.createdAt,
        row.detail,
        row.eventType,
        row.fillLabel,
        row.manifestValidationId,
        row.market,
        row.route,
        row.runId,
        row.searchText,
        row.source,
        row.stage,
        row.statusLabel,
        row.summary,
        row.symbol,
        row.tone
      ]
        .join(" ")
        .toLowerCase()
        .includes(token)
    )
  );
}

function executionAdapterPaperExecutionAuditRecord(
  metadata: Record<string, unknown>,
  key: string
): Record<string, unknown> {
  const value = metadata[key];
  return value && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : {};
}

function executionAdapterPaperExecutionAuditText(metadata: Record<string, unknown>, key: string): string {
  const value = metadata[key];
  return typeof value === "string" || typeof value === "number" || typeof value === "boolean" ? String(value) : "";
}

function executionAdapterPaperExecutionAuditStatusLabel(status: string, paperFillRecorded: boolean): string {
  if (status === "paper_execution_recorded" && paperFillRecorded) {
    return "Paper execution recorded";
  }
  if (status === "blocked") {
    return "Paper execution blocked";
  }
  return status || "Paper execution pending";
}

function executionAdapterPaperExecutionAuditFillLabel(fill: Record<string, unknown>): string {
  const status = executionAdapterPaperExecutionAuditText(fill, "status");
  const side = executionAdapterPaperExecutionAuditText(fill, "side");
  const quantity = executionAdapterPaperExecutionAuditText(fill, "quantity");
  const symbol = executionAdapterPaperExecutionAuditText(fill, "symbol");
  const price = executionAdapterPaperExecutionAuditText(fill, "price");
  return [status, side, quantity, symbol, price ? `@ ${price}` : ""].filter(Boolean).join(" ");
}

function executionAdapterPaperExecutionAuditConfirmationLabel(metadata: Record<string, unknown>): string {
  const required = auditReportLedgerMetadataStringList(metadata, "requiredConfirmationIds");
  const confirmed = auditReportLedgerMetadataStringList(metadata, "confirmedConfirmationIds");
  const missingCount = Math.max(0, required.length - confirmed.length);
  return `${confirmed.length} confirmed / ${missingCount} missing`;
}

function executionAdapterPaperExecutionAuditBlockedReasonsLabel(metadata: Record<string, unknown>): string {
  const reasons = auditReportLedgerMetadataStringList(metadata, "blockedReasons");
  return reasons.length ? reasons.join(", ") : "No blockers";
}

function executionAdapterPaperExecutionAuditBoundaryLabel(
  paperOnly: boolean,
  liveTradingAllowed: boolean,
  routeExecuted: boolean
): string {
  return [
    paperOnly ? "paper only" : "paper boundary unknown",
    liveTradingAllowed ? "live allowed" : "live blocked",
    routeExecuted ? "route executed" : "no route executed"
  ].join(" · ");
}

function executionAdapterPaperExecutionAuditTone(
  status: string,
  paperFillRecorded: boolean,
  liveTradingAllowed: boolean,
  routeExecuted: boolean
): ExecutionAdapterPaperExecutionAuditLedgerRow["tone"] {
  if (liveTradingAllowed || routeExecuted || status === "blocked") {
    return "risk";
  }
  return status === "paper_execution_recorded" && paperFillRecorded ? "positive" : "warning";
}

const portfolioPaperOrderAuditEventKinds: Record<string, PortfolioPaperOrderAuditEventKind> = {
  portfolio_paper_order_approval: "approval",
  portfolio_paper_order_batch: "batch",
  portfolio_paper_order_simulation: "simulation"
};

export function buildPortfolioPaperOrderAuditLedgerRows(
  events: AuditEvidenceReportLedgerEventRecord[]
): PortfolioPaperOrderAuditLedgerRow[] {
  return events
    .filter((event) => Boolean(portfolioPaperOrderAuditEventKinds[event.eventType]))
    .map((event) => {
      const eventKind = portfolioPaperOrderAuditEventKinds[event.eventType];
      const batchId = auditReportLedgerMetadataText(event.metadata, "batchId");
      const orderId = auditReportLedgerMetadataText(event.metadata, "orderId");
      const simulationId = auditReportLedgerMetadataText(event.metadata, "simulationId");
      const symbol = auditReportLedgerMetadataText(event.metadata, "symbol");
      const portfolioName = auditReportLedgerMetadataText(event.metadata, "portfolioName");
      const fillStatus = auditReportLedgerMetadataText(event.metadata, "fillStatus");
      const routeRiskStatus =
        auditReportLedgerMetadataText(event.metadata, "routeRiskStatus") ||
        auditReportLedgerMetadataText(event.metadata, "routeGuardStatus");
      const actor =
        auditReportLedgerMetadataText(event.metadata, "approvedBy") ||
        auditReportLedgerMetadataText(event.metadata, "reviewer") ||
        auditReportLedgerMetadataText(event.metadata, "operator");
      const paperOnly = auditReportLedgerMetadataBoolean(event.metadata, "paperOnly");
      const liveTradingAllowed = portfolioPaperOrderAuditLiveTradingAllowed(event.metadata);
      const boundaryLabel = portfolioPaperOrderAuditBoundaryLabel(paperOnly, liveTradingAllowed);
      const approved = auditReportLedgerMetadataBoolean(event.metadata, "approved");
      const adapterEvidenceId = auditReportLedgerMetadataText(event.metadata, "adapterPaperExecutionId");
      const orderCount =
        auditReportLedgerMetadataNumber(event.metadata, "orderCount") ||
        auditReportLedgerMetadataNumber(event.metadata, "totalOrders");
      const quantity = auditReportLedgerMetadataNumber(event.metadata, "quantity");
      const notionalValue =
        auditReportLedgerMetadataNumber(event.metadata, "notionalValue") ||
        auditReportLedgerMetadataNumber(event.metadata, "totalNotionalValue");
      const fillPrice = auditReportLedgerMetadataNumber(event.metadata, "fillPrice");
      const side = auditReportLedgerMetadataText(event.metadata, "side");
      const statusLabel = portfolioPaperOrderAuditStatusLabel(eventKind, approved, fillStatus);
      const quantityLabel = portfolioPaperOrderAuditQuantityLabel(eventKind, approved, orderCount, side, quantity);
      const valueLabel = portfolioPaperOrderAuditValueLabel(eventKind, notionalValue, symbol, orderId, fillPrice);
      const tone = portfolioPaperOrderAuditTone(eventKind, {
        approved,
        fillStatus,
        liveTradingAllowed,
        paperOnly
      });
      const searchText = [
        event.eventId,
        event.eventType,
        event.runId ?? "",
        event.stage,
        event.source,
        event.summary,
        event.detail,
        statusLabel,
        batchId,
        orderId,
        simulationId,
        symbol,
        portfolioName,
        actor,
        adapterEvidenceId,
        quantityLabel,
        valueLabel,
        boundaryLabel,
        fillStatus,
        routeRiskStatus,
        auditReportLedgerMetadataText(event.metadata, "approvalState"),
        auditReportLedgerMetadataText(event.metadata, "orderState"),
        auditReportLedgerMetadataText(event.metadata, "reason"),
        ...portfolioPaperOrderAuditMetadataSearchParts(event.metadata)
      ]
        .filter(Boolean)
        .join(" ");

      return {
        id: event.eventId,
        actor,
        adapterEvidenceId,
        batchId,
        boundaryLabel,
        createdAt: event.createdAt,
        detail: event.detail,
        eventKind,
        eventType: event.eventType,
        orderId,
        portfolioName,
        quantityLabel,
        runId: event.runId ?? "",
        searchText,
        simulationId,
        source: event.source,
        stage: event.stage,
        statusLabel,
        summary: event.summary,
        symbol,
        tone,
        valueLabel
      };
    });
}

export function buildPortfolioPaperOrderAuditLedgerSummary(
  rows: PortfolioPaperOrderAuditLedgerRow[]
): PortfolioPaperOrderAuditLedgerSummary {
  const latestRow = rows.reduce<PortfolioPaperOrderAuditLedgerRow | undefined>((latest, row) => {
    if (!latest) {
      return row;
    }
    return Date.parse(row.createdAt) > Date.parse(latest.createdAt) ? row : latest;
  }, undefined);

  return {
    approvals: rows.filter((row) => row.eventKind === "approval").length,
    batches: rows.filter((row) => row.eventKind === "batch").length,
    latestEventId: latestRow?.id ?? "",
    liveBlocked: rows.filter((row) => row.boundaryLabel.includes("live blocked")).length,
    simulations: rows.filter((row) => row.eventKind === "simulation").length,
    total: rows.length
  };
}

export function filterPortfolioPaperOrderAuditLedgerRows(
  rows: PortfolioPaperOrderAuditLedgerRow[],
  query: string
): PortfolioPaperOrderAuditLedgerRow[] {
  const queryTokens = query.trim().toLowerCase().split(/\s+/u).filter(Boolean);
  if (!queryTokens.length) {
    return rows;
  }
  return rows.filter((row) =>
    queryTokens.every((token) =>
      [
        row.id,
        row.actor,
        row.adapterEvidenceId,
        row.batchId,
        row.boundaryLabel,
        row.createdAt,
        row.detail,
        row.eventKind,
        row.eventType,
        row.orderId,
        row.portfolioName,
        row.quantityLabel,
        row.runId,
        row.searchText,
        row.simulationId,
        row.source,
        row.stage,
        row.statusLabel,
        row.summary,
        row.symbol,
        row.tone,
        row.valueLabel
      ]
        .join(" ")
        .toLowerCase()
        .includes(token)
    )
  );
}

function portfolioPaperOrderAuditLiveTradingAllowed(metadata: Record<string, unknown>): boolean | null {
  if (auditReportLedgerMetadataHas(metadata, "liveTradingAllowed")) {
    return auditReportLedgerMetadataBoolean(metadata, "liveTradingAllowed");
  }
  if (auditReportLedgerMetadataBoolean(metadata, "liveExecutionBlocked")) {
    return false;
  }
  return null;
}

function portfolioPaperOrderAuditBoundaryLabel(paperOnly: boolean, liveTradingAllowed: boolean | null): string {
  const liveBoundary =
    liveTradingAllowed === null ? "live boundary unknown" : liveTradingAllowed ? "live allowed" : "live blocked";
  return `${paperOnly ? "paper only" : "paper boundary unknown"} · ${liveBoundary}`;
}

function portfolioPaperOrderAuditStatusLabel(
  eventKind: PortfolioPaperOrderAuditEventKind,
  approved: boolean,
  fillStatus: string
): string {
  if (eventKind === "batch") {
    return "Batch recorded";
  }
  if (eventKind === "approval") {
    return approved ? "Approval recorded" : "Approval rejected";
  }
  return fillStatus === "filled" ? "Simulation filled" : "Simulation recorded";
}

function portfolioPaperOrderAuditQuantityLabel(
  eventKind: PortfolioPaperOrderAuditEventKind,
  approved: boolean,
  orderCount: number,
  side: string,
  quantity: number
): string {
  if (eventKind === "batch") {
    const formattedCount = portfolioPaperOrderAuditNumberLabel(orderCount);
    return `${formattedCount} ${orderCount === 1 ? "order" : "orders"}`;
  }
  if (eventKind === "approval") {
    return approved ? "approved" : "rejected";
  }
  return [side, portfolioPaperOrderAuditNumberLabel(quantity)].filter(Boolean).join(" ");
}

function portfolioPaperOrderAuditValueLabel(
  eventKind: PortfolioPaperOrderAuditEventKind,
  notionalValue: number,
  symbol: string,
  orderId: string,
  fillPrice: number
): string {
  if (eventKind === "batch") {
    return portfolioPaperOrderAuditNumberLabel(notionalValue);
  }
  if (eventKind === "approval") {
    return symbol || orderId;
  }
  return portfolioPaperOrderAuditNumberLabel(fillPrice);
}

function portfolioPaperOrderAuditTone(
  eventKind: PortfolioPaperOrderAuditEventKind,
  {
    approved,
    fillStatus,
    liveTradingAllowed,
    paperOnly
  }: { approved: boolean; fillStatus: string; liveTradingAllowed: boolean | null; paperOnly: boolean }
): PortfolioPaperOrderAuditLedgerRow["tone"] {
  if (liveTradingAllowed === true) {
    return "risk";
  }
  if (eventKind === "approval") {
    return approved ? "positive" : "risk";
  }
  if (eventKind === "simulation") {
    return fillStatus === "filled" && paperOnly ? "positive" : "warning";
  }
  return paperOnly ? "warning" : "neutral";
}

function portfolioPaperOrderAuditNumberLabel(value: number): string {
  return Number.isFinite(value)
    ? value.toLocaleString("en-US", { maximumFractionDigits: 8 })
    : "";
}

function portfolioPaperOrderAuditMetadataSearchParts(metadata: Record<string, unknown>): string[] {
  return Object.entries(metadata)
    .map(([key, value]) => {
      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
        return `${key} ${String(value)}`;
      }
      if (Array.isArray(value)) {
        return `${key} ${value.map((item) => String(item)).join(" ")}`;
      }
      if (value && typeof value === "object") {
        return `${key} ${JSON.stringify(value)}`;
      }
      return key;
    })
    .filter(Boolean);
}

