function buildPromotionAdapterCertificationStage(
  certifiedLiveAdapters: number,
  latestCertification: ExecutionAdapterCertificationRow | null,
  latestApply: ExecutionAdapterCertificationApplyRow | null,
  latestRestartEvidence: ExecutionAdapterControlledRestartEvidenceRow | null,
  latestRestartAcceptance: ExecutionAdapterRestartAcceptanceRow | null,
  latestSecretReference: ExecutionAdapterSecretReferenceRow | null,
  latestSecretMaterialization: ExecutionAdapterSecretMaterializationRow | null,
  latestEnvironmentBinding: ExecutionAdapterEnvironmentBindingRow | null,
  latestRuntimeReloadPlan: ExecutionAdapterRuntimeReloadPlanRow | null,
  latestRuntimeReloadExecution: ExecutionAdapterRuntimeReloadExecutionRow | null,
  latestRuntimeReloadAcceptance: ExecutionAdapterRuntimeReloadAcceptanceRow | null,
  latestSandboxProbeExecution: ExecutionAdapterSandboxProbeExecutionRow | null,
  latestSandboxProbeReview: ExecutionAdapterSandboxProbeReviewRow | null,
  latestProductionRouteReview: ExecutionAdapterProductionRouteReviewRow | null,
  latestSandboxOrderSchemaDryRun: ExecutionAdapterSandboxOrderSchemaDryRunRow | null,
  latestPaperOrderLifecycle: ExecutionAdapterPaperOrderLifecycleRow | null,
  latestPaperRouteRunbook: ExecutionAdapterPaperRouteRunbookRow | null,
  latestAdapterOpsState: ExecutionAdapterOpsStateRow | null,
  latestAdapterPaperExecution: ExecutionAdapterPaperExecutionRow | null,
  liveAdapterCertified: boolean,
  adapterGatePassed: boolean
): PromotionQueueStage {
  const secretReferenceDetail = latestSecretReference
    ? `Latest secret reference ${latestSecretReference.auditEventId}: ${latestSecretReference.statusLabel} · ${latestSecretReference.confirmationSummary} · ${latestSecretReference.blockerSummary} · ${latestSecretReference.backend} · ${latestSecretReference.envVarSummary} · ${latestSecretReference.boundary}.`
    : "";
  const secretMaterializationDetail = latestSecretMaterialization
    ? `Latest secret materialization ${latestSecretMaterialization.auditEventId}: ${latestSecretMaterialization.statusLabel} · ${latestSecretMaterialization.confirmationSummary} · ${latestSecretMaterialization.blockerSummary} · ${latestSecretMaterialization.backend} · ${latestSecretMaterialization.envVarSummary} · ${latestSecretMaterialization.boundary}. ${promotionSecretMaterializationNextStep(latestSecretMaterialization)}`
    : "";
  const environmentBindingDetail = latestEnvironmentBinding
    ? `Latest environment binding ${latestEnvironmentBinding.auditEventId}: ${latestEnvironmentBinding.statusLabel} · ${latestEnvironmentBinding.confirmationSummary} · ${latestEnvironmentBinding.blockerSummary} · ${latestEnvironmentBinding.bindingMode} · ${latestEnvironmentBinding.envVarSummary} · ${latestEnvironmentBinding.boundary}. ${promotionEnvironmentBindingNextStep(latestEnvironmentBinding)}`
    : "";
  const runtimeReloadPlanValidationDetail = latestRuntimeReloadPlan?.manifestValidationId
    ? ` · ${latestRuntimeReloadPlan.manifestValidationId}`
    : "";
  const runtimeReloadPlanDetail = latestRuntimeReloadPlan
    ? `Latest runtime reload plan ${latestRuntimeReloadPlan.auditEventId}: ${latestRuntimeReloadPlan.statusLabel} · ${latestRuntimeReloadPlan.confirmationSummary} · ${latestRuntimeReloadPlan.blockerSummary} · ${latestRuntimeReloadPlan.reloadMode} · ${latestRuntimeReloadPlan.maintenanceWindowId}${runtimeReloadPlanValidationDetail} · ${latestRuntimeReloadPlan.boundary}. ${promotionRuntimeReloadPlanNextStep(latestRuntimeReloadPlan)}`
    : "";
  const runtimeReloadExecutionValidationDetail = latestRuntimeReloadExecution?.manifestValidationId
    ? ` · ${latestRuntimeReloadExecution.manifestValidationId}`
    : "";
  const runtimeReloadExecutionDetail = latestRuntimeReloadExecution
    ? `Latest runtime reload execution ${latestRuntimeReloadExecution.auditEventId}: ${latestRuntimeReloadExecution.statusLabel} · ${latestRuntimeReloadExecution.confirmationSummary} · ${latestRuntimeReloadExecution.blockerSummary} · ${latestRuntimeReloadExecution.executionMode} · ${latestRuntimeReloadExecution.reloadMode} · ${latestRuntimeReloadExecution.maintenanceWindowId}${runtimeReloadExecutionValidationDetail} · ${latestRuntimeReloadExecution.boundary}. ${promotionRuntimeReloadExecutionNextStep(latestRuntimeReloadExecution)}`
    : "";
  const runtimeReloadAcceptanceValidationDetail = latestRuntimeReloadAcceptance?.manifestValidationId
    ? ` · ${latestRuntimeReloadAcceptance.manifestValidationId}`
    : "";
  const runtimeReloadAcceptanceDetail = latestRuntimeReloadAcceptance
    ? `Latest runtime reload acceptance ${latestRuntimeReloadAcceptance.auditEventId}: ${latestRuntimeReloadAcceptance.statusLabel} · ${latestRuntimeReloadAcceptance.confirmationSummary} · ${latestRuntimeReloadAcceptance.blockerSummary} · ${latestRuntimeReloadAcceptance.acceptanceMode} · ${latestRuntimeReloadAcceptance.executionMode} · ${latestRuntimeReloadAcceptance.reloadMode} · ${latestRuntimeReloadAcceptance.maintenanceWindowId}${runtimeReloadAcceptanceValidationDetail} · ${latestRuntimeReloadAcceptance.boundary}. ${promotionRuntimeReloadAcceptanceNextStep(latestRuntimeReloadAcceptance)}`
    : "";
  const sandboxProbeExecutionValidationDetail = latestSandboxProbeExecution?.manifestValidationId
    ? ` · manifest ${latestSandboxProbeExecution.manifestValidationId}`
    : "";
  const sandboxProbeExecutionDetail = latestSandboxProbeExecution
    ? `Latest sandbox probe execution ${latestSandboxProbeExecution.auditEventId}: ${latestSandboxProbeExecution.statusLabel} · ${latestSandboxProbeExecution.confirmationSummary} · ${latestSandboxProbeExecution.blockerSummary} · ${latestSandboxProbeExecution.probeExecutionMode} · ${latestSandboxProbeExecution.probeMode}${sandboxProbeExecutionValidationDetail} · ${latestSandboxProbeExecution.boundary}. ${promotionSandboxProbeExecutionNextStep(latestSandboxProbeExecution)}`
    : "";
  const sandboxProbeReviewValidationDetail = latestSandboxProbeReview?.manifestValidationId
    ? ` · manifest ${latestSandboxProbeReview.manifestValidationId}`
    : "";
  const sandboxProbeReviewDetail = latestSandboxProbeReview
    ? `Latest sandbox probe review ${latestSandboxProbeReview.auditEventId}: ${latestSandboxProbeReview.statusLabel} · ${latestSandboxProbeReview.confirmationSummary} · ${latestSandboxProbeReview.blockerSummary} · ${latestSandboxProbeReview.reviewMode} · ${latestSandboxProbeReview.probeExecutionMode}${sandboxProbeReviewValidationDetail} · ${latestSandboxProbeReview.boundary}. ${promotionSandboxProbeReviewNextStep(latestSandboxProbeReview)}`
    : "";
  const productionRouteReviewValidationDetail = latestProductionRouteReview?.manifestValidationId
    ? ` · manifest ${latestProductionRouteReview.manifestValidationId}`
    : "";
  const productionRouteReviewDetail = latestProductionRouteReview
    ? `Latest production route review ${latestProductionRouteReview.auditEventId}: ${latestProductionRouteReview.statusLabel} · ${latestProductionRouteReview.confirmationSummary} · ${latestProductionRouteReview.blockerSummary} · ${latestProductionRouteReview.reviewMode} · ${latestProductionRouteReview.sandboxReviewMode}${productionRouteReviewValidationDetail} · ${latestProductionRouteReview.boundary}. ${promotionProductionRouteReviewNextStep(latestProductionRouteReview)}`
    : "";
  const sandboxOrderSchemaDryRunValidationDetail = latestSandboxOrderSchemaDryRun?.manifestValidationId
    ? ` · manifest ${latestSandboxOrderSchemaDryRun.manifestValidationId}`
    : "";
  const sandboxOrderSchemaDryRunDetail = latestSandboxOrderSchemaDryRun
    ? `Latest sandbox order schema dry-run ${latestSandboxOrderSchemaDryRun.auditEventId}: ${latestSandboxOrderSchemaDryRun.statusLabel} · ${latestSandboxOrderSchemaDryRun.orderIntentSummary} · ${latestSandboxOrderSchemaDryRun.confirmationSummary} · ${latestSandboxOrderSchemaDryRun.blockerSummary} · ${latestSandboxOrderSchemaDryRun.dryRunMode} · ${latestSandboxOrderSchemaDryRun.reviewMode}${sandboxOrderSchemaDryRunValidationDetail} · ${latestSandboxOrderSchemaDryRun.boundary}. ${promotionSandboxOrderSchemaDryRunNextStep(latestSandboxOrderSchemaDryRun)}`
    : "";
  const paperOrderLifecycleValidationDetail = latestPaperOrderLifecycle?.manifestValidationId
    ? ` · manifest ${latestPaperOrderLifecycle.manifestValidationId}`
    : "";
  const paperOrderLifecycleDetail = latestPaperOrderLifecycle
    ? `Latest paper order lifecycle ${latestPaperOrderLifecycle.auditEventId}: ${latestPaperOrderLifecycle.statusLabel} · ${latestPaperOrderLifecycle.orderIntentSummary} · ${latestPaperOrderLifecycle.lifecycleStepSummary} · ${latestPaperOrderLifecycle.confirmationSummary} · ${latestPaperOrderLifecycle.blockerSummary} · ${latestPaperOrderLifecycle.lifecycleMode} · ${latestPaperOrderLifecycle.dryRunMode}${paperOrderLifecycleValidationDetail} · ${latestPaperOrderLifecycle.boundary}. ${promotionPaperOrderLifecycleNextStep(latestPaperOrderLifecycle)}`
    : "";
  const paperRouteRunbookValidationDetail = latestPaperRouteRunbook?.manifestValidationId
    ? ` · manifest ${latestPaperRouteRunbook.manifestValidationId}`
    : "";
  const paperRouteRunbookDetail = latestPaperRouteRunbook
    ? `Latest paper route runbook ${latestPaperRouteRunbook.auditEventId}: ${latestPaperRouteRunbook.statusLabel} · ${latestPaperRouteRunbook.orderIntentSummary} · ${latestPaperRouteRunbook.runbookStepSummary} · ${latestPaperRouteRunbook.confirmationSummary} · ${latestPaperRouteRunbook.blockerSummary} · ${latestPaperRouteRunbook.runbookMode} · ${latestPaperRouteRunbook.lifecycleMode}${paperRouteRunbookValidationDetail} · ${latestPaperRouteRunbook.boundary}. ${promotionPaperRouteRunbookNextStep(latestPaperRouteRunbook)}`
    : "";
  const adapterOpsStateValidationDetail = latestAdapterOpsState?.manifestValidationId
    ? ` · manifest ${latestAdapterOpsState.manifestValidationId}`
    : "";
  const adapterOpsStateDetail = latestAdapterOpsState
    ? `Latest adapter ops state ${latestAdapterOpsState.auditEventId}: ${latestAdapterOpsState.statusLabel} · ${latestAdapterOpsState.orderIntentSummary} · ${latestAdapterOpsState.opsStepSummary} · ${latestAdapterOpsState.confirmationSummary} · ${latestAdapterOpsState.blockerSummary} · ${latestAdapterOpsState.opsMode} · ${latestAdapterOpsState.runbookMode}${adapterOpsStateValidationDetail} · ${latestAdapterOpsState.boundary}. ${promotionAdapterOpsStateNextStep(latestAdapterOpsState)}`
    : "";
  const adapterPaperExecutionValidationDetail = latestAdapterPaperExecution?.manifestValidationId
    ? ` · manifest ${latestAdapterPaperExecution.manifestValidationId}`
    : "";
  const adapterPaperExecutionDetail = latestAdapterPaperExecution
    ? `Latest adapter paper execution ${latestAdapterPaperExecution.auditEventId}: ${latestAdapterPaperExecution.statusLabel} · ${latestAdapterPaperExecution.fillSummary} · ${latestAdapterPaperExecution.confirmationSummary} · ${latestAdapterPaperExecution.blockerSummary} · ${latestAdapterPaperExecution.paperExecutionMode}${adapterPaperExecutionValidationDetail} · ${latestAdapterPaperExecution.boundary}. ${promotionAdapterPaperExecutionNextStep(latestAdapterPaperExecution)}`
    : "";
  if (!latestCertification) {
    const liveAdapterDetail = liveAdapterCertified
      ? "A certified live adapter is available for the selected market."
      : "Live adapters remain interface-only or configuration-required until certification passes.";
    return {
      id: "adapter-certification",
      label: "Adapter certification",
      value: latestAdapterPaperExecution
        ? `${latestAdapterPaperExecution.statusLabel} · ${latestAdapterPaperExecution.adapterId}`
        : latestAdapterOpsState
        ? `${latestAdapterOpsState.statusLabel} · ${latestAdapterOpsState.adapterId}`
        : latestPaperRouteRunbook
        ? `${latestPaperRouteRunbook.statusLabel} · ${latestPaperRouteRunbook.adapterId}`
        : latestPaperOrderLifecycle
        ? `${latestPaperOrderLifecycle.statusLabel} · ${latestPaperOrderLifecycle.adapterId}`
        : latestSandboxOrderSchemaDryRun
        ? `${latestSandboxOrderSchemaDryRun.statusLabel} · ${latestSandboxOrderSchemaDryRun.adapterId}`
        : latestProductionRouteReview
        ? `${latestProductionRouteReview.statusLabel} · ${latestProductionRouteReview.adapterId}`
        : latestSandboxProbeReview
        ? `${latestSandboxProbeReview.statusLabel} · ${latestSandboxProbeReview.adapterId}`
        : latestSandboxProbeExecution
        ? `${latestSandboxProbeExecution.statusLabel} · ${latestSandboxProbeExecution.adapterId}`
        : certifiedLiveAdapters === 1
          ? "1 certified live adapter"
          : `${certifiedLiveAdapters} certified live adapters`,
      detail: [
        liveAdapterDetail,
        secretReferenceDetail,
        secretMaterializationDetail,
        environmentBindingDetail,
        runtimeReloadPlanDetail,
        runtimeReloadExecutionDetail,
        runtimeReloadAcceptanceDetail,
        sandboxProbeExecutionDetail,
        sandboxProbeReviewDetail,
        productionRouteReviewDetail,
        sandboxOrderSchemaDryRunDetail,
        paperOrderLifecycleDetail,
        paperRouteRunbookDetail,
        adapterOpsStateDetail,
        adapterPaperExecutionDetail
      ]
        .filter(Boolean)
        .join(" "),
      status: liveAdapterCertified ? "passed" : "blocked",
      tone: liveAdapterCertified
        ? "positive"
        : latestAdapterPaperExecution?.status === "paper_execution_recorded" && latestAdapterPaperExecution.paperFillRecorded
          ? "warning"
        : latestAdapterPaperExecution
          ? latestAdapterPaperExecution.tone
        : latestAdapterOpsState?.status === "ops_state_recorded" &&
            !latestAdapterOpsState.routeExecuted &&
            !latestAdapterOpsState.liveOrderSubmitted
          ? "warning"
        : latestAdapterOpsState
          ? latestAdapterOpsState.tone
        : latestPaperRouteRunbook?.status === "runbook_recorded" &&
            !latestPaperRouteRunbook.routeExecuted &&
            !latestPaperRouteRunbook.liveOrderSubmitted
          ? "warning"
        : latestPaperRouteRunbook
          ? latestPaperRouteRunbook.tone
        : latestPaperOrderLifecycle?.status === "lifecycle_recorded" &&
            !latestPaperOrderLifecycle.orderSubmitted &&
            !latestPaperOrderLifecycle.liveOrderSubmitted
          ? "warning"
        : latestPaperOrderLifecycle
          ? latestPaperOrderLifecycle.tone
        : latestSandboxOrderSchemaDryRun?.status === "schema_dry_run_recorded" && !latestSandboxOrderSchemaDryRun.orderSubmitted
          ? "warning"
        : latestSandboxOrderSchemaDryRun
          ? latestSandboxOrderSchemaDryRun.tone
        : latestProductionRouteReview?.status === "route_review_recorded"
          ? "warning"
        : latestProductionRouteReview
          ? latestProductionRouteReview.tone
        : latestSandboxProbeReview?.status === "probe_review_recorded"
          ? "warning"
        : latestSandboxProbeReview
          ? latestSandboxProbeReview.tone
        : latestSandboxProbeExecution?.status === "probe_execution_recorded"
          ? "warning"
        : latestSandboxProbeExecution
          ? latestSandboxProbeExecution.tone
        : latestRuntimeReloadAcceptance?.status === "acceptance_recorded" ||
            latestRuntimeReloadExecution?.status === "execution_recorded" ||
            latestRuntimeReloadPlan?.status === "plan_recorded" ||
            latestEnvironmentBinding?.status === "binding_recorded" ||
            latestSecretMaterialization?.status === "manifest_recorded" ||
            latestSecretReference?.status === "reference_recorded"
          ? "warning"
          : "risk"
    };
  }

  const certificationDetail = `Latest certification ${latestCertification.auditEventId}: ${latestCertification.checkSummary} · ${latestCertification.boundary}.`;
  const restartEvidenceDetail = latestRestartEvidence
    ? `Latest restart evidence ${latestRestartEvidence.auditEventId}: ${latestRestartEvidence.statusLabel} · ${latestRestartEvidence.confirmationSummary} · ${latestRestartEvidence.blockerSummary} · ${latestRestartEvidence.boundary}.${latestRestartAcceptance ? "" : ` ${promotionControlledRestartEvidenceNextStep(latestRestartEvidence)}`}`
    : "";
  const restartAcceptanceDetail = latestRestartAcceptance
    ? `Latest restart acceptance ${latestRestartAcceptance.auditEventId}: ${latestRestartAcceptance.statusLabel} · ${latestRestartAcceptance.confirmationSummary} · ${latestRestartAcceptance.blockerSummary} · ${latestRestartAcceptance.boundary}. ${promotionRestartAcceptanceNextStep(latestRestartAcceptance)}`
    : "";
  const applyDetail = latestApply
    ? `Latest apply ${latestApply.auditEventId}: ${latestApply.statusLabel} · ${latestApply.confirmationSummary} · ${latestApply.blockerSummary} · ${latestApply.boundary}.${latestRestartEvidence ? "" : ` ${promotionCertificationApplyNextStep(latestApply)}`}`
    : "";
  const gateDetail =
    !latestApply && !latestRestartEvidence && latestCertification.status === "passed" && latestCertification.liveTradingAllowed && !adapterGatePassed
      ? "Workspace adapter gate is still blocked."
      : "";
  return {
    id: "adapter-certification",
    label: "Adapter certification",
    value: `${latestAdapterPaperExecution?.statusLabel ?? latestAdapterOpsState?.statusLabel ?? latestPaperRouteRunbook?.statusLabel ?? latestPaperOrderLifecycle?.statusLabel ?? latestSandboxOrderSchemaDryRun?.statusLabel ?? latestProductionRouteReview?.statusLabel ?? latestSandboxProbeReview?.statusLabel ?? latestSandboxProbeExecution?.statusLabel ?? latestRestartAcceptance?.statusLabel ?? latestRestartEvidence?.statusLabel ?? latestRuntimeReloadAcceptance?.statusLabel ?? latestRuntimeReloadExecution?.statusLabel ?? latestApply?.statusLabel ?? latestCertification.statusLabel} · ${latestCertification.adapterId}`,
    detail: [
      secretReferenceDetail,
      secretMaterializationDetail,
      environmentBindingDetail,
      runtimeReloadPlanDetail,
      runtimeReloadExecutionDetail,
      runtimeReloadAcceptanceDetail,
      sandboxProbeExecutionDetail,
      sandboxProbeReviewDetail,
      productionRouteReviewDetail,
      sandboxOrderSchemaDryRunDetail,
      paperOrderLifecycleDetail,
      paperRouteRunbookDetail,
      adapterOpsStateDetail,
      adapterPaperExecutionDetail,
      certificationDetail,
      applyDetail,
      restartEvidenceDetail,
      restartAcceptanceDetail,
      gateDetail
    ]
      .filter(Boolean)
      .join(" "),
    status: liveAdapterCertified ? "passed" : "blocked",
    tone: liveAdapterCertified
      ? "positive"
      : latestAdapterPaperExecution?.status === "paper_execution_recorded" && latestAdapterPaperExecution.paperFillRecorded
        ? "warning"
      : latestAdapterPaperExecution
        ? latestAdapterPaperExecution.tone
      : latestAdapterOpsState?.status === "ops_state_recorded" &&
          !latestAdapterOpsState.routeExecuted &&
          !latestAdapterOpsState.liveOrderSubmitted
        ? "warning"
      : latestAdapterOpsState
        ? latestAdapterOpsState.tone
      : latestPaperRouteRunbook?.status === "runbook_recorded" &&
          !latestPaperRouteRunbook.routeExecuted &&
          !latestPaperRouteRunbook.liveOrderSubmitted
        ? "warning"
      : latestPaperRouteRunbook
        ? latestPaperRouteRunbook.tone
      : latestPaperOrderLifecycle?.status === "lifecycle_recorded" &&
          !latestPaperOrderLifecycle.orderSubmitted &&
          !latestPaperOrderLifecycle.liveOrderSubmitted
        ? "warning"
      : latestPaperOrderLifecycle
        ? latestPaperOrderLifecycle.tone
      : latestSandboxOrderSchemaDryRun?.status === "schema_dry_run_recorded" && !latestSandboxOrderSchemaDryRun.orderSubmitted
        ? "warning"
      : latestSandboxOrderSchemaDryRun
        ? latestSandboxOrderSchemaDryRun.tone
      : latestProductionRouteReview?.status === "route_review_recorded"
        ? "warning"
      : latestProductionRouteReview
        ? latestProductionRouteReview.tone
      : latestSandboxProbeReview?.status === "probe_review_recorded"
        ? "warning"
      : latestSandboxProbeReview
        ? latestSandboxProbeReview.tone
      : latestSandboxProbeExecution?.status === "probe_execution_recorded"
        ? "warning"
      : latestSandboxProbeExecution
        ? latestSandboxProbeExecution.tone
      : latestRuntimeReloadAcceptance?.status === "acceptance_recorded" ||
          latestRuntimeReloadExecution?.status === "execution_recorded" ||
          latestRuntimeReloadPlan?.status === "plan_recorded" ||
          latestEnvironmentBinding?.status === "binding_recorded" ||
          latestSecretMaterialization?.status === "manifest_recorded" ||
          latestRestartAcceptance?.status === "acceptance_recorded" ||
          latestRestartEvidence?.status === "evidence_recorded" ||
          latestApply?.status === "ready_for_restart"
        ? "warning"
      : latestCertification.status === "passed" && latestCertification.liveTradingAllowed
        ? "warning"
        : latestCertification.tone
  };
}

function promotionCertificationApplyNextStep(apply: ExecutionAdapterCertificationApplyRow): string {
  if (apply.status === "ready_for_restart") {
    return "Controlled restart evidence is still required before live routing.";
  }
  return "Resolve apply preflight blockers before live routing.";
}

function promotionControlledRestartEvidenceNextStep(evidence: ExecutionAdapterControlledRestartEvidenceRow): string {
  if (evidence.status === "evidence_recorded") {
    return "Controlled restart evidence is recorded; live routing remains blocked until controlled orchestration and human confirmation pass.";
  }
  return "Resolve controlled restart evidence blockers before live routing.";
}

function promotionRestartAcceptanceNextStep(acceptance: ExecutionAdapterRestartAcceptanceRow): string {
  if (acceptance.status === "acceptance_recorded") {
    return "Post-restart acceptance is recorded; live routing remains blocked until real adapter orchestration and human confirmation pass.";
  }
  return "Resolve post-restart acceptance blockers before live routing.";
}

function promotionSecretMaterializationNextStep(materialization: ExecutionAdapterSecretMaterializationRow): string {
  if (materialization.status === "manifest_recorded") {
    return "Secret materialization manifest is recorded; live routing remains blocked until env writes, restart orchestration, and human confirmation pass.";
  }
  return "Resolve secret materialization blockers before restart orchestration.";
}

function promotionEnvironmentBindingNextStep(binding: ExecutionAdapterEnvironmentBindingRow): string {
  if (binding.status === "binding_recorded") {
    return "Environment binding is recorded; live routing remains blocked until runtime reload orchestration and human confirmation pass.";
  }
  return "Resolve environment binding blockers before runtime reload planning.";
}

function promotionRuntimeReloadPlanNextStep(plan: ExecutionAdapterRuntimeReloadPlanRow): string {
  if (plan.status === "plan_recorded") {
    return "Runtime reload plan is recorded; live routing remains blocked until controlled reload execution, acceptance, and human confirmation pass.";
  }
  return "Resolve runtime reload plan blockers before controlled reload execution.";
}

function promotionRuntimeReloadExecutionNextStep(execution: ExecutionAdapterRuntimeReloadExecutionRow): string {
  if (execution.status === "execution_recorded") {
    return "Runtime reload execution evidence is recorded; live routing remains blocked until post-reload acceptance, real adapter orchestration, and human confirmation pass.";
  }
  return "Resolve runtime reload execution blockers before post-reload acceptance.";
}

function promotionRuntimeReloadAcceptanceNextStep(acceptance: ExecutionAdapterRuntimeReloadAcceptanceRow): string {
  if (acceptance.status === "acceptance_recorded") {
    return "Runtime reload acceptance is recorded; live routing remains blocked until real adapter orchestration and human confirmation pass.";
  }
  return "Resolve runtime reload acceptance blockers before real adapter orchestration.";
}

function promotionSandboxProbeExecutionNextStep(execution: ExecutionAdapterSandboxProbeExecutionRow): string {
  if (execution.status === "probe_execution_recorded") {
    return "Sandbox probe execution is recorded; live routing remains blocked until adapter certification policy explicitly allows production routing.";
  }
  return "Resolve sandbox probe execution blockers before treating sandbox evidence as reviewed.";
}

function promotionSandboxProbeReviewNextStep(review: ExecutionAdapterSandboxProbeReviewRow): string {
  if (review.status === "probe_review_recorded") {
    return "Sandbox probe review is recorded; live routing remains blocked until production route policy review and certification allow it.";
  }
  return "Resolve sandbox probe review blockers before treating sandbox evidence as production-route ready.";
}

function promotionProductionRouteReviewNextStep(review: ExecutionAdapterProductionRouteReviewRow): string {
  if (review.status === "route_review_recorded") {
    return "Production route review is recorded; live routing remains blocked until sandbox order schema dry-run, paper route runbook, and certification allow it.";
  }
  return "Resolve production route review blockers before preparing sandbox order schema dry-runs.";
}

function promotionSandboxOrderSchemaDryRunNextStep(dryRun: ExecutionAdapterSandboxOrderSchemaDryRunRow): string {
  if (dryRun.status === "schema_dry_run_recorded" && !dryRun.orderSubmitted) {
    return "Sandbox order schema dry-run is recorded; live routing remains blocked until paper order lifecycle, route runbook, and certification allow it.";
  }
  return "Resolve sandbox order schema dry-run blockers before preparing paper order lifecycle evidence.";
}

function promotionPaperOrderLifecycleNextStep(lifecycle: ExecutionAdapterPaperOrderLifecycleRow): string {
  if (lifecycle.status === "lifecycle_recorded" && !lifecycle.orderSubmitted && !lifecycle.liveOrderSubmitted) {
    return "Paper order lifecycle is recorded; live routing remains blocked until paper route runbook, ops state, and certification allow it.";
  }
  return "Resolve paper order lifecycle blockers before preparing route runbook evidence.";
}

function promotionPaperRouteRunbookNextStep(runbook: ExecutionAdapterPaperRouteRunbookRow): string {
  if (runbook.status === "runbook_recorded" && !runbook.routeExecuted && !runbook.liveOrderSubmitted) {
    return "Paper route runbook is recorded; live routing remains blocked until adapter ops state, paper execution, and certification allow it.";
  }
  return "Resolve paper route runbook blockers before preparing adapter ops state evidence.";
}

function promotionAdapterOpsStateNextStep(opsState: ExecutionAdapterOpsStateRow): string {
  if (opsState.status === "ops_state_recorded" && !opsState.routeExecuted && !opsState.liveOrderSubmitted) {
    return "Adapter ops state is recorded; live routing remains blocked until paper execution and certification allow it.";
  }
  return "Resolve adapter ops state blockers before preparing paper execution evidence.";
}

function promotionAdapterPaperExecutionNextStep(execution: ExecutionAdapterPaperExecutionRow): string {
  if (execution.status === "paper_execution_recorded" && execution.paperFillRecorded) {
    return "Adapter paper execution is recorded with a simulated fill; live routing remains blocked until adapter certification policy explicitly allows production routing.";
  }
  return "Resolve adapter paper execution blockers before treating the paper route as reviewed.";
}

export function buildPromotionReadiness(
  workspace: TerminalWorkspace,
  execution: PaperExecutionSnapshot | null | undefined,
  brokerRows: BrokerAdapterRow[],
  certificationRows: ExecutionAdapterCertificationRow[] = [],
  certificationApplyRows: ExecutionAdapterCertificationApplyRow[] = [],
  controlledRestartEvidenceRows: ExecutionAdapterControlledRestartEvidenceRow[] = [],
  restartAcceptanceRows: ExecutionAdapterRestartAcceptanceRow[] = [],
  secretReferenceRows: ExecutionAdapterSecretReferenceRow[] = [],
  secretMaterializationRows: ExecutionAdapterSecretMaterializationRow[] = [],
  environmentBindingRows: ExecutionAdapterEnvironmentBindingRow[] = [],
  runtimeReloadPlanRows: ExecutionAdapterRuntimeReloadPlanRow[] = [],
  runtimeReloadExecutionRows: ExecutionAdapterRuntimeReloadExecutionRow[] = [],
  runtimeReloadAcceptanceRows: ExecutionAdapterRuntimeReloadAcceptanceRow[] = [],
  humanConfirmationRows: ExecutionAdapterHumanConfirmationRow[] = [],
  sandboxProbeExecutionRows: ExecutionAdapterSandboxProbeExecutionRow[] = [],
  adapterPaperExecutionRows: ExecutionAdapterPaperExecutionRow[] = [],
  sandboxProbeReviewRows: ExecutionAdapterSandboxProbeReviewRow[] = [],
  productionRouteReviewRows: ExecutionAdapterProductionRouteReviewRow[] = [],
  sandboxOrderSchemaDryRunRows: ExecutionAdapterSandboxOrderSchemaDryRunRow[] = [],
  paperOrderLifecycleRows: ExecutionAdapterPaperOrderLifecycleRow[] = [],
  paperRouteRunbookRows: ExecutionAdapterPaperRouteRunbookRow[] = [],
  adapterOpsStateRows: ExecutionAdapterOpsStateRow[] = []
): PromotionReadiness {
  const approval = buildRiskApprovalSummary(workspace);
  const auditBinding = buildResearchRunContextBinding(workspace);
  const run = auditBinding.canUseRun ? workspace.researchRun : null;
  const activeExecution = run && execution?.runId === run.runId ? execution : null;
  const filledOrders = activeExecution?.orders.filter((order) => order.status === "filled") ?? [];
  const paperRiskGate = activeExecution?.gates.find((gate) => gate.id === "paper-risk-check");
  const paperExecutionPassed = filledOrders.length > 0 && paperRiskGate?.passed === true;
  const adapterGatePassed = workspace.execution.gates.find((gate) => gate.id === "adapter-certified")?.passed === true;
  const latestCertification = latestPromotionCertificationRow(workspace, certificationRows);
  const latestCertificationApply = latestPromotionCertificationApplyRow(workspace, certificationApplyRows, latestCertification);
  const latestRestartEvidence = latestPromotionControlledRestartEvidenceRow(
    workspace,
    controlledRestartEvidenceRows,
    latestCertification,
    latestCertificationApply
  );
  const latestRestartAcceptance = latestPromotionRestartAcceptanceRow(
    workspace,
    restartAcceptanceRows,
    latestCertification,
    latestCertificationApply,
    latestRestartEvidence
  );
  const latestSecretReference = latestPromotionSecretReferenceRow(workspace, secretReferenceRows);
  const latestSecretMaterialization = latestPromotionSecretMaterializationRow(
    workspace,
    secretMaterializationRows,
    latestSecretReference
  );
  const latestEnvironmentBinding = latestPromotionEnvironmentBindingRow(
    workspace,
    environmentBindingRows,
    latestSecretMaterialization
  );
  const latestRuntimeReloadPlan = latestPromotionRuntimeReloadPlanRow(
    workspace,
    runtimeReloadPlanRows,
    latestSecretMaterialization,
    latestEnvironmentBinding
  );
  const latestRuntimeReloadExecution = latestPromotionRuntimeReloadExecutionRow(
    workspace,
    runtimeReloadExecutionRows,
    latestSecretMaterialization,
    latestEnvironmentBinding,
    latestRuntimeReloadPlan
  );
  const latestRuntimeReloadAcceptance = latestPromotionRuntimeReloadAcceptanceRow(
    workspace,
    runtimeReloadAcceptanceRows,
    latestSecretMaterialization,
    latestEnvironmentBinding,
    latestRuntimeReloadPlan,
    latestRuntimeReloadExecution
  );
  const latestHumanConfirmation = latestPromotionHumanConfirmationRow(workspace, humanConfirmationRows);
  const latestSandboxProbeExecution = latestPromotionSandboxProbeExecutionRow(
    workspace,
    sandboxProbeExecutionRows,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestSandboxProbeReview = latestPromotionSandboxProbeReviewRow(
    workspace,
    sandboxProbeReviewRows,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestProductionRouteReview = latestPromotionProductionRouteReviewRow(
    workspace,
    productionRouteReviewRows,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestSandboxOrderSchemaDryRun = latestPromotionSandboxOrderSchemaDryRunRow(
    workspace,
    sandboxOrderSchemaDryRunRows,
    latestProductionRouteReview,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestPaperOrderLifecycle = latestPromotionPaperOrderLifecycleRow(
    workspace,
    paperOrderLifecycleRows,
    latestSandboxOrderSchemaDryRun,
    latestProductionRouteReview,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestPaperRouteRunbook = latestPromotionPaperRouteRunbookRow(
    workspace,
    paperRouteRunbookRows,
    latestPaperOrderLifecycle,
    latestSandboxOrderSchemaDryRun,
    latestProductionRouteReview,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestAdapterOpsState = latestPromotionAdapterOpsStateRow(
    workspace,
    adapterOpsStateRows,
    latestPaperRouteRunbook,
    latestPaperOrderLifecycle,
    latestSandboxOrderSchemaDryRun,
    latestProductionRouteReview,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const latestAdapterPaperExecution = latestPromotionAdapterPaperExecutionRow(
    workspace,
    adapterPaperExecutionRows,
    latestAdapterOpsState,
    latestPaperRouteRunbook,
    latestPaperOrderLifecycle,
    latestSandboxOrderSchemaDryRun,
    latestProductionRouteReview,
    latestSandboxProbeReview,
    latestSandboxProbeExecution,
    latestHumanConfirmation,
    latestRuntimeReloadAcceptance,
    latestRuntimeReloadExecution,
    latestRuntimeReloadPlan,
    latestEnvironmentBinding,
    latestSecretMaterialization
  );
  const humanGatePassed =
    workspace.execution.gates.find((gate) => gate.id === "human-confirmed")?.passed === true ||
    latestHumanConfirmation?.status === "confirmation_recorded";
  const evidenceCertified =
    latestCertification?.status === "passed" && latestCertification.liveTradingAllowed && latestCertification.route === "live";
  const certifiedLiveAdapters = brokerRows.filter(
    (row) =>
      row.route === "live" &&
      row.status === "paper_ready" &&
      (!latestCertification || (row.id === latestCertification.adapterId && evidenceCertified))
  ).length;
  const liveAdapterCertified = adapterGatePassed && evidenceCertified && certifiedLiveAdapters > 0;

  const auditedStage: PromotionQueueStage = run
    ? {
        id: "audited-run",
        label: "Audited run",
        value: run.runId,
        detail: `${run.dataRows} ${run.timeframe} bars are bound to the promotion queue.`,
        status: "passed",
        tone: "positive"
      }
    : {
        id: "audited-run",
        label: "Audited run",
        value: auditBinding.status === "mismatched" ? (auditBinding.runId ?? "Stale audited run") : "No audited run",
        detail:
          auditBinding.status === "mismatched"
            ? auditBinding.detail
            : "Run Pipeline before a strategy can enter the promotion queue.",
        status: "blocked",
        tone: "risk"
      };

  const riskStage: PromotionQueueStage = {
    id: "risk-approval",
    label: "Risk approval",
    value:
      approval.status === "live_ready" ? "live approved" : approval.status === "paper_ready" ? "paper approved" : "risk blocked",
    detail: approval.summary,
    status: approval.status === "blocked" ? "blocked" : "passed",
    tone: approval.status === "blocked" ? "risk" : "positive"
  };

  const paperStage: PromotionQueueStage = paperExecutionPassed
    ? {
        id: "paper-execution",
        label: "Paper execution",
        value: filledOrders.length === 1 ? "1 filled order" : `${filledOrders.length} filled orders`,
        detail: `Paper snapshot ${activeExecution?.executionId} passed local risk checks before live promotion.`,
        status: "passed",
        tone: "positive"
      }
    : {
        id: "paper-execution",
        label: "Paper execution",
        value: "No paper fill",
        detail: activeExecution
          ? "Paper execution exists, but a filled order and passing risk check are both required."
          : "Submit a paper order from the active audited run before live promotion review.",
        status: "blocked",
        tone: "warning"
      };

  const adapterStage = buildPromotionAdapterCertificationStage(
    certifiedLiveAdapters,
    latestCertification,
    latestCertificationApply,
    latestRestartEvidence,
    latestRestartAcceptance,
    latestSecretReference,
    latestSecretMaterialization,
    latestEnvironmentBinding,
    latestRuntimeReloadPlan,
    latestRuntimeReloadExecution,
    latestRuntimeReloadAcceptance,
    latestSandboxProbeExecution,
    latestSandboxProbeReview,
      latestProductionRouteReview,
      latestSandboxOrderSchemaDryRun,
      latestPaperOrderLifecycle,
      latestPaperRouteRunbook,
      latestAdapterOpsState,
      latestAdapterPaperExecution,
      liveAdapterCertified,
    adapterGatePassed
  );

  const humanConfirmationValidationDetail = latestHumanConfirmation?.manifestValidationId
    ? ` · manifest ${latestHumanConfirmation.manifestValidationId}`
    : "";
  const humanStage: PromotionQueueStage = latestHumanConfirmation
    ? {
        id: "human-confirmation",
        label: "Human confirmation",
        value: `${latestHumanConfirmation.statusLabel} · ${latestHumanConfirmation.adapterId}`,
        detail: `Latest human confirmation ${latestHumanConfirmation.auditEventId}: ${latestHumanConfirmation.statusLabel} · ${latestHumanConfirmation.confirmationSummary} · ${latestHumanConfirmation.blockerSummary}${humanConfirmationValidationDetail} · ${latestHumanConfirmation.boundary}.`,
        status: latestHumanConfirmation.status === "confirmation_recorded" ? "passed" : "blocked",
        tone: latestHumanConfirmation.tone
      }
    : {
        id: "human-confirmation",
        label: "Human confirmation",
        value: humanGatePassed ? "manual approval recorded" : "manual approval required",
        detail: humanGatePassed
          ? "A human operator confirmed this promotion path."
          : "Live promotion requires explicit human confirmation after adapter certification.",
        status: humanGatePassed ? "passed" : "blocked",
        tone: humanGatePassed ? "positive" : "warning"
      };

  const stages = [auditedStage, riskStage, paperStage, adapterStage, humanStage];
  if (!run || approval.status === "blocked") {
    return {
      status: "blocked",
      headline: "Promotion queue blocked",
      summary: "A strategy needs audited evidence and risk approval before it can enter execution promotion.",
      stages
    };
  }
  if (!paperExecutionPassed) {
    return {
      status: "paper_pending",
      headline: "Paper execution required",
      summary: "The audited run is risk-approved for paper trading, but no filled paper execution is bound yet.",
      stages
    };
  }
  if (!liveAdapterCertified || !humanGatePassed) {
    return {
      status: "certification_pending",
      headline: "Live promotion pending certification",
      summary: "Paper execution has passed, but live routing stays blocked until adapter certification and human confirmation pass.",
      stages
    };
  }
  return {
    status: "live_ready",
    headline: "Live promotion ready",
    summary: "Audited evidence, paper execution, certified adapter, and human confirmation are all bound.",
    stages
  };
}

export function buildPreLiveReadinessChecklist(
  readiness: PromotionReadiness,
  input: PreLiveReadinessChecklistInput = {}
): PreLiveReadinessChecklist {
  const items: PreLiveReadinessChecklistItem[] = readiness.stages.map((stage) => ({
    id: stage.id,
    label: stage.label,
    state: stage.status,
    tone: stage.tone,
    evidence: stage.value,
    detail: stage.detail
  }));
  if (input.paperExecutionReplayGate) {
    items.push(buildPaperExecutionReplayChecklistItem(input.paperExecutionReplayGate));
  }
  const totalCount = items.length;
  const passedCount = items.filter((item) => item.state === "passed").length;
  const blockingCount = items.filter((item) => item.state !== "passed").length;
  const nextAction = items.find((item) => item.state !== "passed") ?? null;
  const adapterStage = items.find((item) => item.id === "adapter-certification");
  const humanStage = items.find((item) => item.id === "human-confirmation");
  const replayStage = items.find((item) => item.id === "paper-execution-replay");

  let status: PreLiveReadinessChecklistStatus;
  let tone: PreLiveReadinessChecklist["tone"];
  let headline: string;
  if (readiness.status === "live_ready" && blockingCount === 0) {
    status = "manual_route_ready";
    tone = "positive";
    headline = "Pre-live checklist complete";
  } else if (readiness.status === "paper_pending") {
    status = "paper_pending";
    tone = "warning";
    headline = "Pre-live paper evidence pending";
  } else if (replayStage && replayStage.state !== "passed" && passedCount > 0) {
    status = "evidence_pending";
    tone = "warning";
    headline = "Pre-live replay evidence pending";
  } else if (adapterStage?.state === "passed" && humanStage?.state !== "passed") {
    status = "operator_pending";
    tone = "warning";
    headline = "Pre-live operator confirmation pending";
  } else if (passedCount > 0) {
    status = "evidence_pending";
    tone = "warning";
    headline = "Pre-live evidence pending";
  } else {
    status = "blocked";
    tone = "risk";
    headline = "Pre-live readiness blocked";
  }

  const nextActionLabel = nextAction ? `${nextAction.id}: ${nextAction.evidence}` : "manual route review only";
  const summary =
    status === "manual_route_ready"
      ? `${passedCount}/${totalCount} gates passed; ready for manual route review only. Direct order submission remains disabled.`
      : `${passedCount}/${totalCount} gates passed; next action ${nextActionLabel}. Direct order submission remains disabled.`;

  return {
    status,
    tone,
    headline,
    summary,
    passedCount,
    totalCount,
    blockingCount,
    nextActionId: nextAction?.id ?? null,
    manualRouteCandidate: status === "manual_route_ready",
    orderSubmissionEnabled: false,
    liveTradingAllowed: false,
    items
  };
}

function buildPaperExecutionReplayChecklistItem(gate: PaperExecutionReplayGate): PreLiveReadinessChecklistItem {
  const passed = gate.status === "replay_ready";
  const state: PromotionQueueStage["status"] = passed ? "passed" : gate.status === "partial" ? "review" : "blocked";
  const evidence =
    gate.status === "replay_ready"
      ? "Paper replay ready"
      : gate.status === "stale"
        ? "Paper replay stale"
        : gate.status === "partial"
          ? "Paper replay incomplete"
          : "Paper replay blocked";
  const latestEvidence = gate.latestEvidenceId ? ` Latest evidence: ${gate.latestEvidenceId}.` : "";
  return {
    id: "paper-execution-replay",
    label: "Paper execution replay",
    state,
    tone: gate.tone === "positive" ? "positive" : gate.tone === "warning" ? "warning" : "risk",
    evidence,
    detail: `${gate.detail} Replay checks ${gate.passedCount}/${gate.totalCount}.${latestEvidence}`
  };
}

export function buildOperatorRunbookSummary(input: OperatorRunbookInput): OperatorRunbookSummary {
  const chainRollups = input.adapterChainHealthRollups ?? [];
  const primaryChain =
    chainRollups.find((rollup) => rollup.status === "paper_ready") ??
    chainRollups.find((rollup) => rollup.status === "blocked") ??
    chainRollups[0] ??
    null;
  const adapterId = primaryChain?.adapterId ?? input.p2PreLiveAcceptance.adapterId ?? "adapter-unselected";
  const contextLabel = [
    input.workspace.selectedInstrument.market,
    input.workspace.selectedInstrument.symbol,
    input.workspace.selectedTimeframe
  ].join(" ");
  const controls: OperatorRunbookControls = {
    killSwitch: input.killSwitch?.trim() || "Disable execution route and keep adapters in paper-only mode",
    rollbackOwner: input.rollbackOwner?.trim() || "operator",
    positionLimit: `${Math.max(0, input.maxPositionPct ?? 20)}% max position per instrument`,
    dataFreshness: operatorRunbookDataFreshness(input.workspace),
    auditPackage: input.p2PreLiveAcceptance.sourcePath || "data/p2-pre-live-acceptance.json",
    environmentState: operatorRunbookEnvironmentState(primaryChain)
  };
  const sections: OperatorRunbookSection[] = [
    operatorRunbookChecklistSection(input.preLiveChecklist),
    operatorRunbookReplaySection(input.paperExecutionReplayGate),
    operatorRunbookAdapterChainSection(primaryChain),
    operatorRunbookP2AcceptanceSection(input.p2PreLiveAcceptance),
    operatorRunbookSafetyBoundarySection(input)
  ];
  const completedSections = sections.filter((section) => section.status === "passed").length;
  const blocker = sections.find((section) => section.status === "blocked") ?? null;
  const review = sections.find((section) => section.status === "review") ?? null;
  const next = blocker ?? review;
  const status: OperatorRunbookStatus = blocker ? "blocked" : review ? "review_pending" : "manual_review_ready";
  const tone: OperatorRunbookTone = status === "manual_review_ready" ? "positive" : status === "review_pending" ? "warning" : "risk";

  return {
    status,
    tone,
    headline:
      status === "manual_review_ready"
        ? "Operator runbook ready for manual review"
        : status === "review_pending"
          ? "Operator runbook pending review"
          : "Operator runbook blocked",
    summary:
      status === "manual_review_ready"
        ? "All operator runbook sections are aligned for manual pre-live review only; live trading remains blocked."
        : `${completedSections}/${sections.length} operator runbook sections passed; ${next?.label ?? "operator review"} is next.`,
    contextLabel,
    adapterId,
    completedSections,
    totalSections: sections.length,
    nextActionId: next?.id ?? null,
    nextAction: next ? `Resolve ${next.label}: ${next.nextAction}` : "Record or review the operator runbook before any separate live-route enablement.",
    controls,
    sections,
    orderSubmissionEnabled: false,
    liveTradingAllowed: false,
    liveOrderSubmitted: false,
    routeExecuted: false
  };
}

export function buildOperatorRunbookMarkdown(runbook: OperatorRunbookSummary): string {
  const lines = [
    "# Operator Runbook",
    "",
    `Status: ${runbook.status}`,
    `Context: ${runbook.contextLabel}`,
    `Adapter: ${runbook.adapterId}`,
    `Progress: ${runbook.completedSections}/${runbook.totalSections}`,
    `Next action: ${runbook.nextAction}`,
    "",
    "## Controls",
    `- Kill switch: ${runbook.controls.killSwitch}`,
    `- Rollback owner: ${runbook.controls.rollbackOwner}`,
    `- Position limit: ${runbook.controls.positionLimit}`,
    `- Data freshness: ${runbook.controls.dataFreshness}`,
    `- Environment state: ${runbook.controls.environmentState}`,
    `- Audit package: ${runbook.controls.auditPackage}`,
    "",
    "## Safety Boundary",
    `- orderSubmissionEnabled=${runbook.orderSubmissionEnabled}`,
    `- liveTradingAllowed=${runbook.liveTradingAllowed}`,
    `- liveOrderSubmitted=${runbook.liveOrderSubmitted}`,
    `- routeExecuted=${runbook.routeExecuted}`,
    "",
    "## Sections",
    ...runbook.sections.flatMap((section) => [
      `- ${section.id}: ${section.status} · ${section.evidence}`,
      `  - ${section.detail}`,
      `  - Next: ${section.nextAction}`
    ])
  ];
  return lines.join("\n");
}

function operatorRunbookChecklistSection(checklist: PreLiveReadinessChecklist): OperatorRunbookSection {
  const passed = checklist.status === "manual_route_ready" && checklist.manualRouteCandidate && checklist.blockingCount === 0;
  const status: OperatorRunbookSectionStatus = passed ? "passed" : checklist.passedCount > 0 ? "review" : "blocked";
  return {
    id: "pre-live-checklist",
    label: "Pre-live checklist",
    status,
    evidence: `${checklist.passedCount}/${checklist.totalCount} gates`,
    detail: checklist.summary,
    nextAction: checklist.nextActionId ? `Complete ${checklist.nextActionId}` : "Keep checklist evidence attached to the runbook.",
    tone: operatorRunbookSectionTone(status)
  };
}

function operatorRunbookReplaySection(gate: PaperExecutionReplayGate): OperatorRunbookSection {
  const status: OperatorRunbookSectionStatus =
    gate.status === "replay_ready" ? "passed" : gate.status === "partial" ? "review" : "blocked";
  return {
    id: "paper-execution-replay",
    label: "Paper execution replay",
    status,
    evidence: `${gate.passedCount}/${gate.totalCount} replay checks`,
    detail: gate.detail,
    nextAction: gate.currentBlockerLabel ? `Resolve ${gate.currentBlockerLabel}` : "Keep replay evidence aligned with the current run.",
    tone: operatorRunbookSectionTone(status)
  };
}

function operatorRunbookAdapterChainSection(
  chain: ExecutionAdapterChainHealthRollup | null
): OperatorRunbookSection {
  if (!chain) {
    return {
      id: "adapter-chain",
      label: "Adapter chain",
      status: "blocked",
      evidence: "no adapter chain",
      detail: "No adapter chain health rollup is available.",
      nextAction: "Record adapter chain evidence from secret reference through paper execution.",
      tone: "risk"
    };
  }
  const status: OperatorRunbookSectionStatus =
    chain.status === "paper_ready" ? "passed" : chain.status === "in_progress" ? "review" : "blocked";
  return {
    id: "adapter-chain",
    label: "Adapter chain",
    status,
    evidence: `${chain.completedStageCount}/${chain.totalStageCount} stages`,
    detail: chain.detail,
    nextAction: chain.blockerLabel ? `Resolve ${chain.blockerLabel}` : "Keep adapter chain evidence available for audit.",
    tone: operatorRunbookSectionTone(status)
  };
}

function operatorRunbookP2AcceptanceSection(acceptance: P2PreLiveAcceptanceSummary): OperatorRunbookSection {
  const unsafe =
    acceptance.reportedOrderSubmissionEnabled ||
    acceptance.reportedLiveTradingAllowed ||
    acceptance.reportedLiveOrderSubmitted ||
    acceptance.reportedRouteExecuted ||
    !acceptance.liveBlockedBoundary;
  const status: OperatorRunbookSectionStatus = acceptance.state === "passed" && !unsafe ? "passed" : "blocked";
  return {
    id: "p2-acceptance",
    label: "P2 acceptance",
    status,
    evidence: acceptance.state,
    detail: acceptance.detail,
    nextAction: status === "passed" ? "Keep acceptance manifest linked to this operator runbook." : acceptance.actionLabel,
    tone: operatorRunbookSectionTone(status)
  };
}

function operatorRunbookSafetyBoundarySection(input: OperatorRunbookInput): OperatorRunbookSection {
  const chainUnsafe = (input.adapterChainHealthRollups ?? []).some(
    (rollup) => rollup.orderSubmissionEnabled || rollup.liveTradingAllowed
  );
  const unsafe =
    input.preLiveChecklist.orderSubmissionEnabled ||
    input.preLiveChecklist.liveTradingAllowed ||
    input.paperExecutionReplayGate.orderSubmissionEnabled ||
    input.paperExecutionReplayGate.liveTradingAllowed ||
    input.p2PreLiveAcceptance.reportedOrderSubmissionEnabled ||
    input.p2PreLiveAcceptance.reportedLiveTradingAllowed ||
    input.p2PreLiveAcceptance.reportedLiveOrderSubmitted ||
    input.p2PreLiveAcceptance.reportedRouteExecuted ||
    (input.p2PreLiveAcceptance.state !== "missing" && !input.p2PreLiveAcceptance.liveBlockedBoundary) ||
    chainUnsafe;
  return {
    id: "safety-boundary",
    label: "Safety boundary",
    status: unsafe ? "blocked" : "passed",
    evidence: unsafe ? "unsafe claim detected" : "live blocked",
    detail: unsafe
      ? "One or more inputs claim order submission, route execution, or live trading is enabled."
      : "Order submission, live orders, route execution, and live trading remain disabled.",
    nextAction: unsafe ? "Remove unsafe execution claims before operator review." : "Do not enable live routes in P2.",
    tone: unsafe ? "risk" : "positive"
  };
}

function operatorRunbookSectionTone(status: OperatorRunbookSectionStatus): OperatorRunbookTone {
  if (status === "passed") {
    return "positive";
  }
  return status === "review" ? "warning" : "risk";
}

function operatorRunbookDataFreshness(workspace: TerminalWorkspace): string {
  const quality = workspace.researchRun?.dataQuality;
  if (!quality) {
    return workspace.researchRun
      ? `${workspace.researchRun.dataRows.toLocaleString("en-US")} rows · freshness not audited`
      : "No audited research data freshness evidence";
  }
  return `${quality.source} · ${quality.rows.toLocaleString("en-US")} rows · ${
    quality.isComplete ? "complete" : "review"
  }`;
}

function operatorRunbookEnvironmentState(chain: ExecutionAdapterChainHealthRollup | null): string {
  if (!chain) {
    return "adapter chain missing";
  }
  return `${chain.adapterId} · ${chain.status} · live blocked`;
}

export function buildStrategyRuleRows(workspace: TerminalWorkspace): StrategyRuleRow[] {
  const draft = buildStrategyRuleDraft(workspace);
  return [
    {
      id: "entry-rule",
      group: "entry",
      label: "Entry signal",
      condition: workspace.strategy.entry,
      parameter: strategyEntryParameter(workspace.strategy.entry, draft.entryWindow),
      status: isPendingStrategyText(workspace.strategy.entry) ? "pending" : "active",
      tone: isPendingStrategyText(workspace.strategy.entry) ? "warning" : "positive"
    },
    {
      id: "exit-rule",
      group: "exit",
      label: "Exit signal",
      condition: workspace.strategy.exit,
      parameter: strategyExitParameter(workspace.strategy.exit, draft.exitWindow),
      status: isPendingStrategyText(workspace.strategy.exit) ? "pending" : "active",
      tone: "warning"
    },
    {
      id: "position-rule",
      group: "position",
      label: "Position sizing",
      condition: workspace.strategy.position,
      parameter: `${formatPercentValue(draft.positionPct)}% exposure cap`,
      status: isPendingStrategyText(workspace.strategy.position) ? "pending" : "active",
      tone: isPendingStrategyText(workspace.strategy.position) ? "warning" : "neutral"
    },
    {
      id: "risk-rule",
      group: "risk",
      label: "Risk guardrail",
      condition: workspace.strategy.risk,
      parameter: "Stop / take profit / drawdown / execution mode",
      status: "guardrail",
      tone: "risk"
    }
  ];
}

export function buildStrategyReadinessGates(workspace: TerminalWorkspace): StrategyReadinessGate[] {
  const draft = buildStrategyRuleDraft(workspace);
  const schemaIsReady =
    !isPendingStrategyText(workspace.strategy.entry) &&
    !isPendingStrategyText(workspace.strategy.exit) &&
    draft.entryWindow > 0 &&
    draft.exitWindow > 0;
  const riskIsReady =
    !isPendingStrategyText(workspace.strategy.position) &&
    !isPendingStrategyText(workspace.strategy.risk) &&
    draft.positionPct > 0 &&
    draft.stopLossPct > 0 &&
    draft.takeProfitPct > 0 &&
    draft.maxDrawdownPct > 0;
  const auditBinding = buildResearchRunContextBinding(workspace);
  const hasBlockedGate = !schemaIsReady || !riskIsReady;

  return [
    schemaIsReady
      ? {
          id: "schema",
          label: "Strategy schema",
          value: `${strategyEntryParameter(workspace.strategy.entry, draft.entryWindow)} / ${strategyExitParameter(
            workspace.strategy.exit,
            draft.exitWindow
          )}`,
          detail: "Entry and exit conditions are structured.",
          status: "passed",
          tone: "positive"
        }
      : {
          id: "schema",
          label: "Strategy schema",
          value: "pending",
          detail: "Structured entry and exit rules are required before audit.",
          status: "blocked",
          tone: "risk"
        },
    riskIsReady
      ? {
          id: "risk",
          label: "Risk controls",
          value: [
            `${formatPercentValue(draft.positionPct)}%`,
            `${formatPercentValue(draft.stopLossPct)}%`,
            `${formatPercentValue(draft.takeProfitPct)}%`,
            `${formatPercentValue(draft.maxDrawdownPct)}%`
          ].join(" / "),
          detail: "Position, stop, take profit, and drawdown guards are parseable.",
          status: "passed",
          tone: "positive"
        }
      : {
          id: "risk",
          label: "Risk controls",
          value: "pending",
          detail: "Position sizing and risk guardrails must be explicit.",
          status: "blocked",
          tone: "risk"
        },
    {
      id: "execution",
      label: "Execution mode",
      value: draft.paperOnly ? "paper only" : "live gated",
      detail: "Live routing stays blocked until adapter, risk, and human gates pass.",
      status: draft.paperOnly ? "passed" : "review",
      tone: draft.paperOnly ? "positive" : "warning"
    },
    auditBinding.status === "matched"
      ? {
          id: "audit",
          label: "Audit evidence",
          value: auditBinding.runId ?? "bound",
          detail: auditBinding.detail,
          status: "passed",
          tone: "positive"
        }
      : auditBinding.status === "mismatched"
        ? {
            id: "audit",
            label: "Audit evidence",
            value: auditBinding.runId ?? "stale run",
            detail: auditBinding.detail,
            status: "blocked",
            tone: "risk"
          }
      : {
          id: "audit",
          label: "Audit evidence",
          value: hasBlockedGate ? "blocked" : "needs run",
          detail: hasBlockedGate
            ? "Fix blocked gates before running an audit pipeline."
            : "Run Pipeline to bind this draft to a reproducible audit run.",
          status: hasBlockedGate ? "blocked" : "review",
          tone: hasBlockedGate ? "risk" : "warning"
        }
  ];
}

export function mergeStrategyReadinessGatesWithLocalAudit(
  coreGates: StrategyReadinessGate[] | null | undefined,
  localGates: StrategyReadinessGate[]
): StrategyReadinessGate[] {
  if (!coreGates) {
    return localGates;
  }
  const localAuditGate = localGates.find((gate) => gate.id === "audit");
  if (!localAuditGate) {
    return coreGates;
  }
  const merged = coreGates.map((gate) => (gate.id === "audit" ? localAuditGate : gate));
  if (!merged.some((gate) => gate.id === "audit")) {
    merged.push(localAuditGate);
  }
  return merged;
}

export function buildStrategyVersionDiffRows(
  workspace: TerminalWorkspace,
  item: StrategyLibraryDraftItem
): StrategyVersionDiffRow[] {
  const rows: Array<{ id: StrategyVersionDiffRow["id"]; label: string; current: string; saved: string }> = [
    {
      id: "context",
      label: "Context",
      current: strategyContextLabel(
        workspace.selectedInstrument.market,
        workspace.selectedInstrument.symbol,
        workspace.selectedTimeframe
      ),
      saved: strategyContextLabel(item.market, item.symbol, item.timeframe)
    },
    {
      id: "name",
      label: "Name",
      current: workspace.strategy.name,
      saved: item.strategySnapshot.name
    },
    {
      id: "entry",
      label: "Entry",
      current: workspace.strategy.entry,
      saved: item.strategySnapshot.entry
    },
    {
      id: "exit",
      label: "Exit",
      current: workspace.strategy.exit,
      saved: item.strategySnapshot.exit
    },
    {
      id: "position",
      label: "Position",
      current: workspace.strategy.position,
      saved: item.strategySnapshot.position
    },
    {
      id: "risk",
      label: "Risk",
      current: workspace.strategy.risk,
      saved: item.strategySnapshot.risk
    }
  ];

  return rows.map((row) => {
    const changed = normalizeDiffValue(row.current) !== normalizeDiffValue(row.saved);
    return {
      ...row,
      changed,
      tone: changed ? "warning" : "neutral"
    };
  });
}

export function buildStrategyGovernanceQueueRows({
  workspace,
  library = [],
  runHistory = []
}: {
  workspace: TerminalWorkspace;
  library?: StrategyLibraryDraftItem[];
  runHistory?: ResearchRunAudit[];
}): StrategyGovernanceQueue {
  const currentContextLabel = strategyContextLabel(
    workspace.selectedInstrument.market,
    workspace.selectedInstrument.symbol,
    workspace.selectedTimeframe
  );
  const currentValidation = buildStrategyGovernanceValidation(workspace, workspace.strategy);
  const currentAuditBinding = buildResearchRunContextBinding(workspace);
  const currentDraftRow: StrategyGovernanceQueueRow = {
    id: "current-draft",
    name: workspace.strategy.name,
    revision: "current-draft",
    market: workspace.selectedInstrument.market,
    symbol: workspace.selectedInstrument.symbol,
    timeframe: workspace.selectedTimeframe,
    status: "current",
    stage: "current_draft",
    tone: currentValidation.validationStatus === "blocked" ? "risk" : "neutral",
    contextLabel: currentContextLabel,
    contextMismatch: false,
    importProvenance: currentContextLabel,
    validationStatus: currentValidation.validationStatus,
    validationDetail: currentValidation.validationDetail,
    auditRunId: currentAuditBinding.runId,
    latestAuditRunId: currentAuditBinding.status === "matched" ? currentAuditBinding.runId : null,
    changedFieldCount: 0,
    changedFields: [],
    nextActionId: "save-current-version",
    nextActionLabel: "Save current version",
    detail:
      currentAuditBinding.status === "matched"
        ? `Current draft is bound to audit run ${currentAuditBinding.runId}.`
        : currentValidation.validationDetail
  };
  const rows = [
    currentDraftRow,
    ...library.map((item) => buildStrategyGovernanceLibraryRow(workspace, item, runHistory))
  ].sort(strategyGovernanceQueueSort);

  return {
    rows,
    summary: buildStrategyGovernanceQueueSummary(rows)
  };
}

function buildStrategyGovernanceLibraryRow(
  workspace: TerminalWorkspace,
  item: StrategyLibraryDraftItem,
  runHistory: ResearchRunAudit[]
): StrategyGovernanceQueueRow {
  const diffRows = buildStrategyVersionDiffRows(workspace, item);
  const changedFields = diffRows.filter((row) => row.changed).map((row) => row.id);
  const contextMismatch =
    item.market !== workspace.selectedInstrument.market ||
    item.symbol !== workspace.selectedInstrument.symbol ||
    item.timeframe !== workspace.selectedTimeframe;
  const validation = buildStrategyGovernanceValidation(workspace, item.strategySnapshot, item);
  const latestAuditRunId = latestStrategyAuditRunId(item, runHistory);
  const stage = strategyGovernanceStage({
    changedFieldCount: changedFields.length,
    contextMismatch,
    item,
    latestAuditRunId,
    validationStatus: validation.validationStatus
  });
  const nextActionId = strategyGovernanceActionId(stage);
  const contextLabel = strategyContextLabel(item.market, item.symbol, item.timeframe);

  return {
    id: item.revision,
    name: item.name,
    revision: item.revision,
    market: item.market,
    symbol: item.symbol,
    timeframe: item.timeframe,
    status: item.status,
    stage,
    tone: strategyGovernanceTone(stage),
    contextLabel,
    contextMismatch,
    importProvenance: contextLabel,
    validationStatus: validation.validationStatus,
    validationDetail: validation.validationDetail,
    auditRunId: item.auditRunId ?? null,
    latestAuditRunId,
    changedFieldCount: changedFields.length,
    changedFields,
    nextActionId,
    nextActionLabel: strategyGovernanceActionLabel(nextActionId),
    detail: strategyGovernanceDetail({
      changedFields,
      contextLabel,
      item,
      latestAuditRunId,
      stage,
      validationDetail: validation.validationDetail
    })
  };
}

function buildStrategyGovernanceValidation(
  workspace: TerminalWorkspace,
  strategySnapshot: StrategySnapshot,
  item?: StrategyLibraryDraftItem
): Pick<StrategyGovernanceQueueRow, "validationStatus" | "validationDetail"> {
  const validationWorkspace: TerminalWorkspace = {
    ...workspace,
    selectedInstrument: {
      ...workspace.selectedInstrument,
      market: item?.market ?? workspace.selectedInstrument.market,
      symbol: item?.symbol ?? workspace.selectedInstrument.symbol,
      name: item?.name ?? workspace.selectedInstrument.name
    },
    selectedTimeframe: item?.timeframe ?? workspace.selectedTimeframe,
    strategy: strategySnapshot,
    researchRun: null
  };
  const gates = buildStrategyReadinessGates(validationWorkspace).filter((gate) => gate.id !== "audit");
  const blocked = gates.filter((gate) => gate.status === "blocked");
  if (blocked.length) {
    return {
      validationStatus: "blocked",
      validationDetail: blocked.map((gate) => `${gate.label}: ${gate.detail}`).join(" · ")
    };
  }
  const review = gates.filter((gate) => gate.status === "review");
  if (review.length) {
    return {
      validationStatus: "review",
      validationDetail: review.map((gate) => `${gate.label}: ${gate.detail}`).join(" · ")
    };
  }
  return {
    validationStatus: "ready",
    validationDetail: "Strategy schema, risk controls, and paper-only execution mode are ready."
  };
}

function latestStrategyAuditRunId(item: StrategyLibraryDraftItem, runHistory: ResearchRunAudit[]): string | null {
  const matchingRuns = runHistory
    .filter(
      (run) =>
        run.market === item.market &&
        run.symbol === item.symbol &&
        run.timeframe === item.timeframe &&
        run.strategyRevision === item.revision
    )
    .sort((left, right) => Date.parse(right.createdAt) - Date.parse(left.createdAt));
  return matchingRuns[0]?.runId ?? item.auditRunId ?? null;
}

function strategyGovernanceStage({
  changedFieldCount,
  contextMismatch,
  item,
  latestAuditRunId,
  validationStatus
}: {
  changedFieldCount: number;
  contextMismatch: boolean;
  item: StrategyLibraryDraftItem;
  latestAuditRunId: string | null;
  validationStatus: StrategyGovernanceQueueRow["validationStatus"];
}): StrategyGovernanceQueueStage {
  if (validationStatus === "blocked") {
    return "blocked";
  }
  if (contextMismatch) {
    return "imported";
  }
  if (changedFieldCount > 0) {
    return "stale";
  }
  if (item.status === "audited" && latestAuditRunId) {
    return "audited";
  }
  return "needs_reaudit";
}

function strategyGovernanceActionId(stage: StrategyGovernanceQueueStage): StrategyGovernanceQueueActionId {
  if (stage === "stale" || stage === "needs_reaudit") {
    return "load-and-rerun";
  }
  return "load-version";
}

function strategyGovernanceActionLabel(actionId: StrategyGovernanceQueueActionId): string {
  if (actionId === "save-current-version") {
    return "Save current version";
  }
  if (actionId === "load-and-rerun") {
    return "Load and rerun audit";
  }
  return "Load version";
}

function strategyGovernanceTone(stage: StrategyGovernanceQueueStage): StrategyGovernanceQueueRow["tone"] {
  if (stage === "audited") {
    return "positive";
  }
  if (stage === "blocked") {
    return "risk";
  }
  if (stage === "current_draft" || stage === "imported") {
    return "neutral";
  }
  return "warning";
}

function strategyGovernanceDetail({
  changedFields,
  contextLabel,
  item,
  latestAuditRunId,
  stage,
  validationDetail
}: {
  changedFields: StrategyVersionDiffRow["id"][];
  contextLabel: string;
  item: StrategyLibraryDraftItem;
  latestAuditRunId: string | null;
  stage: StrategyGovernanceQueueStage;
  validationDetail: string;
}): string {
  if (stage === "blocked") {
    return validationDetail;
  }
  if (stage === "imported") {
    return `Saved for ${contextLabel}; load as a cross-context draft before auditing in this workspace.`;
  }
  if (stage === "stale") {
    return `Current context changed in ${changedFields.join(", ")}; load this version and rerun an audit.`;
  }
  if (stage === "audited") {
    return `Audited version is backed by ${latestAuditRunId ?? item.auditRunId}.`;
  }
  return "Saved draft is valid but has no current audit evidence; load it and rerun the pipeline.";
}

function buildStrategyGovernanceQueueSummary(
  rows: StrategyGovernanceQueueRow[]
): StrategyGovernanceQueueSummary {
  return {
    totalRows: rows.length,
    currentDraftCount: rows.filter((row) => row.stage === "current_draft").length,
    auditedCount: rows.filter((row) => row.stage === "audited").length,
    importedCount: rows.filter((row) => row.stage === "imported").length,
    staleCount: rows.filter((row) => row.stage === "stale").length,
    needsReauditCount: rows.filter((row) => row.stage === "needs_reaudit").length,
    blockedCount: rows.filter((row) => row.stage === "blocked").length
  };
}

function strategyGovernanceQueueSort(left: StrategyGovernanceQueueRow, right: StrategyGovernanceQueueRow): number {
  const rank: Record<StrategyGovernanceQueueStage, number> = {
    current_draft: 0,
    blocked: 1,
    needs_reaudit: 2,
    stale: 3,
    audited: 4,
    imported: 5
  };
  const rankDelta = rank[left.stage] - rank[right.stage];
  if (rankDelta !== 0) {
    return rankDelta;
  }
  return left.revision.localeCompare(right.revision);
}

export function buildStrategyRuleDraft(workspace: TerminalWorkspace): StrategyRuleDraft {
  const strategy = workspace.strategy;
  const entryRsiCondition = inferRsiCondition(strategy.entry);
  const exitRsiCondition = inferRsiCondition(strategy.exit);
  const entryVolumeWindow = inferVolumeWindow(strategy.entry);
  const hasEntrySmaCondition = hasSmaConditionText(strategy.entry);
  const isPrimaryEntryRsi = Boolean(entryRsiCondition && !hasEntrySmaCondition);
  const entryWindow = isPrimaryEntryRsi
    ? entryRsiCondition?.window ?? defaultStrategyRuleDraft.entryWindow
    : inferSmaWindow(strategy.entry, defaultStrategyRuleDraft.entryWindow);
  const exitWindow = exitRsiCondition?.window ?? inferSmaWindow(strategy.exit, defaultStrategyRuleDraft.exitWindow);

  return {
    name: strategy.name.trim() || defaultStrategyRuleDraft.name,
    entryKind: isPrimaryEntryRsi && entryRsiCondition
      ? rsiOperatorToConditionKind(entryRsiCondition.operator)
      : inferSmaConditionKind(strategy.entry, "close_above_sma"),
    entryWindow,
    entryThreshold: isPrimaryEntryRsi
      ? entryRsiCondition?.threshold ?? defaultStrategyRuleDraft.entryThreshold
      : defaultStrategyRuleDraft.entryThreshold,
    entryRsiConfirm: Boolean(entryRsiCondition && !isPrimaryEntryRsi),
    entryRsiWindow: entryRsiCondition?.window ?? defaultStrategyRuleDraft.entryRsiWindow,
    entryRsiThreshold: entryRsiCondition?.threshold ?? defaultStrategyRuleDraft.entryRsiThreshold,
    entryVolumeConfirm: entryVolumeWindow !== null,
    entryVolumeWindow: entryVolumeWindow ?? defaultStrategyRuleDraft.entryVolumeWindow,
    exitKind: exitRsiCondition
      ? rsiOperatorToConditionKind(exitRsiCondition.operator)
      : inferSmaConditionKind(strategy.exit, "close_below_sma"),
    exitWindow,
    exitThreshold: exitRsiCondition?.threshold ?? defaultStrategyRuleDraft.exitThreshold,
    positionPct: inferPercent(strategy.position, defaultStrategyRuleDraft.positionPct),
    stopLossPct: inferPercentNearKeywords(strategy.risk, ["stop", "止损"], defaultStrategyRuleDraft.stopLossPct),
    takeProfitPct: inferPercentNearKeywords(
      strategy.risk,
      ["take profit", "take-profit", "止盈"],
      defaultStrategyRuleDraft.takeProfitPct
    ),
    maxDrawdownPct: inferPercentNearKeywords(
      strategy.risk,
      ["drawdown", "回撤"],
      defaultStrategyRuleDraft.maxDrawdownPct
    ),
    paperOnly: !/\blive\b|实盘/u.test(strategy.risk.toLowerCase()) || /paper only|模拟/u.test(strategy.risk.toLowerCase())
  };
}

export function buildStrategyTemplateOptions(): StrategyTemplateOption[] {
  return strategyTemplateOptions.map((template) => ({
    ...template,
    draft: { ...template.draft }
  }));
}

function strategyContextLabel(market: Market, symbol: string, timeframe: Timeframe): string {
  return `${market.toUpperCase()} · ${symbol} · ${timeframe}`;
}

export function buildResearchRunContextBinding(workspace: TerminalWorkspace): ResearchRunContextBinding {
  const selectedContext = strategyContextLabel(
    workspace.selectedInstrument.market,
    workspace.selectedInstrument.symbol,
    workspace.selectedTimeframe
  );
  const run = workspace.researchRun;

  if (!run) {
    return {
      status: "missing",
      canUseRun: false,
      runId: null,
      selectedContext,
      runContext: null,
      detail: "Run Pipeline to bind a matching audited research run."
    };
  }

  const runMarket = run.market ?? workspace.selectedInstrument.market;
  const runSymbol = run.symbol ?? workspace.selectedInstrument.symbol;
  const runContext = strategyContextLabel(runMarket, runSymbol, run.timeframe);
  const matches =
    runMarket === workspace.selectedInstrument.market &&
    runSymbol === workspace.selectedInstrument.symbol &&
    run.timeframe === workspace.selectedTimeframe;

  if (matches) {
    return {
      status: "matched",
      canUseRun: true,
      runId: run.runId,
      selectedContext,
      runContext,
      detail: `Audited run ${run.runId} matches the selected research context.`
    };
  }

  return {
    status: "mismatched",
    canUseRun: false,
    runId: run.runId,
    selectedContext,
    runContext,
    detail: `Audited run ${run.runId} belongs to ${runContext}, not ${selectedContext}.`
  };
}

function normalizeDiffValue(value: string): string {
  return value.trim().replace(/\s+/g, " ");
}

export function strategySnapshotFromRuleDraft(draft: StrategyRuleDraft): StrategySnapshot {
  const normalizedDraft = normalizeStrategyRuleDraft(draft);
  const entrySignal = strategyConditionSnapshotText(
    normalizedDraft.entryKind,
    normalizedDraft.entryWindow,
    normalizedDraft.entryThreshold
  );
  const entrySignals = [entrySignal];
  if (normalizedDraft.entryRsiConfirm && !isRsiConditionKind(normalizedDraft.entryKind)) {
    entrySignals.push(`RSI${normalizedDraft.entryRsiWindow} > ${formatConditionNumber(normalizedDraft.entryRsiThreshold)}`);
  }
  if (normalizedDraft.entryVolumeConfirm) {
    entrySignals.push(`Volume > VOL${normalizedDraft.entryVolumeWindow}`);
  }
  return {
    name: normalizedDraft.name,
    entry: entrySignals.join(" AND "),
    exit: strategyConditionSnapshotText(normalizedDraft.exitKind, normalizedDraft.exitWindow, normalizedDraft.exitThreshold),
    position: `${formatPercentValue(normalizedDraft.positionPct)}% max capital allocation`,
    risk: [
      `Stop -${formatPercentValue(normalizedDraft.stopLossPct)}%`,
      `take profit +${formatPercentValue(normalizedDraft.takeProfitPct)}%`,
      `drawdown guard ${formatPercentValue(normalizedDraft.maxDrawdownPct)}%`,
      normalizedDraft.paperOnly ? "paper only" : "live gated"
    ].join(", ")
  };
}

export function buildBacktestTradeRows(workspace: TerminalWorkspace): BacktestTradeRow[] {
  if (workspace.backtestTrades?.length) {
    return workspace.backtestTrades;
  }

  const price = resolvePaperOrderPrice(workspace);
  const quantity = calculatePaperQuantity(workspace.selectedInstrument.market, price);
  const returnMetric = metricValue(workspace, "Return", "N/A");
  const drawdownMetric = metricValue(workspace, "Max DD", "N/A");
  const exposure = inferExposureFromPosition(workspace.strategy.position);
  const entryTone: BacktestTradeRow["tone"] = returnMetric.startsWith("-") ? "warning" : "positive";

  return [
    {
      id: "entry-fill",
      timestamp: "T+0",
      symbol: workspace.selectedInstrument.symbol,
      side: "BUY",
      status: isPendingStrategyText(workspace.strategy.entry) ? "blocked" : "filled",
      price: price.toFixed(2),
      quantity: String(quantity),
      exposure,
      pnl: returnMetric,
      reason: workspace.strategy.entry,
      tone: isPendingStrategyText(workspace.strategy.entry) ? "warning" : entryTone
    },
    {
      id: "risk-review",
      timestamp: "T+1",
      symbol: workspace.selectedInstrument.symbol,
      side: "RISK",
      status: "review",
      price: "-",
      quantity: "-",
      exposure: "drawdown",
      pnl: normalizeDrawdownLoss(drawdownMetric),
      reason: workspace.strategy.risk,
      tone: "warning"
    },
    {
      id: "exit-review",
      timestamp: "T+2",
      symbol: workspace.selectedInstrument.symbol,
      side: "SELL",
      status: isPendingStrategyText(workspace.strategy.exit) ? "blocked" : "open",
      price: price.toFixed(2),
      quantity: String(quantity),
      exposure,
      pnl: returnMetric,
      reason: workspace.strategy.exit,
      tone: "neutral"
    }
  ];
}

export function resolveBacktestAssumptions(workspace: TerminalWorkspace): BacktestAssumptions {
  return normalizeBacktestAssumptions(workspace.backtestAssumptions);
}

function normalizeBacktestAssumptions(current?: Partial<BacktestAssumptions>): BacktestAssumptions {
  const assumptions = current ?? defaultBacktestAssumptions;
  return {
    initialCash: normalizeBacktestAssumptionValue(
      "initialCash",
      assumptions.initialCash,
      defaultBacktestAssumptions.initialCash
    ),
    feeBps: normalizeBacktestAssumptionValue("feeBps", assumptions.feeBps, defaultBacktestAssumptions.feeBps),
    slippageBps: normalizeBacktestAssumptionValue(
      "slippageBps",
      assumptions.slippageBps,
      defaultBacktestAssumptions.slippageBps
    )
  };
}

export function buildBacktestAssumptionRows(workspace: TerminalWorkspace): BacktestAssumptionRow[] {
  const assumptions = resolveBacktestAssumptions(workspace);
  return (Object.keys(backtestAssumptionSpecs) as BacktestAssumptionField[]).map((field) => ({
    field,
    ...backtestAssumptionSpecs[field],
    value: assumptions[field]
  }));
}

export function buildBacktestEvidenceCards(workspace: TerminalWorkspace): BacktestEvidenceCard[] {
  const assumptions = resolveBacktestAssumptions(workspace);
  const diagnostics = workspace.backtestDiagnostics ?? [];
  const firstDiagnostic = diagnostics[0];
  const run = workspace.researchRun;
  const contextBinding = buildResearchRunContextBinding(workspace);

  return [
    run && contextBinding.canUseRun
      ? {
          id: "run",
          label: "Run package",
          value: run.runId,
          detail: `${run.dataRows} ${run.timeframe} bars · ${run.executionMode}`,
          tone: "positive"
        }
      : run
        ? {
            id: "run",
            label: "Run package",
            value: run.runId,
            detail: contextBinding.detail,
            tone: "risk"
          }
      : {
          id: "run",
          label: "Run package",
          value: "Draft workspace",
          detail: "Run Pipeline to bind a reproducible run id.",
          tone: "warning"
        },
    {
      id: "strategy",
      label: "Strategy revision",
      value: run?.strategyRevision ?? "Local draft",
      detail: workspace.strategy.name,
      tone: run ? (contextBinding.canUseRun ? "positive" : "risk") : "warning"
    },
    {
      id: "costs",
      label: "Cost model",
      value: `${assumptions.feeBps} bps / ${assumptions.slippageBps} bps`,
      detail: `Cash ${formatAssumptionCurrency(assumptions.initialCash)}`,
      tone: "neutral"
    },
    {
      id: "diagnostics",
      label: "Diagnostics",
      value: diagnostics.length === 1 ? "1 check" : `${diagnostics.length} checks`,
      detail: firstDiagnostic
        ? `${firstDiagnostic.label}: ${firstDiagnostic.detail}`
        : "No core diagnostics supplied yet.",
      tone: firstDiagnostic?.tone ?? "warning"
    }
  ];
}

export function buildBacktestReadinessGates(workspace: TerminalWorkspace): BacktestReadinessGate[] {
  const assumptions = resolveBacktestAssumptions(workspace);
  const contextBinding = buildResearchRunContextBinding(workspace);
  const run = workspace.researchRun;
  const hasAuditedRun = contextBinding.canUseRun;
  const strategyIsParseable =
    !isPendingStrategyText(workspace.strategy.entry) &&
    !isPendingStrategyText(workspace.strategy.exit) &&
    !isPendingStrategyText(workspace.strategy.position) &&
    !isPendingStrategyText(workspace.strategy.risk);

  return [
    hasAuditedRun
      ? {
          id: "data",
          label: "Data snapshot",
          status: "passed",
          detail: `Audited ${run?.dataRows ?? 0} ${run?.timeframe ?? workspace.selectedTimeframe} bars are bound.`,
          tone: "positive"
        }
      : run
        ? {
            id: "data",
            label: "Data snapshot",
            status: "blocked",
            detail: contextBinding.detail,
            tone: "risk"
          }
      : {
          id: "data",
          label: "Data snapshot",
          status: "blocked",
          detail: "Run Pipeline to bind a reproducible OHLCV snapshot.",
          tone: "risk"
        },
    strategyIsParseable
      ? {
          id: "strategy",
          label: "Strategy schema",
          status: "passed",
          detail: `${workspace.strategy.name} is parseable.`,
          tone: "positive"
        }
      : {
          id: "strategy",
          label: "Strategy schema",
          status: "blocked",
          detail: "Complete entry, exit, position, and risk rules before audit.",
          tone: "risk"
        },
    {
      id: "costs",
      label: "Cost model",
      status: "passed",
      detail: `Cash ${formatAssumptionCurrency(assumptions.initialCash)} · fee ${assumptions.feeBps} bps · slippage ${assumptions.slippageBps} bps.`,
      tone: "neutral"
    },
    hasAuditedRun
      ? {
          id: "execution",
          label: "Execution promotion",
          status: "review",
          detail: "Paper execution can be staged; live adapters remain gated.",
          tone: "warning"
        }
      : {
          id: "execution",
          label: "Execution promotion",
          status: "blocked",
          detail: "Paper execution waits for an audited run id.",
          tone: "risk"
        }
  ];
}

export function buildBacktestReport(workspace: TerminalWorkspace): BacktestReport {
  const assumptions = resolveBacktestAssumptions(workspace);
  const assumptionRows = buildBacktestAssumptionRows(workspace);
  const evidenceCards = buildBacktestEvidenceCards(workspace);
  const readinessGates = buildBacktestReadinessGates(workspace);
  const trades = buildBacktestTradeRows(workspace);
  const diagnostics = workspace.backtestDiagnostics ?? [];
  const equityCurve = workspace.backtestEquityCurve ?? [];
  const run = workspace.researchRun;
  const contextBinding = buildResearchRunContextBinding(workspace);
  const benchmark = buildBacktestBenchmark(workspace);
  const blockedGates = readinessGates.filter((gate) => gate.status === "blocked");
  const aiReviewReady =
    contextBinding.canUseRun && !blockedGates.some((gate) => gate.id === "data" || gate.id === "strategy");
  const executionReady = contextBinding.canUseRun && !blockedGates.length;
  const metricTradeCount = metricValue(workspace, "Trades", "0");

  if (!run) {
    return {
      status: "blocked",
      headline: "Backtest report needs an audited run",
      summary: "Run Pipeline to create a reproducible backtest before AI review or execution.",
      runId: null,
      aiReviewReady: false,
      executionReady: false,
      assumptions,
      assumptionRows,
      evidenceCards,
      readinessGates,
      benchmark,
      metrics: workspace.metrics,
      trades,
      diagnostics,
      equityCurve,
      tradeCount: trades.length,
      equityPointCount: equityCurve.length,
      diagnosticCount: diagnostics.length
    };
  }

  if (!contextBinding.canUseRun) {
    return {
      status: "blocked",
      headline: "Backtest report needs a matching audited run",
      summary: "Run Pipeline to create a fresh audited run for the selected market, symbol, and timeframe.",
      runId: run.runId,
      aiReviewReady: false,
      executionReady: false,
      assumptions,
      assumptionRows,
      evidenceCards,
      readinessGates,
      benchmark,
      metrics: workspace.metrics,
      trades,
      diagnostics,
      equityCurve,
      tradeCount: trades.length,
      equityPointCount: equityCurve.length,
      diagnosticCount: diagnostics.length
    };
  }

  return {
    status: aiReviewReady ? "ready" : "blocked",
    headline: `Backtest report bound to ${run.runId}`,
    summary: `${run.dataRows} ${run.timeframe} bars · ${metricTradeCount} trades · ${
      aiReviewReady ? "AI review ready" : "AI review blocked"
    }`,
    runId: run.runId,
    aiReviewReady,
    executionReady,
    assumptions,
    assumptionRows,
    evidenceCards,
    readinessGates,
    benchmark,
    metrics: workspace.metrics,
    trades,
    diagnostics,
    equityCurve,
    tradeCount: trades.length,
    equityPointCount: equityCurve.length,
    diagnosticCount: diagnostics.length
  };
}

export function buildBacktestParameterScanRows(workspace: TerminalWorkspace): BacktestParameterScanRow[] {
  if (!buildResearchRunContextBinding(workspace).canUseRun) {
    return [];
  }

  const run = workspace.researchRun;
  const bars = run?.dataSnapshot?.bars
    .filter((bar) => Number.isFinite(bar.close) && bar.close > 0)
    .slice()
    .sort((left, right) => left.timestampMs - right.timestampMs);

  if (!run || !bars || bars.length < 2) {
    return [];
  }

  const draft = buildStrategyRuleDraft(workspace);
  const entryWindows = parameterScanWindows(draft.entryWindow);
  const exitWindows = parameterScanWindows(draft.exitWindow);
  const entryRsiThresholds: Array<number | null> =
    draft.entryRsiConfirm && !isRsiConditionKind(draft.entryKind)
      ? parameterScanThresholds(draft.entryRsiThreshold)
      : [null];
  const entryVolumeWindows: Array<number | null> = draft.entryVolumeConfirm
    ? parameterScanWindows(draft.entryVolumeWindow)
    : [null];
  const currentMetricReturn = parsePercentMetric(metricValue(workspace, "Return", "N/A"));
  const currentScan = simulateSmaParameterScan(
    workspace,
    bars,
    draft.entryWindow,
    draft.exitWindow,
    draft.entryRsiThreshold,
    draft.entryVolumeWindow
  );
  const currentReturn = currentMetricReturn ?? currentScan.totalReturnPct;

  return entryWindows.flatMap((entryWindow) =>
    exitWindows.flatMap((exitWindow) =>
      entryRsiThresholds.flatMap((entryRsiThreshold) =>
        entryVolumeWindows.map((entryVolumeWindow) => {
          const result = simulateSmaParameterScan(
            workspace,
            bars,
            entryWindow,
            exitWindow,
            entryRsiThreshold,
            entryVolumeWindow
          );
          const delta = result.totalReturnPct - currentReturn;
          const isCurrent =
            entryWindow === draft.entryWindow &&
            exitWindow === draft.exitWindow &&
            (!draft.entryRsiConfirm || entryRsiThreshold === draft.entryRsiThreshold) &&
            (!draft.entryVolumeConfirm || entryVolumeWindow === draft.entryVolumeWindow);
          const breachesDrawdown = result.maxDrawdownPct > draft.maxDrawdownPct;
          const rsiCondition = entryRsiThreshold === null ? "" : ` / RSI>${formatConditionNumber(entryRsiThreshold)}`;
          const rsiId = entryRsiThreshold === null ? "" : `-rsi-${formatConditionNumber(entryRsiThreshold)}`;
          const volumeCondition = entryVolumeWindow === null ? "" : ` / VOL${entryVolumeWindow}`;
          const volumeId = entryVolumeWindow === null ? "" : `-vol-${entryVolumeWindow}`;
          return {
            id: `scan-entry-${entryWindow}-exit-${exitWindow}${rsiId}${volumeId}`,
            runId: run.runId,
            source: run.dataSnapshot?.hash ?? run.dataSnapshot?.source ?? "audited snapshot",
            condition: `SMA${entryWindow} / SMA${exitWindow}${rsiCondition}${volumeCondition}`,
            entryWindow,
            exitWindow,
            entryRsiThreshold,
            entryVolumeWindow,
            returnPct: formatSignedPct(result.totalReturnPct),
            maxDrawdownPct: formatPct(result.maxDrawdownPct),
            tradeCount: result.tradeCount,
            alphaVsCurrent: formatSignedPointDelta(delta),
            status: isCurrent ? "current" : "candidate",
            tone: isCurrent ? "neutral" : breachesDrawdown ? "risk" : delta >= 0 ? "positive" : "warning",
            dataRows: bars.length
          };
        })
      )
    )
  );
}

export function buildBacktestParameterScanSummary(workspace: TerminalWorkspace): BacktestParameterScanSummary | null {
  const rows = buildBacktestParameterScanRows(workspace);
  if (!rows.length) {
    return null;
  }

  const rankedRows = rows
    .map((row, index) => ({
      row,
      index,
      returnPct: parsePercentMetric(row.returnPct) ?? Number.NEGATIVE_INFINITY,
      maxDrawdownPct: parsePercentMetric(row.maxDrawdownPct) ?? Number.POSITIVE_INFINITY
    }))
    .sort(
      (left, right) =>
        right.returnPct - left.returnPct ||
        left.maxDrawdownPct - right.maxDrawdownPct ||
        left.index - right.index
    );
  const currentRankIndex = rankedRows.findIndex((entry) => entry.row.status === "current");
  const currentRow = rows.find((row) => row.status === "current") ?? null;
  const candidateRows = rows.filter((row) => row.status === "candidate");
  const positiveCount = rows.filter((row) => row.tone === "positive").length;
  const riskCount = rows.filter((row) => row.tone === "risk").length;
  const bestCandidate =
    rankedRows.find((entry) => entry.row.status === "candidate" && entry.row.tone !== "risk") ??
    rankedRows.find((entry) => entry.row.status === "candidate") ??
    null;
  const currentRank = currentRankIndex >= 0 ? currentRankIndex + 1 : null;
  const bestRow = bestCandidate?.row ?? null;
  const tone: BacktestParameterScanSummary["tone"] =
    bestRow?.tone === "positive"
      ? "positive"
      : riskCount === candidateRows.length && candidateRows.length > 0
        ? "risk"
        : currentRank === 1
          ? "neutral"
          : "warning";

  return {
    totalRows: rows.length,
    candidateCount: candidateRows.length,
    positiveCount,
    riskCount,
    currentCondition: currentRow?.condition ?? null,
    currentRank,
    bestCandidateId: bestRow?.id ?? null,
    bestCandidateCondition: bestRow?.condition ?? null,
    bestCandidateReturnPct: bestRow?.returnPct ?? "N/A",
    bestCandidateMaxDrawdownPct: bestRow?.maxDrawdownPct ?? "N/A",
    bestCandidateDelta: bestRow?.alphaVsCurrent ?? "N/A",
    headline: bestRow ? `${bestRow.condition} candidate for re-audit` : "No candidate cleared for re-audit",
    detail: [
      currentRank === null
        ? "Current parameter row is missing from the locked scan."
        : `Current ${currentRow?.condition ?? "parameter"} ranks ${currentRank}/${rows.length} on the locked snapshot.`,
      `${candidateRows.length} candidates, ${positiveCount} positive rows, ${riskCount} drawdown-risk rows.`,
      bestRow
        ? `${bestRow.condition} is the top non-current candidate for re-audit; this is not investment advice.`
        : "No non-current candidate is available for re-audit; this is not investment advice."
    ].join(" "),
    tone
  };
}

export function buildBacktestReportMarkdown(
  workspace: TerminalWorkspace,
  runHistory: ResearchRunAudit[] = []
): string | null {
  const run = workspace.researchRun;
  if (!run) {
    return null;
  }

  const report = buildBacktestReport(workspace);
  const aiDossier = buildAiReviewDossier(workspace);
  const snapshot = run.dataSnapshot;
  const preparationEvidence = snapshot?.preparationEvidence ?? null;
  const marketCalendar = snapshot?.marketCalendar ?? null;
  const researchNote = normalizedResearchNote(run.researchNote);
  const metricRows = report.metrics.map((metric) => [metric.label, metric.value, metric.tone]);
  const parameterScanSummary = buildBacktestParameterScanSummary(workspace);
  const benchmarkRows = [
    ["Strategy", report.benchmark.strategyReturn],
    ["Benchmark buy and hold", report.benchmark.benchmarkReturn],
    ["Alpha", report.benchmark.alpha]
  ];
  const assumptionRows = report.assumptionRows.map((row) => [row.label, `${row.value} ${row.suffix}`]);
  const parameterScanRows = buildBacktestParameterScanRows(workspace).map((row) => [
    row.condition,
    row.returnPct,
    row.maxDrawdownPct,
    row.tradeCount,
    row.alphaVsCurrent,
    row.status
  ]);
  const runComparisonRows = buildBacktestRunComparisonMatrixRows(runHistory, run.runId);
  const runComparisonSummary = buildBacktestRunComparisonMatrixSummary(runComparisonRows);
  const runComparisonMarkdownRows = runComparisonRows.map((row) => [
    row.runId,
    row.badges.join(", "),
    row.returnPct,
    row.maxDrawdownPct,
    row.winRatePct,
    row.tradeCount,
    row.dataQualityLabel,
    row.assumptions
  ]);
  const crossSymbolComparisonRows = buildBacktestCrossSymbolComparisonRows(runHistory, run.runId);
  const crossSymbolComparisonSummary = buildBacktestCrossSymbolComparisonSummary(crossSymbolComparisonRows);
  const crossSymbolComparisonMarkdownRows = crossSymbolComparisonRows.map((row) => [
    row.symbol,
    row.runId,
    row.badges.join(", "),
    row.returnPct,
    row.maxDrawdownPct,
    row.winRatePct,
    row.tradeCount,
    row.dataQualityLabel
  ]);
  const gateRows = report.readinessGates.map((gate) => [gate.label, gate.status, gate.detail]);
  const aiCitationRows = aiDossier.citations.map((citation) => [
    citation.label,
    citation.value,
    citation.detail
  ]);
  const tradeRows = report.trades.map((trade) => [
    trade.timestamp,
    trade.side,
    trade.status,
    trade.price,
    trade.quantity,
    trade.pnl,
    trade.reason
  ]);

  return [
    "# AIQuant Audited Backtest Report",
    "",
    `Run ID: \`${run.runId}\``,
    `Market: \`${workspace.selectedInstrument.market}\``,
    `Symbol: \`${workspace.selectedInstrument.symbol}\``,
    `Timeframe: \`${run.timeframe}\``,
    `Strategy revision: \`${run.strategyRevision}\``,
    `Execution mode: \`${run.executionMode}\``,
    "",
    "## Summary",
    "",
    report.summary,
    "",
    "## Metrics",
    "",
    markdownTable(["Metric", "Value", "Tone"], metricRows),
    "",
    "## Benchmark",
    "",
    report.benchmark.detail,
    "",
    markdownTable(["Item", "Value"], benchmarkRows),
    "",
    "## Data Snapshot",
    "",
    markdownTable(
      ["Field", "Value"],
      [
        ["Source", snapshot?.source ?? "missing"],
        ["Rows", String(snapshot?.rows ?? run.dataRows)],
        ["Hash", snapshot?.hash ?? ""],
        ["Window", `${snapshot?.start ?? "unknown"} -> ${snapshot?.end ?? "unknown"}`],
        ["Quality", run.dataQuality ? `${run.dataQuality.source} · ${run.dataQuality.isComplete ? "complete" : "incomplete"}` : "not attached"],
        ["Market calendar", marketCalendar ? formatMarketCalendarEvidenceDetail(marketCalendar) : "not locked"],
        ["Preparation evidence", preparationEvidence ? formatPreparationEvidenceDetail(preparationEvidence) : "not locked"]
      ]
    ),
    "",
    "## Backtest Assumptions",
    "",
    markdownTable(["Assumption", "Value"], assumptionRows),
    "",
    "## Parameter Scan Summary",
    "",
    parameterScanSummary
      ? markdownTable(
          ["Field", "Value"],
          [
            ["Rows", parameterScanSummary.totalRows],
            ["Current rank", parameterScanSummary.currentRank ? `${parameterScanSummary.currentRank}/${parameterScanSummary.totalRows}` : "N/A"],
            ["Candidate for re-audit", parameterScanSummary.bestCandidateCondition ?? "N/A"],
            ["Candidate return", parameterScanSummary.bestCandidateReturnPct],
            ["Candidate max drawdown", parameterScanSummary.bestCandidateMaxDrawdownPct],
            ["Candidate delta", parameterScanSummary.bestCandidateDelta],
            ["Risk rows", parameterScanSummary.riskCount],
            ["Boundary", "Candidate must be re-audited; no investment advice."]
          ]
        )
      : "Parameter scan summary requires an audited data snapshot.",
    "",
    "## Parameter Sensitivity",
    "",
    parameterScanRows.length
      ? markdownTable(["Condition", "Return", "Max drawdown", "Trades", "Delta", "Status"], parameterScanRows)
      : "Parameter sensitivity requires an audited data snapshot.",
    "",
    "## Run Comparison Matrix",
    "",
    runComparisonSummary
      ? [
          runComparisonSummary.headline,
          "",
          runComparisonSummary.detail,
          "",
          markdownTable(
            ["Run", "Badges", "Return", "Max drawdown", "Win rate", "Trades", "Data quality", "Assumptions"],
            runComparisonMarkdownRows
          )
        ].join("\n")
      : "Run comparison matrix requires at least one audited run in history for the same market, symbol, and timeframe.",
    "",
    "## Cross-Symbol Comparison",
    "",
    crossSymbolComparisonSummary
      ? [
          crossSymbolComparisonSummary.headline,
          "",
          crossSymbolComparisonSummary.detail,
          "",
          markdownTable(
            ["Symbol", "Run", "Badges", "Return", "Max drawdown", "Win rate", "Trades", "Data quality"],
            crossSymbolComparisonMarkdownRows
          )
        ].join("\n")
      : "Cross-symbol comparison requires audited runs in history for the same market and timeframe.",
    "",
    "## AI Evidence Boundary",
    "",
    "No investment advice. AI can explain supplied audited evidence only and must not promise returns.",
    "",
    markdownTable(["Citation", "Value", "Evidence"], aiCitationRows),
    "",
    researchNote ? "## Locked Research Note" : "",
    researchNote ? "" : "",
    researchNote ? researchNote.body : "",
    researchNote ? "" : "",
    "## Readiness Gates",
    "",
    markdownTable(["Gate", "Status", "Detail"], gateRows),
    "",
    "## Trade Replay",
    "",
    tradeRows.length
      ? markdownTable(["Time", "Side", "Status", "Price", "Quantity", "PnL", "Reason"], tradeRows)
      : "No trade rows are attached to this audited run.",
    "",
    "## Execution Boundary",
    "",
    report.executionReady
      ? "Paper execution handoff is ready. Live execution still requires certified adapters, risk approval, and human confirmation."
      : "Execution remains blocked until all readiness gates pass."
  ]
    .filter((line, index, lines) => line !== "" || lines[index - 1] !== "")
    .join("\n")
    .trimEnd()
    .concat("\n");
}

export function buildBacktestBenchmark(workspace: TerminalWorkspace): BacktestBenchmark {
  const contextBinding = buildResearchRunContextBinding(workspace);
  const run = workspace.researchRun;
  const snapshot = run?.dataSnapshot;
  const bars = snapshot?.bars.filter((bar) => Number.isFinite(bar.close) && bar.close > 0) ?? [];
  const strategyReturn = parsePercentMetric(metricValue(workspace, "Return", "N/A"));
  const formattedStrategyReturn = strategyReturn === null ? "N/A" : formatSignedPct(strategyReturn);

  if (!run || !contextBinding.canUseRun || bars.length < 2) {
    return {
      label: "Buy and hold",
      symbol: workspace.selectedInstrument.symbol,
      strategyReturn: formattedStrategyReturn,
      benchmarkReturn: "Pending snapshot",
      alpha: "N/A",
      detail:
        run && !contextBinding.canUseRun
          ? contextBinding.detail
          : "Run Pipeline must include a data snapshot before benchmark comparison.",
      tone: "warning",
      sampleBars: 0,
      source: snapshot?.source ?? "missing snapshot"
    };
  }

  const firstClose = bars[0].close;
  const lastClose = bars[bars.length - 1].close;
  const benchmarkReturn = ((lastClose - firstClose) / firstClose) * 100;
  const alpha = strategyReturn === null ? null : strategyReturn - benchmarkReturn;
  const tone = alpha === null ? "neutral" : alpha >= 0 ? "positive" : "warning";

  return {
    label: "Buy and hold",
    symbol: workspace.selectedInstrument.symbol,
    strategyReturn: formattedStrategyReturn,
    benchmarkReturn: formatSignedPct(benchmarkReturn),
    alpha: alpha === null ? "N/A" : formatSignedPointDelta(alpha),
    detail: `${bars.length} audited bars from ${snapshot?.source ?? "unknown"} · ${bars[0].timestamp} to ${
      bars[bars.length - 1].timestamp
    }.`,
    tone,
    sampleBars: bars.length,
    source: snapshot?.source ?? "unknown"
  };
}

function parameterScanWindows(currentWindow: number): number[] {
  return Array.from(
    new Set([currentWindow - 5, currentWindow, currentWindow + 5].map((window) => normalizeStrategyWindow(window)))
  ).sort((left, right) => left - right);
}

function parameterScanThresholds(currentThreshold: number): number[] {
  return Array.from(
    new Set(
      [currentThreshold - 5, currentThreshold, currentThreshold + 5].map((threshold) =>
        normalizeStrategyThreshold(threshold, defaultStrategyRuleDraft.entryRsiThreshold)
      )
    )
  ).sort((left, right) => left - right);
}

function simulateSmaParameterScan(
  workspace: TerminalWorkspace,
  bars: ResearchRunDataSnapshotBar[],
  entryWindow: number,
  exitWindow: number,
  entryRsiThreshold: number | null = null,
  entryVolumeWindow: number | null = null
): { totalReturnPct: number; maxDrawdownPct: number; tradeCount: number } {
  const assumptions = resolveBacktestAssumptions(workspace);
  const draft = buildStrategyRuleDraft(workspace);
  const feeRate = assumptions.feeBps / 10_000;
  const slippageRate = assumptions.slippageBps / 10_000;
  const positionPct = Math.max(0, Math.min(draft.positionPct / 100, 1));
  const stopLossPct = draft.stopLossPct / 100;
  const takeProfitPct = draft.takeProfitPct / 100;
  const closes = bars.map((bar) => bar.close);
  const volumes = bars.map((bar) => bar.volume);
  let cash = assumptions.initialCash;
  let quantity = 0;
  let entryPrice = 0;
  let tradeCount = 0;
  const equityValues: number[] = [];

  bars.forEach((bar, index) => {
    const passesRsi =
      !draft.entryRsiConfirm ||
      rsiAbove(closes, index, draft.entryRsiWindow, entryRsiThreshold ?? draft.entryRsiThreshold);
    const passesVolume =
      !draft.entryVolumeConfirm || volumeAboveSma(volumes, index, entryVolumeWindow ?? draft.entryVolumeWindow);
    if (quantity <= 0 && closeAboveSma(closes, index, entryWindow) && passesRsi && passesVolume) {
      const budget = cash * positionPct;
      const executionPrice = bar.close * (1 + slippageRate);
      const nextQuantity = executionPrice > 0 ? budget / executionPrice : 0;
      const fee = budget * feeRate;
      if (nextQuantity > 0 && budget + fee <= cash) {
        cash -= budget + fee;
        quantity = nextQuantity;
        entryPrice = executionPrice;
        tradeCount += 1;
      }
    } else if (quantity > 0) {
      const shouldExit =
        bar.close <= entryPrice * (1 - stopLossPct) ||
        bar.close >= entryPrice * (1 + takeProfitPct) ||
        closeBelowSma(closes, index, exitWindow);
      if (shouldExit) {
        const executionPrice = bar.close * (1 - slippageRate);
        const gross = quantity * executionPrice;
        cash += gross - gross * feeRate;
        quantity = 0;
        entryPrice = 0;
        tradeCount += 1;
      }
    }

    equityValues.push(cash + quantity * bar.close);
  });

  if (quantity > 0) {
    const lastClose = bars[bars.length - 1].close;
    const executionPrice = lastClose * (1 - slippageRate);
    const gross = quantity * executionPrice;
    cash += gross - gross * feeRate;
    quantity = 0;
    tradeCount += 1;
    equityValues[equityValues.length - 1] = cash;
  }

  return {
    totalReturnPct: ((cash / assumptions.initialCash) - 1) * 100,
    maxDrawdownPct: maxDrawdownFromEquity(equityValues),
    tradeCount
  };
}

function closeAboveSma(closes: number[], index: number, window: number): boolean {
  const average = smaAt(closes, index, window);
  return average !== null && closes[index] > average;
}

function closeBelowSma(closes: number[], index: number, window: number): boolean {
  const average = smaAt(closes, index, window);
  return average !== null && closes[index] < average;
}

function volumeAboveSma(volumes: number[], index: number, window: number): boolean {
  const average = smaAt(volumes, index, window);
  return average !== null && volumes[index] > average;
}

function rsiAbove(closes: number[], index: number, window: number, threshold: number): boolean {
  const value = rsiAt(closes, index, window);
  return value !== null && value > threshold;
}

function rsiAt(closes: number[], index: number, window: number): number | null {
  if (window <= 0 || index < window) {
    return null;
  }
  let gains = 0;
  let losses = 0;
  for (let cursor = index - window + 1; cursor <= index; cursor += 1) {
    const delta = closes[cursor] - closes[cursor - 1];
    if (delta >= 0) {
      gains += delta;
    } else {
      losses += Math.abs(delta);
    }
  }
  const averageGain = gains / window;
  const averageLoss = losses / window;
  if (averageLoss === 0) {
    return 100;
  }
  const relativeStrength = averageGain / averageLoss;
  return 100 - 100 / (1 + relativeStrength);
}

function smaAt(values: number[], index: number, window: number): number | null {
  if (window <= 0 || index + 1 < window) {
    return null;
  }
  const slice = values.slice(index + 1 - window, index + 1);
  return slice.reduce((sum, value) => sum + value, 0) / window;
}

function maxDrawdownFromEquity(equityValues: number[]): number {
  if (!equityValues.length) {
    return 0;
  }
  let peak = equityValues[0];
  let maxDrawdown = 0;
  equityValues.forEach((equity) => {
    peak = Math.max(peak, equity);
    if (peak > 0) {
      maxDrawdown = Math.max(maxDrawdown, ((peak - equity) / peak) * 100);
    }
  });
  return maxDrawdown;
}

function markdownTable(headers: string[], rows: Array<Array<string | number | boolean | null | undefined>>): string {
  return [
    `| ${headers.map(markdownCell).join(" | ")} |`,
    `| ${headers.map(() => "---").join(" | ")} |`,
    ...rows.map((row) => `| ${row.map(markdownCell).join(" | ")} |`)
  ].join("\n");
}

function markdownCell(value: string | number | boolean | null | undefined): string {
  return String(value ?? "")
    .replace(/\r?\n+/gu, " ")
    .replace(/\|/gu, "\\|")
    .trim();
}

function aiBenchmarkDetail(benchmark: BacktestBenchmark): string {
  if (benchmark.sampleBars <= 0 || benchmark.benchmarkReturn === "Pending snapshot") {
    return "Benchmark comparison waits for an audited data snapshot.";
  }
  return `Strategy ${benchmark.strategyReturn} vs buy-and-hold ${benchmark.benchmarkReturn} over ${benchmark.sampleBars} audited bars.`;
}

export function buildModuleNewsEvents(workspace: TerminalWorkspace): ModuleNewsEvent[] {
  const selectedInstrument = workspace.selectedInstrument;
  const selectedSymbol = selectedInstrument.symbol;
  const price = selectedInstrument.price;
  const quoteSource = selectedInstrument.quoteSource ?? "workspace";
  const hasQuote = price !== undefined && price !== null && Number.isFinite(price);
  const blockedGateCount = workspace.execution.gates.filter((gate) => !gate.passed).length;
  const localEvents: ModuleNewsEvent[] = [
    hasQuote
      ? {
          id: "quote-update",
          source: "Market data",
          title: `${selectedSymbol} quote ${formatInstrumentPrice(price)} from ${quoteSource}`,
          impact: selectedInstrument.changePct < 0 ? "warning" : "positive",
          detail: `As of ${selectedInstrument.quoteAsOf ?? "latest workspace refresh"} · change ${formatSignedPct(
            selectedInstrument.changePct
          )}`
        }
      : {
          id: "quote-missing",
          source: "Market data",
          title: `${selectedSymbol} quote unavailable`,
          impact: "warning",
          detail: "Refresh workspace or configure a market data adapter."
        },
    workspace.researchRun
      ? {
          id: "audit-run",
          source: "Audit log",
          title: `Run ${workspace.researchRun.runId} bound to ${selectedSymbol}`,
          impact: "ai",
          detail: `${workspace.researchRun.dataRows} ${workspace.researchRun.timeframe} bars · revision ${workspace.researchRun.strategyRevision} · ${workspace.researchRun.executionMode}`
        }
      : {
          id: "audit-needed",
          source: "Audit log",
          title: `${selectedSymbol} needs a fresh audited run`,
          impact: "warning",
          detail: "Run Pipeline to bind data, backtest, agent review, and execution gates."
        },
    {
      id: "execution-gates",
      source: "Risk engine",
      title: workspace.execution.liveEnabled ? "Live execution gates open" : `${blockedGateCount} execution gates blocked`,
      impact: workspace.execution.liveEnabled ? "positive" : "risk",
      detail: workspace.execution.gates.map((gate) => `${gate.label}: ${gate.passed ? "passed" : "blocked"}`).join(" · ")
    }
  ];
  const committeeEvents = workspace.decisionLog.slice(0, 3).map((entry, index) => ({
    id: `committee-${index}`,
    source: "AI committee",
    title: `${entry.agent}: ${entry.message}`,
    impact: entry.tone,
    detail: `Linked to ${selectedSymbol} research context.`
  }));
  return [...localEvents, ...committeeEvents];
}

function inferSmaConditionKind(text: string, fallback: StrategyConditionKind): StrategyConditionKind {
  const normalized = text.toLowerCase();
  if (normalized.includes("below") || text.includes("<")) {
    return "close_below_sma";
  }
  if (normalized.includes("above") || text.includes(">")) {
    return "close_above_sma";
  }
  return fallback;
}

function inferSmaWindow(text: string, fallback: number): number {
  const match = text.match(/sma\s*(\d+)/iu) ?? text.match(/window\s*=\s*(\d+)/iu);
  return normalizeStrategyWindow(match ? Number(match[1]) : fallback);
}

function rsiOperatorToConditionKind(operator: "<" | ">"): StrategyConditionKind {
  return operator === "<" ? "rsi_below" : "rsi_above";
}

function inferPercent(text: string, fallback: number): number {
  const match = text.match(/(\d+(?:\.\d+)?)\s*%/u);
  return normalizeStrategyPercent(match ? Number(match[1]) : fallback, fallback);
}

function inferPercentNearKeywords(text: string, keywords: string[], fallback: number): number {
  const normalized = text.toLowerCase();
  for (const match of normalized.matchAll(/([+-]?\d+(?:\.\d+)?)\s*%/gu)) {
    const index = match.index ?? 0;
    const prefix = normalized.slice(Math.max(0, index - 36), index);
    if (keywords.some((keyword) => prefix.includes(keyword))) {
      return normalizeStrategyPercent(Math.abs(Number(match[1])), fallback);
    }
  }
  return normalizeStrategyPercent(fallback, fallback);
}

function normalizeStrategyRuleDraft(draft: StrategyRuleDraft): StrategyRuleDraft {
  return {
    name: draft.name.trim() || defaultStrategyRuleDraft.name,
    entryKind: normalizeStrategyConditionKind(draft.entryKind, defaultStrategyRuleDraft.entryKind),
    entryWindow: normalizeStrategyWindow(draft.entryWindow),
    entryThreshold: normalizeStrategyThreshold(draft.entryThreshold, defaultStrategyRuleDraft.entryThreshold),
    entryRsiConfirm: Boolean(draft.entryRsiConfirm),
    entryRsiWindow: normalizeStrategyWindow(draft.entryRsiWindow),
    entryRsiThreshold: normalizeStrategyThreshold(draft.entryRsiThreshold, defaultStrategyRuleDraft.entryRsiThreshold),
    entryVolumeConfirm: Boolean(draft.entryVolumeConfirm),
    entryVolumeWindow: normalizeStrategyWindow(draft.entryVolumeWindow),
    exitKind: normalizeStrategyConditionKind(draft.exitKind, defaultStrategyRuleDraft.exitKind),
    exitWindow: normalizeStrategyWindow(draft.exitWindow),
    exitThreshold: normalizeStrategyThreshold(draft.exitThreshold, defaultStrategyRuleDraft.exitThreshold),
    positionPct: normalizeStrategyPercent(draft.positionPct, defaultStrategyRuleDraft.positionPct),
    stopLossPct: normalizeStrategyPercent(draft.stopLossPct, defaultStrategyRuleDraft.stopLossPct),
    takeProfitPct: normalizeStrategyPercent(draft.takeProfitPct, defaultStrategyRuleDraft.takeProfitPct),
    maxDrawdownPct: normalizeStrategyPercent(draft.maxDrawdownPct, defaultStrategyRuleDraft.maxDrawdownPct),
    paperOnly: draft.paperOnly
  };
}

function normalizeStrategyConditionKind(kind: StrategyConditionKind, fallback: StrategyConditionKind): StrategyConditionKind {
  return ["close_above_sma", "close_below_sma", "rsi_below", "rsi_above"].includes(kind) ? kind : fallback;
}

function isRsiConditionKind(kind: StrategyConditionKind): boolean {
  return kind === "rsi_below" || kind === "rsi_above";
}

function normalizeStrategyWindow(value: number): number {
  if (!Number.isFinite(value)) {
    return defaultStrategyRuleDraft.entryWindow;
  }
  return Math.max(1, Math.min(Math.round(value), 250));
}

function normalizeStrategyThreshold(value: number, fallback: number): number {
  if (!Number.isFinite(value)) {
    return fallback;
  }
  return Math.max(0, Math.min(Number(value.toFixed(2)), 100));
}

function normalizeStrategyPercent(value: number, fallback: number): number {
  if (!Number.isFinite(value)) {
    return fallback;
  }
  return Math.max(0, Math.min(Number(value.toFixed(2)), 100));
}

function strategyConditionSnapshotText(kind: StrategyConditionKind, window: number, threshold: number): string {
  if (kind === "close_below_sma") {
    return `Close < SMA${window}`;
  }
  if (kind === "rsi_below") {
    return `RSI${window} < ${formatConditionNumber(threshold)}`;
  }
  if (kind === "rsi_above") {
    return `RSI${window} > ${formatConditionNumber(threshold)}`;
  }
  return `Close > SMA${window}`;
}

function formatPercentValue(value: number): string {
  return Number.isInteger(value) ? String(value) : value.toFixed(2).replace(/0+$/u, "").replace(/\.$/u, "");
}

function isPendingStrategyText(text: string): boolean {
  return text.startsWith("Pending") || text.startsWith("Run Pipeline");
}

function metricValue(workspace: TerminalWorkspace, label: string, fallback: string): string {
  return workspace.metrics.find((metric) => metric.label === label)?.value ?? fallback;
}

function normalizeDrawdownLoss(value: string): string {
  if (value === "N/A" || value.startsWith("-")) {
    return value;
  }
  return `-${value}`;
}

function formatWarningCount(count: number): string {
  return count === 1 ? "1 warning" : `${count} warnings`;
}

function formatPreparationEvidenceDetail(evidence: ResearchRunDataPreparationEvidence): string {
  const parts = [
    evidence.runId,
    evidence.kind,
    `${evidence.symbol} ${evidence.timeframe}`,
    `${evidence.quality.source} ${evidence.quality.isComplete ? "complete" : "review"}`,
    `${evidence.upsertedRows} rows cached`
  ];
  if (evidence.overrideAuditEventId) {
    parts.push(`override ${evidence.overrideAuditEventId}`);
  }
  return parts.join(" · ");
}

function formatMarketCalendarEvidenceDetail(calendar: ResearchContextMarketCalendar): string {
  const warnings = calendar.warnings.filter((warning) => warning.trim());
  return [
    calendar.market,
    calendar.timezone,
    `${calendar.status}/${calendar.session}`,
    marketCalendarNextEventDetail(calendar),
    warnings[0] ?? calendar.source,
    formatWarningCount(warnings.length)
  ].join(" · ");
}

function marketCalendarEvidenceTone(calendar: ResearchContextMarketCalendar): "positive" | "warning" {
  const hasWarnings = calendar.warnings.some((warning) => warning.trim());
  return (calendar.status === "open" || calendar.status === "always_open") && !hasWarnings ? "positive" : "warning";
}

function parsePercentMetric(value: string): number | null {
  const normalized = value.trim().replace("%", "");
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : null;
}

function formatSignedCurrency(value: number): string {
  return `${value >= 0 ? "+" : ""}${value.toFixed(2)}`;
}

function formatQuantity(value: number): string {
  return Number.isInteger(value) ? String(value) : value.toFixed(6).replace(/0+$/u, "").replace(/\.$/u, "");
}

function portfolioPaperOrderStateTone(state: string): "positive" | "warning" | "neutral" | "risk" {
  if (state === "operator_approved" || state === "ready_for_simulation" || state === "simulation_filled") {
    return "positive";
  }
  if (state === "awaiting_operator_review" || state === "risk_review" || state === "simulation_recorded") {
    return "warning";
  }
  if (state === "operator_rejected" || state === "risk_rejected" || state === "invalid_order" || state === "live_blocked") {
    return "risk";
  }
  return "neutral";
}

function executionAdapterLedgerTone(state: string): "positive" | "warning" | "neutral" | "risk" {
  if (state === "paper_ready" || state === "live_ready") {
    return "positive";
  }
  if (state === "config_required") {
    return "warning";
  }
  if (state === "live_blocked" || state === "blocked") {
    return "risk";
  }
  return "neutral";
}

function executionAdapterCertificationTone(
  status: ExecutionAdapterCertificationStatus
): "positive" | "warning" | "neutral" | "risk" {
  if (status === "passed") {
    return "positive";
  }
  if (status === "review") {
    return "warning";
  }
  if (status === "blocked" || status === "failed") {
    return "risk";
  }
  return "neutral";
}

function executionAdapterCertificationStatusLabel(status: ExecutionAdapterCertificationStatus): string {
  return (
    {
      blocked: "Blocked",
      failed: "Failed",
      passed: "Passed",
      review: "Review"
    } satisfies Record<ExecutionAdapterCertificationStatus, string>
  )[status];
}

function executionAdapterCertificationCheckSummary(
  summary: ExecutionAdapterCertificationSnapshot["summary"]
): string {
  const parts = [
    [summary.passedChecks, "passed"],
    [summary.blockedChecks, "blocked"],
    [summary.failedChecks, "failed"],
    [summary.reviewChecks, "review"]
  ]
    .filter(([count]) => Number(count) > 0)
    .map(([count, label]) => `${count} ${label}`);
  return [...(parts.length ? parts : ["0 passed"]), `${summary.checkCount} checks`].join(" / ");
}

